-- Poems batch 461
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-84','退宮人二首','張祜','唐','御定全唐诗','yuding','','[]','開元皇帝掌中憐，流落人間二十年。',64,'御定全唐詩/json/511.json','["開元皇帝掌中憐，流落人間二十年。", "長說承天門上宴，百官樓下拾金錢。", "歌喉漸退出宮闈，泣話伶官上許歸。", "猶說入時歡聖壽，內人初著五方衣。"]'),
('yuding-85','耍娘歌','張祜','唐','御定全唐诗','yuding','','[]','宜春花夜雪千枝，妃子偷行上密隨。',32,'御定全唐詩/json/511.json','["宜春花夜雪千枝，妃子偷行上密隨。", "便喚耍娘歌一曲，六宮生老是蛾眉。"]'),
('yuding-86','悖拏兒舞','張祜','唐','御定全唐诗','yuding','','[]','春風南內百花時，道唱梁州急遍吹。',32,'御定全唐詩/json/511.json','["春風南內百花時，道唱梁州急遍吹。", "揭手便拈金碗舞，上皇驚笑悖拏兒。"]'),
('yuding-87','題靈徹上人舊房','張祜','唐','御定全唐诗','yuding','','[]','寂寞空門支道林，滿堂詩板舊知音。',32,'御定全唐詩/json/511.json','["寂寞空門支道林，滿堂詩板舊知音。", "秋風吹葉古廊下，一半繩床燈影深。"]'),
('yuding-88','晚秋潼關西門作','張祜','唐','御定全唐诗','yuding','','[]','日落寒郊煙物清，古槐陰黑少人行。',32,'御定全唐詩/json/511.json','["日落寒郊煙物清，古槐陰黑少人行。", "關門西去華山色，秦地東來河水聲。"]'),
('yuding-89','贈內人','張祜','唐','御定全唐诗','yuding','','[]','禁門宮樹月痕過，媚眼唯看宿燕窠。',32,'御定全唐詩/json/511.json','["禁門宮樹月痕過，媚眼唯看宿燕窠。", "斜拔玉釵燈影畔，剔開紅焰救飛蛾。"]'),
('yuding-90','洛中作','張祜','唐','御定全唐诗','yuding','','[]','元和天子昔平戎，惆悵金輿尚未通。',32,'御定全唐詩/json/511.json','["元和天子昔平戎，惆悵金輿尚未通。", "盡日洛橋閑處看，秋風時節上陽宮。"]'),
('yuding-91','折楊柳枝二首','張祜','唐','御定全唐诗','yuding','','[]','莫折宮前楊柳枝，玄宗曾向笛中吹。',64,'御定全唐詩/json/511.json','["莫折宮前楊柳枝，玄宗曾向笛中吹。", "傷心日暮煙霞起，無限春愁生翠眉。", "凝碧池邊斂翠眉，景陽樓下綰青絲。", "那勝妃子朝元閣，玉手和煙弄一枝。"]'),
('yuding-92','華清宮四首','張祜','唐','御定全唐诗','yuding','','[]','風樹離離月稍明，九天龍氣在華清。',128,'御定全唐詩/json/511.json','["風樹離離月稍明，九天龍氣在華清。", "宮門深鎖無人覺，半夜雲中羯鼓聲。", "天闕沉沉夜未央，碧雲仙曲舞霓裳。", "一聲玉笛向空盡，月滿驪山宮漏長。", "紅樹蕭蕭閣半開，上皇曾幸此宮來。", "至今風俗驪山下，村笛猶吹阿濫堆。", "水繞宮牆處處聲，殘紅長綠露華清。", "武皇一夕夢不覺，十二玉樓空月明。"]'),
('yuding-93','贈竇家小兒','張祜','唐','御定全唐诗','yuding','','[]','深綠衣裳小小人，每來聽裏解相親。',32,'御定全唐詩/json/511.json','["深綠衣裳小小人，每來聽裏解相親。", "天生合去雲霄上，一尺松栽已出塵。"]'),
('yuding-94','聽崔莒侍禦葉家歌','張祜','唐','御定全唐诗','yuding','','[]','宛羅重縠起歌筵，活鳳生花動碧煙。',32,'御定全唐詩/json/511.json','["宛羅重縠起歌筵，活鳳生花動碧煙。", "一聲唱斷無人和，觸破秋雲直上天。"]'),
('yuding-95','長門怨','張祜','唐','御定全唐诗','yuding','','[]','日映宮牆柳色寒，笙歌遙指碧雲端。',32,'御定全唐詩/json/511.json','["日映宮牆柳色寒，笙歌遙指碧雲端。", "珠鉛滴盡無心語，強把花枝冷笑看。"]'),
('yuding-96','讀老莊','張祜','唐','御定全唐诗','yuding','','[]','等閒緝綴閑言語，誇向時人喚作詩。',32,'御定全唐詩/json/511.json','["等閒緝綴閑言語，誇向時人喚作詩。", "昨日偶拈莊老讀，萬尋山上一毫釐。"]'),
('yuding-97','偶題','張祜','唐','御定全唐诗','yuding','','[]','古來名下豈虛為，李白顛狂自稱時。',32,'御定全唐詩/json/511.json','["古來名下豈虛為，李白顛狂自稱時。", "唯恨世間無賀老，謫仙長在沒人知。"]'),
('yuding-98','別玉華仙侶','張祜','唐','御定全唐诗','yuding','','[]','繞舍煙霞為四鄰，寒泉白石日相親。',32,'御定全唐詩/json/511.json','["繞舍煙霞為四鄰，寒泉白石日相親。", "塵機不盡住不得，珍重玉山山上人。"]'),
('yuding-99','汴上送客','張祜','唐','御定全唐诗','yuding','','[]','河流西下雁南飛，楚客相逢淚濕衣。',32,'御定全唐詩/json/511.json','["河流西下雁南飛，楚客相逢淚濕衣。", "張翰思歸何太切，扁舟不住又東歸。"]'),
('yuding-100','郵亭殘花','張祜','唐','御定全唐诗','yuding','','[]','雲暗山橫日欲斜，郵亭下馬對殘花。',32,'御定全唐詩/json/511.json','["雲暗山橫日欲斜，郵亭下馬對殘花。", "自從身逐征西府，每到花時不在家。"]'),
('yuding-101','秋時送鄭侍禦','張祜','唐','御定全唐诗','yuding','','[]','離鴻聲怨碧雲淨，楚瑟調高清曉天。',32,'御定全唐詩/json/511.json','["離鴻聲怨碧雲淨，楚瑟調高清曉天。", "盡日相看俱不語，西風搖落數枝蓮。"]'),
('yuding-102','宿武牢關','張祜','唐','御定全唐诗','yuding','','[]','行人候曉久裴徊，不待雞鳴未得開。',32,'御定全唐詩/json/511.json','["行人候曉久裴徊，不待雞鳴未得開。", "堪羨寒溪自無事，潺潺一夜宿關來。"]'),
('yuding-103','夜宿湓浦逢崔升','張祜','唐','御定全唐诗','yuding','','[]','江流不動月西沈，南北行人萬里心。',32,'御定全唐詩/json/511.json','["江流不動月西沈，南北行人萬里心。", "況是相逢雁天夕，星河寥落水雲深。"]'),
('yuding-104','京城寓懷','張祜','唐','御定全唐诗','yuding','','[]','三十年持一釣竿，偶隨書薦入長安。',32,'御定全唐詩/json/511.json','["三十年持一釣竿，偶隨書薦入長安。", "由來不是求名者，唯待春風看牡丹。"]'),
('yuding-105','集靈台二首','張祜','唐','御定全唐诗','yuding','','[]','日光斜照集靈台，紅樹花迎曉露開。',64,'御定全唐詩/json/511.json','["日光斜照集靈台，紅樹花迎曉露開。", "昨夜上皇新授籙，太真含笑入簾來。", "虢國夫人承主恩，平明騎馬入宮門。", "卻嫌脂粉汙顏色，淡掃蛾眉朝至尊。"]'),
('yuding-106','感歸','張祜','唐','御定全唐诗','yuding','','[]','行卻江南路幾千，歸來不把一文錢。',32,'御定全唐詩/json/511.json','["行卻江南路幾千，歸來不把一文錢。", "鄉人笑我窮寒鬼，還似襄陽孟浩然。"]'),
('yuding-107','偶作','張祜','唐','御定全唐诗','yuding','','[]','遍識青霄路上人，相逢只是語逡巡。',32,'御定全唐詩/json/511.json','["遍識青霄路上人，相逢只是語逡巡。", "可勝飲盡江南酒，歲月猶殘李白身。"]'),
('yuding-108','勸飲酒','張祜','唐','御定全唐诗','yuding','','[]','燒得硫黃漫學仙，未勝長付酒家錢。',32,'御定全唐詩/json/511.json','["燒得硫黃漫學仙，未勝長付酒家錢。", "竇常不吃齊推樂，卻在人間八十年。"]'),
('yuding-109','阿鴇湯','張祜','唐','御定全唐诗','yuding','','[]','月照宮城紅樹芳，綠窗燈影在雕梁。',32,'御定全唐詩/json/511.json','["月照宮城紅樹芳，綠窗燈影在雕梁。", "金輿未到長生殿，妃子偷尋阿鴇湯。"]'),
('yuding-110','馬嵬坡','張祜','唐','御定全唐诗','yuding','','[]','旌旗不整奈君何，南去人稀北去多。',32,'御定全唐詩/json/511.json','["旌旗不整奈君何，南去人稀北去多。", "塵土已殘香粉豔，荔枝猶到馬嵬坡。"]'),
('yuding-111','太真香囊子','張祜','唐','御定全唐诗','yuding','','[]','蹙金妃子小花囊，銷耗胸前結舊香。',32,'御定全唐詩/json/511.json','["蹙金妃子小花囊，銷耗胸前結舊香。", "誰為君王重解得，一生遺恨系心腸。"]'),
('yuding-112','雨霖鈴','張祜','唐','御定全唐诗','yuding','','[]','雨霖鈴夜卻歸秦，猶見張徽一曲新。',32,'御定全唐詩/json/511.json','["雨霖鈴夜卻歸秦，猶見張徽一曲新。", "長說上皇和淚教，月明南內更無人。"]'),
('yuding-113','聽歌二首','張祜','唐','御定全唐诗','yuding','','[]','兒郎漫說轉喉輕，須待情來意自生。',64,'御定全唐詩/json/511.json','["兒郎漫說轉喉輕，須待情來意自生。", "只是眼前絲竹和，大家聲裏唱新聲。", "十二年前邊塞行，坐中無語歎歌情。", "不堪昨夜先垂淚，西去陽關第一聲。"]'),
('yuding-114','聽箏','張祜','唐','御定全唐诗','yuding','','[]','十指纖纖玉筍紅，雁行輕遏翠弦中。',32,'御定全唐詩/json/511.json','["十指纖纖玉筍紅，雁行輕遏翠弦中。", "分明似說長城苦，水咽雲寒一夜風。"]'),
('yuding-115','王家琵琶','張祜','唐','御定全唐诗','yuding','','[]','金屑檀槽玉腕明，子弦輕撚為多情。',32,'御定全唐詩/json/511.json','["金屑檀槽玉腕明，子弦輕撚為多情。", "只愁拍盡涼州破，畫出風雷是撥聲。"]'),
('yuding-116','李家柘枝','張祜','唐','御定全唐诗','yuding','','[]','紅鉛拂臉細腰人，金繡羅衫軟著身。',32,'御定全唐詩/json/511.json','["紅鉛拂臉細腰人，金繡羅衫軟著身。", "長恐舞時殘拍盡，卻思雲雨更無因。"]'),
('yuding-117','楚州韋中丞箜篌','張祜','唐','御定全唐诗','yuding','','[]','千重鉤鎖撼金鈴，萬顆真珠瀉玉瓶。',32,'御定全唐詩/json/511.json','["千重鉤鎖撼金鈴，萬顆真珠瀉玉瓶。", "恰值滿堂人欲醉，甲光才觸一時醒。"]'),
('yuding-118','邊上逢歌者','張祜','唐','御定全唐诗','yuding','','[]','垂老秋歌出塞庭，遏雲相付舊秦青。',32,'御定全唐詩/json/511.json','["垂老秋歌出塞庭，遏雲相付舊秦青。", "少年翻擲新聲盡，卻向人前側耳聽。"]'),
('yuding-119','馬嵬歸','張祜','唐','御定全唐诗','yuding','','[]','雲愁鳥恨驛坡前，孑孑龍旗指望賢。',32,'御定全唐詩/json/511.json','["雲愁鳥恨驛坡前，孑孑龍旗指望賢。", "無複一生重語事，柘黃衫袖掩潸然。"]'),
('yuding-120','塞上聞笛','張祜','唐','御定全唐诗','yuding','','[]','一夜梅花笛裏飛，冷沙晴檻月光輝。',32,'御定全唐詩/json/511.json','["一夜梅花笛裏飛，冷沙晴檻月光輝。", "北風吹盡向何處，高入塞雲燕雁稀。"]'),
('yuding-121','經舊游','張祜','唐','御定全唐诗','yuding','','[]','去年來送行人處，依舊蟲聲古岸南。',32,'御定全唐詩/json/511.json','["去年來送行人處，依舊蟲聲古岸南。", "斜日照溪雲影斷，水葓花穗倒空潭。"]'),
('yuding-122','東山寺','張祜','唐','御定全唐诗','yuding','','[]','寒色蒼蒼老柏風，石苔清滑露光融。',32,'御定全唐詩/json/511.json','["寒色蒼蒼老柏風，石苔清滑露光融。", "半夜四山鐘磬盡，水精宮殿月玲瓏。"]'),
('yuding-123','峰頂寺','張祜','唐','御定全唐诗','yuding','','[]','月明如水山頭寺，仰面看天石上行。',32,'御定全唐詩/json/511.json','["月明如水山頭寺，仰面看天石上行。", "夜半深廊人語定，一枝鬆動鶴來聲。"]'),
('yuding-124','題潤州鶴林寺','張祜','唐','御定全唐诗','yuding','','[]','古寺名僧多異時，道情虛遣俗情悲。',32,'御定全唐詩/json/511.json','["古寺名僧多異時，道情虛遣俗情悲。", "千年鶴在市朝變，來去舊山人不知。"]'),
('yuding-125','題勝上人山房','張祜','唐','御定全唐诗','yuding','','[]','清晝房廊山半開，一瓶新汲灑莓苔。',32,'御定全唐詩/json/511.json','["清晝房廊山半開，一瓶新汲灑莓苔。", "古松百尺始生葉，颯颯風聲天上來。"]'),
('yuding-126','李夫人詞','張祜','唐','御定全唐诗','yuding','','[]','延年不語望三星，莫說夫人上涕零。',32,'御定全唐詩/json/511.json','["延年不語望三星，莫說夫人上涕零。", "爭奈世間惆悵在，甘泉宮夜看圖形。"]'),
('yuding-127','題金陵渡','張祜','唐','御定全唐诗','yuding','','[]','金陵津渡小山樓，一宿行人自可愁。',32,'御定全唐詩/json/511.json','["金陵津渡小山樓，一宿行人自可愁。", "潮落夜江斜月裏，兩三星火是瓜州。"]'),
('yuding-128','過陰陵','張祜','唐','御定全唐诗','yuding','','[]','壯士悽惶到山下，行人惆悵上山頭。',32,'御定全唐詩/json/511.json','["壯士悽惶到山下，行人惆悵上山頭。", "生前此路已迷失，寂寞孤魂何處遊。"]'),
('yuding-129','縱游淮南','張祜','唐','御定全唐诗','yuding','','[]','十裏長街市井連，月明橋上看神仙。',32,'御定全唐詩/json/511.json','["十裏長街市井連，月明橋上看神仙。", "人生只合揚州死，禪智山光好墓田。"]'),
('yuding-130','登樂游原','張祜','唐','御定全唐诗','yuding','','[]','幾年詩酒滯江幹，水積雲重思萬端。',32,'御定全唐詩/json/511.json','["幾年詩酒滯江幹，水積雲重思萬端。", "今日南方惆悵盡，樂游原上見長安。"]'),
('yuding-131','過石頭城','張祜','唐','御定全唐诗','yuding','','[]','累累墟墓葬西原，六代同歸蔓草根。',32,'御定全唐詩/json/511.json','["累累墟墓葬西原，六代同歸蔓草根。", "唯是歲華流盡處，石頭城下水千痕。"]'),
('yuding-132','黃蜀葵花','張祜','唐','御定全唐诗','yuding','','[]','名花八葉嫩黃金，色照書窗透竹林。',32,'御定全唐詩/json/511.json','["名花八葉嫩黃金，色照書窗透竹林。", "無奈美人閑把嗅，直疑檀口印中心。"]'),
('yuding-133','楊花','張祜','唐','御定全唐诗','yuding','','[]','散亂隨風處處勻，庭前幾日雪花新。',32,'御定全唐詩/json/511.json','["散亂隨風處處勻，庭前幾日雪花新。", "無端惹著潘郎鬢，驚殺綠窗紅粉人。"]'),
('yuding-134','薔薇花','張祜','唐','御定全唐诗','yuding','','[]','曉風抹盡燕支顆，夜雨催成蜀錦機。',32,'御定全唐詩/json/511.json','["曉風抹盡燕支顆，夜雨催成蜀錦機。", "當晝開時正明媚，故鄉疑是買臣歸。"]'),
('yuding-135','戲顏郎中獵','張祜','唐','御定全唐诗','yuding','','[]','忽聞射獵出軍城，人著戎衣馬帶纓。',32,'御定全唐詩/json/511.json','["忽聞射獵出軍城，人著戎衣馬帶纓。", "倒把角弓呈一箭，滿川狐兔當頭行。"]'),
('yuding-136','江上旅泊呈杜員外','張祜','唐','御定全唐诗','yuding','','[]','牛渚南來沙岸長，遠吟佳句望池陽。',32,'御定全唐詩/json/511.json','["牛渚南來沙岸長，遠吟佳句望池陽。", "野人未必非毛遂，太守還須是孟嘗。"]'),
('yuding-137','容兒缽頭','張祜','唐','御定全唐诗','yuding','','[]','爭走金車叱鞅牛，笑聲唯是說千秋。',32,'御定全唐詩/json/511.json','["爭走金車叱鞅牛，笑聲唯是說千秋。", "兩邊角子羊門裏，猶學容兒弄缽頭。"]'),
('yuding-138','熱戲樂','張祜','唐','御定全唐诗','yuding','','[]','熱戲爭心劇火燒，銅槌暗熱不相饒。',32,'御定全唐詩/json/511.json','["熱戲爭心劇火燒，銅槌暗熱不相饒。", "上皇失喜甯王笑，百尺幢竿果動搖。"]'),
('yuding-139','玉環琵琶','張祜','唐','御定全唐诗','yuding','','[]','宮樓一曲琵琶聲，滿眼雲山是去程。',32,'御定全唐詩/json/511.json','["宮樓一曲琵琶聲，滿眼雲山是去程。", "回顧段師非汝意，玉環休把恨分明。"]'),
('yuding-140','題酸棗驛前碑','張祜','唐','御定全唐诗','yuding','','[]','蒼苔古澀自雕疏，誰道中郎筆力餘。',32,'御定全唐詩/json/511.json','["蒼苔古澀自雕疏，誰道中郎筆力餘。", "長愛當時遇王粲，每來碑下不關書。"]'),
('yuding-141','題朱兵曹山居','張祜','唐','御定全唐诗','yuding','','[]','朱氏西齋萬卷書，水門山闊自高疏。',32,'御定全唐詩/json/511.json','["朱氏西齋萬卷書，水門山闊自高疏。", "我來穿穴非無意，願向君家作壁魚。"]'),
('yuding-142','題畫僧二首','張祜','唐','御定全唐诗','yuding','','[]','骨峭情高彼岸人，一杯長泛海為津。',64,'御定全唐詩/json/511.json','["骨峭情高彼岸人，一杯長泛海為津。", "僧儀又入清流品，卻恐前生是許詢。", "瘦頸隆肩碧眼生，翰林親贊虎頭能。", "終年不語看如意，似證禪心入大乘。"]'),
('yuding-143','送走馬使','張祜','唐','御定全唐诗','yuding','','[]','新樣花文配蜀羅，同心雙帶蹙金蛾。',32,'御定全唐詩/json/511.json','["新樣花文配蜀羅，同心雙帶蹙金蛾。", "慣將喉舌傳軍好，馬跡鈴聲遍兩河。"]'),
('yuding-144','題禦溝','張祜','唐','御定全唐诗','yuding','','[]','萬樹垂楊拂禦溝，溶溶漾漾繞神州。',32,'御定全唐詩/json/511.json','["萬樹垂楊拂禦溝，溶溶漾漾繞神州。", "都緣濟物心無阻，從此恩波處處流。"]'),
('yuding-145','題青龍寺','張祜','唐','御定全唐诗','yuding','','[]','二十年沈滄海間，一游京國也應閑。',32,'御定全唐詩/json/511.json','["二十年沈滄海間，一游京國也應閑。", "人人盡到求名處，獨向青龍寺看山。"]'),
('yuding-146','硫黃','張祜','唐','御定全唐诗','yuding','','[]','一粒硫黃入貴門，寢堂深處問玄言。',32,'御定全唐詩/json/511.json','["一粒硫黃入貴門，寢堂深處問玄言。", "時人盡說韋山甫，昨日餘幹吊子孫。"]'),
('yuding-147','散花樓','張祜','唐','御定全唐诗','yuding','','[]','錦江城外錦城頭，回望秦川上軫憂。',32,'御定全唐詩/json/511.json','["錦江城外錦城頭，回望秦川上軫憂。", "正值血魂來夢裏，杜鵑聲在散花樓。"]'),
('yuding-148','王家五弦','張祜','唐','御定全唐诗','yuding','','[]','五條弦出萬端情，撚撥間關漫態生。',32,'御定全唐詩/json/511.json','["五條弦出萬端情，撚撥間關漫態生。", "唯羨風流田太守，小金鈴子耳邊鳴。"]'),
('yuding-149','聽薛陽陶吹蘆管','張祜','唐','御定全唐诗','yuding','','[]','紫清人下薛陽陶，末曲新笳調更高。',32,'御定全唐詩/json/511.json','["紫清人下薛陽陶，末曲新笳調更高。", "無奈一聲天外絕，百年已死斷腸刀。"]'),
('yuding-150','過汾水關','張祜','唐','御定全唐诗','yuding','','[]','千里南來背日行，關門無事一侯嬴。',32,'御定全唐詩/json/511.json','["千里南來背日行，關門無事一侯嬴。", "山根百尺路前去，十夜耳中汾水聲。"]'),
('yuding-151','櫻桃','張祜','唐','御定全唐诗','yuding','','[]','石榴未拆梅猶小，愛此山花四五株。',32,'御定全唐詩/json/511.json','["石榴未拆梅猶小，愛此山花四五株。", "斜日庭前風嫋嫋，碧油千片漏紅珠。"]'),
('yuding-152','酬淩秀才惠枕','張祜','唐','御定全唐诗','yuding','','[]','八寸黃楊惠不輕，虎頭光照簟文清。',32,'御定全唐詩/json/511.json','["八寸黃楊惠不輕，虎頭光照簟文清。", "空心想此緣成夢，拔劍燈前一夜行。"]'),
('yuding-153','感春申君','張祜','唐','御定全唐诗','yuding','','[]','薄俗何心議感恩，諂容卑跡賴君門。',32,'御定全唐詩/json/511.json','["薄俗何心議感恩，諂容卑跡賴君門。", "春申還道三千客，寂寞無人殺李園。"]'),
('yuding-154','孟才人歎','張祜','唐','御定全唐诗','yuding','','[]','偶因歌態詠嬌嚬，傳唱宮中十二春。',32,'御定全唐詩/json/511.json','["偶因歌態詠嬌嚬，傳唱宮中十二春。", "卻為一聲河滿子，下泉須吊舊才人。"]'),
('yuding-155','聽簡上人吹蘆管三首','張祜','唐','御定全唐诗','yuding','','[]','蜀國僧吹蘆一枝，隴西遊客淚先垂。',96,'御定全唐詩/json/511.json','["蜀國僧吹蘆一枝，隴西遊客淚先垂。", "至今留得新聲在，卻為中原人不知。", "細蘆僧管夜沉沉，越鳥巴猿寄恨吟。", "吹到耳邊聲盡處，一條絲斷碧雲心。", "月落江城樹繞鴉，一聲蘆管是天涯。", "分明西國人來說，赤佛堂西是漢家。"]'),
('yuding-156','聽岳州徐員外彈琴','張祜','唐','御定全唐诗','yuding','','[]','玉律潛符一古琴，哲人心見聖人心。',32,'御定全唐詩/json/511.json','["玉律潛符一古琴，哲人心見聖人心。", "盡日南風似遺意，九疑猿鳥滿山吟。"]'),
('yuding-157','鉤弋夫人詞','張祜','唐','御定全唐诗','yuding','','[]','惆悵雲陵事不回，萬金重更築仙台。',32,'御定全唐詩/json/511.json','["惆悵雲陵事不回，萬金重更築仙台。", "莫言天上無消息，猶是夫人作鳥來。"]'),
('yuding-158','鴻溝','張祜','唐','御定全唐诗','yuding','','[]','龍蛇百戰爭天下，各制雄心指此溝。',32,'御定全唐詩/json/511.json','["龍蛇百戰爭天下，各制雄心指此溝。", "寧似九州分國土，地圖初割海中流。"]'),
('yuding-159','悲納鐵','張祜','唐','御定全唐诗','yuding','','[]','長聞為政古諸侯，使佩刀人盡佩牛。',32,'御定全唐詩/json/511.json','["長聞為政古諸侯，使佩刀人盡佩牛。", "誰謂今來正耕墾，卻銷農器作戈矛。"]'),
('yuding-160','胡渭州','張祜','唐','御定全唐诗','yuding','','[]','亭亭孤月照行舟，寂寂長江萬里流。',32,'御定全唐詩/json/511.json','["亭亭孤月照行舟，寂寂長江萬里流。", "鄉國不知何處是，雲山漫漫使人愁。"]'),
('yuding-161','破陣樂','張祜','唐','御定全唐诗','yuding','','[]','秋風四面足風沙，塞外征人暫別家。',32,'御定全唐詩/json/511.json','["秋風四面足風沙，塞外征人暫別家。", "千里不辭行路遠，時光早晚到天涯。"]'),
('yuding-162','楓橋','張祜','唐','御定全唐诗','yuding','','[]','長洲苑外草蕭蕭，卻算遊城歲月遙。',32,'御定全唐詩/json/511.json','["長洲苑外草蕭蕭，卻算遊城歲月遙。", "唯有別時今不忘，暮煙疏雨過楓橋。"]'),
('yuding-163','句','張祜','唐','御定全唐诗','yuding','','[]','萬國見清道，一身成白頭。（《上令狐相公》。',124,'御定全唐詩/json/511.json','["萬國見清道，一身成白頭。（《上令狐相公》。", "以下見《紀事》）", "此地榮辱盛，豈宜山中人。", "椿兒繞樹春園裏，桂子尋花夜月中。", "一身扶杖二兒隨。", "夏雨蓮苞破，秋風桂子凋。（《題天竺寺》。", "以下並見《海錄碎事》）", "杜鵑花發杜鵑叫，烏臼花生烏臼啼。", "茶風無奈筆，酒禿不勝簪。"]'),
('yuding-0','答李昌期','楊洵美','唐','御定全唐诗','yuding','','[]','三山載群仙，峨峨鹹浪中。雲衣剪不得，此路安可從。',72,'御定全唐詩/json/512.json','["三山載群仙，峨峨鹹浪中。雲衣剪不得，此路安可從。", "我生亦何事，出門如飛蓬。白日又黃昏，所悲瑤草空。", "蟲聲故鄉夢，枕上禾黍風。吾道如未喪，天運何時通。"]'),
('yuding-1','宮詞','長孫翱','唐','御定全唐诗','yuding','','[]','一道甘泉接禦溝，上皇行處不曾秋。',32,'御定全唐詩/json/512.json','["一道甘泉接禦溝，上皇行處不曾秋。", "誰言水是無情物，也到宮前咽不流。"]'),
('yuding-2','和於中丞登越王樓見寄','盧求','唐','御定全唐诗','yuding','','[]','高情推謝守，善政屬綿州。未落紫泥詔，閑登白雪樓。',48,'御定全唐詩/json/512.json','["高情推謝守，善政屬綿州。未落紫泥詔，閑登白雪樓。", "晴江如送日，寒嶺鎮迎秋。滿壁朝天士，唯予不系舟。"]'),
('yuding-3','雨','歐陽袞','唐','御定全唐诗','yuding','','[]','細雨弄春陰，餘寒入晝深。山姿輕薄霧，煙色澹幽林。',48,'御定全唐詩/json/512.json','["細雨弄春陰，餘寒入晝深。山姿輕薄霧，煙色澹幽林。", "鹿踐莓苔滑，魚牽水荇沈。懷情方未已，清酒漫須斟。"]'),
('yuding-4','田家','歐陽袞','唐','御定全唐诗','yuding','','[]','黯黯日將夕，牛羊村外來。岩阿青氣發，籬落杏花開。',48,'御定全唐詩/json/512.json','["黯黯日將夕，牛羊村外來。岩阿青氣發，籬落杏花開。", "草木應初感，鶬鶊亦已催。晚間春作好，行樂不須猜。"]'),
('yuding-5','神光寺','歐陽袞','唐','御定全唐诗','yuding','','[]','香刹懸青磴，飛樓界碧空。石門棲怖鴿，慈塔繞歸鴻。',48,'御定全唐詩/json/512.json','["香刹懸青磴，飛樓界碧空。石門棲怖鴿，慈塔繞歸鴻。", "有法將心鏡，無名屬性通。從來樂幽寂，尋覓未能窮。"]'),
('yuding-6','和項斯遊頭陀寺上方','歐陽袞','唐','御定全唐诗','yuding','','[]','步入桃源裏，晴花更滿枝。峰回山意曠，林杳竹光遲。',48,'御定全唐詩/json/512.json','["步入桃源裏，晴花更滿枝。峰回山意曠，林杳竹光遲。", "遠寺尋龍藏，名香發雁池。間能將遠語，況及上陽時。"]'),
('yuding-7','秦原道中','歐陽袞','唐','御定全唐诗','yuding','','[]','分險架長瀾，斜梁控夕巒。宿雲依嶺斷，初月入江寒。',48,'御定全唐詩/json/512.json','["分險架長瀾，斜梁控夕巒。宿雲依嶺斷，初月入江寒。", "緇化秦裘敝，塵驚漢策殘。無言倦行旅，遙路屬時難。"]'),
('yuding-8','月峰寺憶理公','歐陽袞','唐','御定全唐诗','yuding','','[]','共來江海上，清論一宵同。禪榻渾依舊，心期浩已空。',48,'御定全唐詩/json/512.json','["共來江海上，清論一宵同。禪榻渾依舊，心期浩已空。", "驚春花落樹，聞梵澗搖風。二諦欣咨啟，還應夢寐通。"]'),
('yuding-9','寄陳去疾進士','歐陽袞','唐','御定全唐诗','yuding','','[]','放跡疑辭垢，棲心亦道門。玄言蘿幌馥，詩思竹爐溫。',48,'御定全唐詩/json/512.json','["放跡疑辭垢，棲心亦道門。玄言蘿幌馥，詩思竹爐溫。", "解帶搖花落，彈琴散鳥喧。江山茲夕意，唯有素交存。"]'),
('yuding-10','聽郢客歌陽春白雪','歐陽袞','唐','御定全唐诗','yuding','','[]','寂聽郢中人，高歌已絕倫。臨風飄白雪，向日奏陽春。',72,'御定全唐詩/json/512.json','["寂聽郢中人，高歌已絕倫。臨風飄白雪，向日奏陽春。", "調雅偏盈耳，聲長杳入神。連連貫珠並，嫋嫋遏雲頻。", "度曲知難和，凝情想任真。周郎如賞羨，莫使滯芳晨。"]'),
('yuding-11','南澗寺','歐陽袞','唐','御定全唐诗','yuding','','[]','春寺無人亂鳥啼，藤蘿陰磴野僧迷。雲藏古壁遺龍象，',40,'御定全唐詩/json/512.json','["春寺無人亂鳥啼，藤蘿陰磴野僧迷。雲藏古壁遺龍象，", "為耽寂樂親禪侶，莫怪閑行費馬蹄。"]'),
('yuding-0','獻歲書情','裴夷直','唐','御定全唐诗','yuding','','[]','白髮添雙鬢，空宮又一年。音書鴻不到，夢寐兔空懸。',48,'御定全唐詩/json/513.json','["白髮添雙鬢，空宮又一年。音書鴻不到，夢寐兔空懸。", "地遠星辰側，天高雨露偏。聖期知有感，雲海漫相連。"]'),
('yuding-1','奉和大樑相公重九日軍中宴會之什','裴夷直','唐','御定全唐诗','yuding','','[]','今古同嘉節，歡娛但異名。陶公緣綠醑，謝傅為蒼生。',48,'御定全唐詩/json/513.json','["今古同嘉節，歡娛但異名。陶公緣綠醑，謝傅為蒼生。", "酒泛金英麗，詩通玉律清。何言辭物累，方系萬人情。"]'),
('yuding-2','奉和大樑相公同張員外重九日宴集','裴夷直','唐','御定全唐诗','yuding','','[]','重九思嘉節，追歡從謝公。酒清欺玉露，菊盛愧金風。',48,'御定全唐詩/json/513.json','["重九思嘉節，追歡從謝公。酒清欺玉露，菊盛愧金風。", "不待秋蟾白，須沈落照紅。更將門下客，酬和管弦中。"]'),
('yuding-3','同樂天中秋夜洛河玩月二首','裴夷直','唐','御定全唐诗','yuding','','[]','清洛半秋懸璧月，彩船當夕泛銀河。蒼龍頷底珠皆沒，',80,'御定全唐詩/json/513.json','["清洛半秋懸璧月，彩船當夕泛銀河。蒼龍頷底珠皆沒，", "須知天地為爐意，盡取黃金鑄作波。", "不熱不寒三五夕，晴川明月正相臨。千珠競沒蒼龍頷，", "如何清洛如清晝，共見初升又見沈。"]'),
('yuding-4','和邢郎中病中重陽強遊樂游原','裴夷直','唐','御定全唐诗','yuding','','[]','嘉晨令節共陶陶，風景牽情並不勞。曉日整冠蘭室靜，',40,'御定全唐詩/json/513.json','["嘉晨令節共陶陶，風景牽情並不勞。曉日整冠蘭室靜，", "何必銷憂憑外物，只將清韻敵春醪。"]'),
('yuding-5','觀淬龍泉劍','裴夷直','唐','御定全唐诗','yuding','','[]','歐冶將成器，風胡幸見逢。發硎思剸玉，投水化為龍。',72,'御定全唐詩/json/513.json','["歐冶將成器，風胡幸見逢。發硎思剸玉，投水化為龍。", "詎肯藏深匣，終朝用刜鐘。蓮花生寶鍔，秋日勵霜鋒。", "煉質才三尺，吹毛過百重。擊磨如不倦，提握願長從。"]'),
('yuding-6','春色滿皇州','裴夷直','唐','御定全唐诗','yuding','','[]','寒銷山水地，春遍帝王州。北闕晴光動，南山喜氣浮。',72,'御定全唐詩/json/513.json','["寒銷山水地，春遍帝王州。北闕晴光動，南山喜氣浮。", "夭紅妝暖樹，急綠走陰溝。思婦開香閣，王孫上玉樓。", "氛氳直城北，駘蕩曲江頭。今日靈台下，翻然卻是愁。"]'),
('yuding-7','亞夫碎玉鬥','裴夷直','唐','御定全唐诗','yuding','','[]','雄謀竟不決，寶玉終不愛。倏爾霜刃揮，颯然春冰碎。',72,'御定全唐詩/json/513.json','["雄謀竟不決，寶玉終不愛。倏爾霜刃揮，颯然春冰碎。", "飛光動旗幟，散響驚環佩。霜灑繡障前，星流錦筵內。", "圖王業已失，為虜言空悔。獨有青史中，英風觀千載。"]'),
('yuding-8','水亭','裴夷直','唐','御定全唐诗','yuding','','[]','歲律行將變，君恩竟未回。門前即潮水，朝去暮常來。',24,'御定全唐詩/json/513.json','["歲律行將變，君恩竟未回。門前即潮水，朝去暮常來。"]'),
('yuding-9','揚州寄諸子','裴夷直','唐','御定全唐诗','yuding','','[]','千里隔煙波，孤舟宿何處。遙思耿不眠，淮南夜風雨。',24,'御定全唐詩/json/513.json','["千里隔煙波，孤舟宿何處。遙思耿不眠，淮南夜風雨。"]'),
('yuding-10','酬盧郎中游寺見招不遇','裴夷直','唐','御定全唐诗','yuding','','[]','偶出送山客，不知游梵宮。秋光古松下，誰伴一仙翁。',24,'御定全唐詩/json/513.json','["偶出送山客，不知游梵宮。秋光古松下，誰伴一仙翁。"]'),
('yuding-11','寓言','裴夷直','唐','御定全唐诗','yuding','','[]','秋樹卻逢暖，未凋能幾時。何須尚松桂，搖動暫青枝。',24,'御定全唐詩/json/513.json','["秋樹卻逢暖，未凋能幾時。何須尚松桂，搖動暫青枝。"]'),
('yuding-12','唁人喪侍兒','裴夷直','唐','御定全唐诗','yuding','','[]','夜情河耿耿，春恨草綿綿。唯有嫦娥月，從今照墓田。',24,'御定全唐詩/json/513.json','["夜情河耿耿，春恨草綿綿。唯有嫦娥月，從今照墓田。"]'),
('yuding-13','席上夜別張主簿','裴夷直','唐','御定全唐诗','yuding','','[]','紅燭剪還明，綠尊添又滿。不愁前路長，只畏今宵短。',24,'御定全唐詩/json/513.json','["紅燭剪還明，綠尊添又滿。不愁前路長，只畏今宵短。"]'),
('yuding-14','方丈泉','裴夷直','唐','御定全唐诗','yuding','','[]','循涯不知淺，見底似非深。永日無波浪，澄澄照我心。',24,'御定全唐詩/json/513.json','["循涯不知淺，見底似非深。永日無波浪，澄澄照我心。"]'),
('yuding-15','晚望','裴夷直','唐','御定全唐诗','yuding','','[]','日下夕陰長，前山凝積翠。白鳥一行飛，聯聯粉書字。',24,'御定全唐詩/json/513.json','["日下夕陰長，前山凝積翠。白鳥一行飛，聯聯粉書字。"]'),
('yuding-16','前山','裴夷直','唐','御定全唐诗','yuding','','[]','只謂一蒼翠，不知猶數重。晚來雲映處，更見兩三峰。',24,'御定全唐詩/json/513.json','["只謂一蒼翠，不知猶數重。晚來雲映處，更見兩三峰。"]'),
('yuding-17','發交州日留題解煉師房','裴夷直','唐','御定全唐诗','yuding','','[]','久喜房廊接，今成道路賒。明朝回首處，此地是天涯。',24,'御定全唐詩/json/513.json','["久喜房廊接，今成道路賒。明朝回首處，此地是天涯。"]'),
('yuding-18','令和州買松','裴夷直','唐','御定全唐诗','yuding','','[]','好覓淩霜質，仍須帶雨栽。須知剖竹日，便是看松來。',24,'御定全唐詩/json/513.json','["好覓淩霜質，仍須帶雨栽。須知剖竹日，便是看松來。"]'),
('yuding-19','題斷金集後','裴夷直','唐','御定全唐诗','yuding','','[]','一覽斷金集，再悲埋玉人。牙弦千古絕，珠淚萬行新。',24,'御定全唐詩/json/513.json','["一覽斷金集，再悲埋玉人。牙弦千古絕，珠淚萬行新。"]'),
('yuding-20','晚涼','裴夷直','唐','御定全唐诗','yuding','','[]','簷前蔽日多高樹，竹下添池有小渠。',32,'御定全唐詩/json/513.json','["簷前蔽日多高樹，竹下添池有小渠。", "山客野僧歸去後，晚涼移案獨臨書。"]'),
('yuding-21','和周侍禦洛城雪','裴夷直','唐','御定全唐诗','yuding','','[]','天街飛轡踏瓊英，四顧全疑在玉京。',32,'御定全唐詩/json/513.json','["天街飛轡踏瓊英，四顧全疑在玉京。", "一種相如抽秘思，兔園那比鳳凰城。"]'),
('yuding-22','奉和大樑相公送人二首','裴夷直','唐','御定全唐诗','yuding','','[]','謝公日日傷離別，又向西堂送阿連。',64,'御定全唐詩/json/513.json','["謝公日日傷離別，又向西堂送阿連。", "想到越中秋已盡，鏡河應羨月團圓。", "北津楊柳迎煙綠，南岸闌幹映水紅。", "君到襄陽渡江處，始應回首憶羊公。"]'),
('yuding-23','酬唐仁烈相別後喜阻風未發見寄','裴夷直','唐','御定全唐诗','yuding','','[]','離心一起淚雙流，春浪無情也白頭。',32,'御定全唐詩/json/513.json','["離心一起淚雙流，春浪無情也白頭。", "風若有知須放去，莫教重別又重愁。"]'),
('yuding-24','秦中臥病思歸','裴夷直','唐','御定全唐诗','yuding','','[]','索索涼風滿樹頭，破窗殘月五更秋。',32,'御定全唐詩/json/513.json','["索索涼風滿樹頭，破窗殘月五更秋。", "病身歸處吳江上，一寸心中萬里愁。"]'),
('yuding-25','送王繢','裴夷直','唐','御定全唐诗','yuding','','[]','翠羽長將玉樹期，偶然飛下肯多時。',32,'御定全唐詩/json/513.json','["翠羽長將玉樹期，偶然飛下肯多時。", "翩翩一路嵐陰晚，卻入青蔥宿舊枝。"]'),
('yuding-26','贈美人琴弦','裴夷直','唐','御定全唐诗','yuding','','[]','應從玉指到金徽，萬態千情料可知。',32,'御定全唐詩/json/513.json','["應從玉指到金徽，萬態千情料可知。", "今夜燈前湘水怨，殷勤封在七條絲。"]'),
('yuding-27','病中知皇子陂荷花盛發寄王繢','裴夷直','唐','御定全唐诗','yuding','','[]','十裏蓮塘路不賒，病來簾外是天涯。',32,'御定全唐詩/json/513.json','["十裏蓮塘路不賒，病來簾外是天涯。", "煩君四句遙相寄，應得詩中便看花。"]'),
('yuding-28','戲唐仁烈','裴夷直','唐','御定全唐诗','yuding','','[]','自知年幾偏應少，先把屠蘇不讓春。',32,'御定全唐詩/json/513.json','["自知年幾偏應少，先把屠蘇不讓春。", "倘更數年逢此日，還應惆悵羨他人。"]'),
('yuding-29','上下七盤二首','裴夷直','唐','御定全唐诗','yuding','','[]','鬥回山路掩皇州，二載歡娛一望休。',64,'御定全唐詩/json/513.json','["鬥回山路掩皇州，二載歡娛一望休。", "從此萬重青嶂合，無因更得重回頭。", "商山半月雨漫漫，偶值新晴下七盤。", "山似換來天似洗，可憐風日到長安。"]'),
('yuding-30','八月十五日夜','裴夷直','唐','御定全唐诗','yuding','','[]','去年今夜在商州，還為清光上驛樓。',32,'御定全唐詩/json/513.json','["去年今夜在商州，還為清光上驛樓。", "宛是依依舊顏色，自憐人換幾般愁。"]'),
('yuding-31','南詔朱藤杖','裴夷直','唐','御定全唐诗','yuding','','[]','六節南藤色似朱，拄行階砌勝人扶。',32,'御定全唐詩/json/513.json','["六節南藤色似朱，拄行階砌勝人扶。", "會須將入深山去，倚看雲泉作老夫。"]'),
('yuding-32','夜意','裴夷直','唐','御定全唐诗','yuding','','[]','蕭疏盡地林無影，浩蕩連天月有波。',32,'御定全唐詩/json/513.json','["蕭疏盡地林無影，浩蕩連天月有波。", "獨立空亭人睡後，洛橋風便水聲多。"]'),
('yuding-33','漫作','裴夷直','唐','御定全唐诗','yuding','','[]','月色莫來孤寢處，春風又向別人家。',32,'御定全唐詩/json/513.json','["月色莫來孤寢處，春風又向別人家。", "梁園桃李雖無數，斷定今年不看花。"]'),
('yuding-34','訪劉君','裴夷直','唐','御定全唐诗','yuding','','[]','擾擾馳蹄又走輪，五更飛盡九衢塵。',32,'御定全唐詩/json/513.json','["擾擾馳蹄又走輪，五更飛盡九衢塵。", "靈芝破觀深松院，還有齋時未起人。"]'),
('yuding-35','楊柳枝詞','裴夷直','唐','御定全唐诗','yuding','','[]','已作綠絲籠曉日，又成飛絮撲晴波。',32,'御定全唐詩/json/513.json','["已作綠絲籠曉日，又成飛絮撲晴波。", "隋家不合栽楊柳，長遣行人春恨多。"]'),
('yuding-36','寄杭州崔使君','裴夷直','唐','御定全唐诗','yuding','','[]','朝下歸來只閉關，羨君高步出人寰。',32,'御定全唐詩/json/513.json','["朝下歸來只閉關，羨君高步出人寰。", "三年不見塵中事，滿眼江濤送雪山。"]'),
('yuding-37','窮冬曲江閒步','裴夷直','唐','御定全唐诗','yuding','','[]','雪盡南坡雁北飛，草根春意勝春暉。',32,'御定全唐詩/json/513.json','["雪盡南坡雁北飛，草根春意勝春暉。", "曲江永日無人到，獨繞寒池又獨歸。"]'),
('yuding-38','省中題新植雙松','裴夷直','唐','御定全唐诗','yuding','','[]','端坐高宮起遠心，雲高水闊共幽沈。',32,'御定全唐詩/json/513.json','["端坐高宮起遠心，雲高水闊共幽沈。", "更堂寓直將誰語，自種雙松伴夜吟。"]'),
('yuding-39','崇山郡','裴夷直','唐','御定全唐诗','yuding','','[]','地盡炎荒瘴海頭，聖朝今又放驩兜。',32,'御定全唐詩/json/513.json','["地盡炎荒瘴海頭，聖朝今又放驩兜。", "交州已在南天外，更過交州四五州。"]'),
('yuding-40','臨水','裴夷直','唐','御定全唐诗','yuding','','[]','一見心原斷百憂，益知身世兩悠悠。',32,'御定全唐詩/json/513.json','["一見心原斷百憂，益知身世兩悠悠。", "江亭獨倚闌幹處，人亦無言水自流。"]'),
('yuding-41','題江上柳寄李使君','裴夷直','唐','御定全唐诗','yuding','','[]','桂江南渡無楊柳，見此令人眼暫明。',32,'御定全唐詩/json/513.json','["桂江南渡無楊柳，見此令人眼暫明。", "應學郡中賢太守，依依相向許多情。"]'),
('yuding-42','江上見月懷古','裴夷直','唐','御定全唐诗','yuding','','[]','月上江平夜不風，伏波遺跡半成空。',32,'御定全唐詩/json/513.json','["月上江平夜不風，伏波遺跡半成空。", "今宵倍欲悲陵穀，銅柱分明在水中。"]'),
('yuding-43','鸚鵡','裴夷直','唐','御定全唐诗','yuding','','[]','勸爾莫移禽鳥性，翠毛紅觜任天真。',32,'御定全唐詩/json/513.json','["勸爾莫移禽鳥性，翠毛紅觜任天真。", "如今漫學人言巧，解語終須累爾身。"]'),
('yuding-44','寄婺州李給事二首','裴夷直','唐','御定全唐诗','yuding','','[]','心盡玉皇恩已遠，跡留江郡宦應孤。',64,'御定全唐詩/json/513.json','["心盡玉皇恩已遠，跡留江郡宦應孤。", "不知壯氣今何似，猶得淩雲貫日無。", "瘴鬼翻能念直心，五年相遇不相侵。", "目前唯有思君病，無底滄溟未是深。"]'),
('yuding-45','秋日','裴夷直','唐','御定全唐诗','yuding','','[]','六眸龜北涼應早，三足烏南日正長。',32,'御定全唐詩/json/513.json','["六眸龜北涼應早，三足烏南日正長。", "常記京關怨搖落，如今目斷滿林霜。"]'),
('yuding-46','遣意','裴夷直','唐','御定全唐诗','yuding','','[]','梧桐墜露悲先朽，松桂淩霜倚後枯。',32,'御定全唐詩/json/513.json','["梧桐墜露悲先朽，松桂淩霜倚後枯。", "不是世間長在物，暫分貞脆竟何殊。"]'),
('yuding-47','戲酬惟賞上人','裴夷直','唐','御定全唐诗','yuding','','[]','師是浮雲無著身，我居塵網敢相親。',32,'御定全唐詩/json/513.json','["師是浮雲無著身，我居塵網敢相親。", "應從海上秋風便，偶自飛來不為人。"]'),
('yuding-48','寓言','裴夷直','唐','御定全唐诗','yuding','','[]','流水頹陽不暫停，東流西落兩無情。',32,'御定全唐詩/json/513.json','["流水頹陽不暫停，東流西落兩無情。", "不是世間人自老，古來華髮此中生。"]'),
('yuding-49','憶家','裴夷直','唐','御定全唐诗','yuding','','[]','天海相連無盡處，夢魂來往尚應難。',32,'御定全唐詩/json/513.json','["天海相連無盡處，夢魂來往尚應難。", "誰言南海無霜雪，試向愁人兩鬢看。"]'),
('yuding-50','留客','裴夷直','唐','御定全唐诗','yuding','','[]','青梅欲熟筍初長，嫩綠新陰繞砌涼。',32,'御定全唐詩/json/513.json','["青梅欲熟筍初長，嫩綠新陰繞砌涼。", "湖館翛然無俗客，白衣居士且匡床。"]'),
('yuding-51','別蘄春王判官','裴夷直','唐','御定全唐诗','yuding','','[]','四十年來真久故，三千裏外暫相逢。',32,'御定全唐詩/json/513.json','["四十年來真久故，三千裏外暫相逢。", "今日一杯成遠別，煙波眇眇恨重重。"]'),
('yuding-52','將發循州社日于所居館宴送','裴夷直','唐','御定全唐诗','yuding','','[]','浪花如雪疊江風，社過高秋萬恨中。',32,'御定全唐詩/json/513.json','["浪花如雪疊江風，社過高秋萬恨中。", "明日便隨江燕去，依依俱是故巢空。"]'),
('yuding-0','泛溪','朱慶餘','唐','御定全唐诗','yuding','','[]','曲渚回花舫，生衣臥向風。鳥飛溪色裏，人語棹聲中。',48,'御定全唐詩/json/514.json','["曲渚回花舫，生衣臥向風。鳥飛溪色裏，人語棹聲中。", "餘卉才分影，新蒲自作叢。前灣更幽絕，雖淺去猶通。"]'),
('yuding-1','宿陳處士書齋','朱慶餘','唐','御定全唐诗','yuding','','[]','結茅當此地，下馬見高情。菰葉寒塘晚，杉陰白石明。',48,'御定全唐詩/json/514.json','["結茅當此地，下馬見高情。菰葉寒塘晚，杉陰白石明。", "向爐新茗色，隔雪遠鐘聲。閑得相逢少，吟多寐不成。"]'),
('yuding-2','上宣州沈大夫','朱慶餘','唐','御定全唐诗','yuding','','[]','科名繼世古來稀，高步何年下紫微。帝命幾曾移重鎮，',40,'御定全唐詩/json/514.json','["科名繼世古來稀，高步何年下紫微。帝命幾曾移重鎮，", "今日得遊風化地，卻回滄海有光輝。"]'),
('yuding-3','杭州送蕭寶校書','朱慶餘','唐','御定全唐诗','yuding','','[]','馬識青山路，人隨白浪船。別君猶有淚，學道謾經年。',24,'御定全唐詩/json/514.json','["馬識青山路，人隨白浪船。別君猶有淚，學道謾經年。"]'),
('yuding-4','送盛長史','朱慶餘','唐','御定全唐诗','yuding','','[]','莫辭東路遠，此別豈閑行。職處中軍要，官兼上佐榮。',48,'御定全唐詩/json/514.json','["莫辭東路遠，此別豈閑行。職處中軍要，官兼上佐榮。", "野亭楓葉暗，秋水藕花明。拜省期將近，孤舟促去程。"]'),
('yuding-5','宿道士觀','朱慶餘','唐','御定全唐诗','yuding','','[]','堂閉仙人影，空壇月露初。閑聽道家子，盥漱讀靈書。',24,'御定全唐詩/json/514.json','["堂閉仙人影，空壇月露初。閑聽道家子，盥漱讀靈書。"]'),
('yuding-6','湖州韓使君置宴','朱慶餘','唐','御定全唐诗','yuding','','[]','老大成名仍足病，縱聽絲竹也無歡。',32,'御定全唐詩/json/514.json','["老大成名仍足病，縱聽絲竹也無歡。", "高情太守容閑坐，借與青山盡日看。"]'),
('yuding-7','題仙游寺','朱慶餘','唐','御定全唐诗','yuding','','[]','石抱龍堂蘚石幹，山遮白日寺門寒。',32,'御定全唐詩/json/514.json','["石抱龍堂蘚石幹，山遮白日寺門寒。", "長松瀑布饒奇狀，曾有仙人駐鶴看。"]'),
('yuding-8','宮詞','朱慶餘','唐','御定全唐诗','yuding','','[]','寂寂花時閉院門，美人相並立瓊軒。',32,'御定全唐詩/json/514.json','["寂寂花時閉院門，美人相並立瓊軒。", "含情欲說宮中事，鸚鵡前頭不敢言。"]'),
('yuding-9','公子行','朱慶餘','唐','御定全唐诗','yuding','','[]','閑從結客冶游時，忘卻紅樓薄暮期。',32,'御定全唐詩/json/514.json','["閑從結客冶游時，忘卻紅樓薄暮期。", "醉上黃金堤上去，馬鞭捎斷綠楊絲。"]'),
('yuding-10','送陳摽','朱慶餘','唐','御定全唐诗','yuding','','[]','滿酌勸童僕，好隨郎馬蹄。春風慎行李，莫上白銅鞮。',24,'御定全唐詩/json/514.json','["滿酌勸童僕，好隨郎馬蹄。春風慎行李，莫上白銅鞮。"]'),
('yuding-11','尋古觀','朱慶餘','唐','御定全唐诗','yuding','','[]','仙觀曾過知不遠，花藏石室杳難尋。',32,'御定全唐詩/json/514.json','["仙觀曾過知不遠，花藏石室杳難尋。", "泉邊白鹿聞人語，看過天壇漸入深。"]'),
('yuding-12','南嶺路','朱慶餘','唐','御定全唐诗','yuding','','[]','越嶺向南風景異，人人傳說到京城。',32,'御定全唐詩/json/514.json','["越嶺向南風景異，人人傳說到京城。", "經冬來往不踏雪，盡在刺桐花下行。"]'),
('yuding-13','陪江州李使君重陽宴百花亭','朱慶餘','唐','御定全唐诗','yuding','','[]','閑攜九日酒，共到百花亭。醉裏求詩境，回看島嶼青。',24,'御定全唐詩/json/514.json','["閑攜九日酒，共到百花亭。醉裏求詩境，回看島嶼青。"]'),
('yuding-14','上張水部','朱慶餘','唐','御定全唐诗','yuding','','[]','出入門闌久，兒童亦有情。不忘將姓字，常說向公卿。',48,'御定全唐詩/json/514.json','["出入門闌久，兒童亦有情。不忘將姓字，常說向公卿。", "每許連床坐，仍容並馬行。恩深轉無語，懷抱甚分明。"]'),
('yuding-15','鳳翔西池與賈島納涼','朱慶餘','唐','御定全唐诗','yuding','','[]','四面無炎氣，清池闊複深。蝶飛逢草住，魚戲見人沈。',48,'御定全唐詩/json/514.json','["四面無炎氣，清池闊複深。蝶飛逢草住，魚戲見人沈。", "拂石安茶器，移床選樹陰。幾回同到此，盡日得閒吟。"]'),
('yuding-16','上汴州令狐相公','朱慶餘','唐','御定全唐诗','yuding','','[]','罷相恩猶在，那容處靜司。政嚴初領節，名重更因詩。',48,'御定全唐詩/json/514.json','["罷相恩猶在，那容處靜司。政嚴初領節，名重更因詩。", "公事巡營外，戎裝拜敕時。恭聞長與善，應念出身遲。"]'),
('yuding-17','送於中丞入蕃冊立','朱慶餘','唐','御定全唐诗','yuding','','[]','上馬生邊思，戎裝別眾僚。雙旌銜命重，空磧去程遙。',48,'御定全唐詩/json/514.json','["上馬生邊思，戎裝別眾僚。雙旌銜命重，空磧去程遙。", "迥沒沙中樹，孤飛雪外雕。蕃庭過冊禮，幾日卻回朝。"]'),
('yuding-18','送淮陰丁明府','朱慶餘','唐','御定全唐诗','yuding','','[]','之官未入境，已有愛人心。遣吏回中路，停舟對遠林。',48,'御定全唐詩/json/514.json','["之官未入境，已有愛人心。遣吏回中路，停舟對遠林。", "島聲淮浪靜，雨色稻苗深。暇日公門掩，唯應伴客吟。"]'),
('yuding-19','送韋校書佐靈州幕','朱慶餘','唐','御定全唐诗','yuding','','[]','共知行處樂，猶惜此時分。職已為書記，官曾校典墳。',48,'御定全唐詩/json/514.json','["共知行處樂，猶惜此時分。職已為書記，官曾校典墳。", "寒城初落葉，高戍遠生雲。邊事何須問，深謀只在君。"]'),
('yuding-20','上江州李史君','朱慶餘','唐','御定全唐诗','yuding','','[]','起家聲望重，自古更誰過。得在朝廷少，還因諫諍多。',48,'御定全唐詩/json/514.json','["起家聲望重，自古更誰過。得在朝廷少，還因諫諍多。", "經年愁瘴癘，幾處遇恩波。入境無餘事，唯聞父老歌。"]'),
('yuding-21','發鳳翔後塗中懷田少府','朱慶餘','唐','御定全唐诗','yuding','','[]','識君春未半，意欲住經秋。見酒連詩句，逢花跋馬頭。',48,'御定全唐詩/json/514.json','["識君春未半，意欲住經秋。見酒連詩句，逢花跋馬頭。", "別來唯獨宿，夢裏尚同遊。所在求飧過，無因離得愁。"]'),
('yuding-22','雪夜與真上人宿韓協律宅','朱慶餘','唐','御定全唐诗','yuding','','[]','斜雪微沾砌，空堂夜語清。逆風聽漏短，回燭向樓明。',48,'御定全唐詩/json/514.json','["斜雪微沾砌，空堂夜語清。逆風聽漏短，回燭向樓明。", "盥漱隨禪伴，謳吟得野情。此歡那敢忘，世貴丈夫名。"]'),
('yuding-23','與賈島、顧非熊、無可上人宿萬年姚少府宅','朱慶餘','唐','御定全唐诗','yuding','','[]','莫厭通宵坐，貧中會聚難。堂虛雪氣入，燈在漏聲殘。',48,'御定全唐詩/json/514.json','["莫厭通宵坐，貧中會聚難。堂虛雪氣入，燈在漏聲殘。", "役思因生病，當禪豈覺寒。開門各有事，非不惜餘歡。"]'),
('yuding-24','震為蒼筤竹','朱慶餘','唐','御定全唐诗','yuding','','[]','為擢東方秀，修然異眾筠。青蒼才映粉，蒙密正含春。',72,'御定全唐詩/json/514.json','["為擢東方秀，修然異眾筠。青蒼才映粉，蒙密正含春。", "嫩籜沾微雨，幽根絕細塵。乍憐分徑小，偏覺帶煙新。", "結實皆留鳳，垂陰似庇人。顧唯竿在手，深水掛赬鱗。"]'),
('yuding-25','題青龍寺','朱慶餘','唐','御定全唐诗','yuding','','[]','寺好因崗勢，登臨值夕陽。青山當佛閣，紅葉滿僧廊。',48,'御定全唐詩/json/514.json','["寺好因崗勢，登臨值夕陽。青山當佛閣，紅葉滿僧廊。", "竹色連平地，蟲聲在上方。最憐東面靜，為近楚城牆。"]'),
('yuding-26','送滕庶子致仕歸江南','朱慶餘','唐','御定全唐诗','yuding','','[]','常懷獨往意，此日去朝簪。丹詔榮歸騎，清風滿故林。',48,'御定全唐詩/json/514.json','["常懷獨往意，此日去朝簪。丹詔榮歸騎，清風滿故林。", "諸侯新起敬，遺老重相尋。在處饒山水，堪行慰所心。"]'),
('yuding-27','夏日題武功姚主簿','朱慶餘','唐','御定全唐诗','yuding','','[]','亭午無公事，垂簾樹色間。僧來茶灶動，吏去印床閑。',48,'御定全唐詩/json/514.json','["亭午無公事，垂簾樹色間。僧來茶灶動，吏去印床閑。", "傍竹行尋巷，當門立看山。吟詩老不倦，未省話官班。"]'),
('yuding-28','送張景宣下第東歸','朱慶餘','唐','御定全唐诗','yuding','','[]','歸省值花時，閑吟落第詩。高情憐道在，公論覺才遺。',48,'御定全唐詩/json/514.json','["歸省值花時，閑吟落第詩。高情憐道在，公論覺才遺。", "春雨連淮暗，私船過馬遲。離心可惆悵，為有入城期。"]'),
('yuding-29','送顧非熊下第歸','朱慶餘','唐','御定全唐诗','yuding','','[]','但取詩名遠，寧論下第頻。惜為今日別，共受幾年貧。',48,'御定全唐詩/json/514.json','["但取詩名遠，寧論下第頻。惜為今日別，共受幾年貧。", "聽雨宿吳寺，過江逢越人。知從本府薦，秋晚又辭親。"]'),
('yuding-30','送韋繇校書赴浙東幕','朱慶餘','唐','御定全唐诗','yuding','','[]','丞相辟書新，秋關獨去人。官離芸閣早，名占甲科頻。',48,'御定全唐詩/json/514.json','["丞相辟書新，秋關獨去人。官離芸閣早，名占甲科頻。", "水驛迎船火，山城候騎塵。湖邊寄家久，到日喜榮親。"]'),
('yuding-31','尋賈島所居','朱慶餘','唐','御定全唐诗','yuding','','[]','求閑身未得，此日到京東。獨在鐘聲外，相逢樹色中。',48,'御定全唐詩/json/514.json','["求閑身未得，此日到京東。獨在鐘聲外，相逢樹色中。", "誰言人漸老，所向意皆同。月上因留宿，移床對藥叢。"]'),
('yuding-32','題毗陵上人院','朱慶餘','唐','御定全唐诗','yuding','','[]','院深終日靜，落葉覆秋蟲。盥漱新齋後，修行未老中。',48,'御定全唐詩/json/514.json','["院深終日靜，落葉覆秋蟲。盥漱新齋後，修行未老中。", "映松山色遠，隔水磬聲通。此處宜清夜，高吟永與同。"]'),
('yuding-33','送李侍禦入蕃','朱慶餘','唐','御定全唐诗','yuding','','[]','遠使隨雙節，新官屬外台。戎裝非好武，書記本多才。',48,'御定全唐詩/json/514.json','["遠使隨雙節，新官屬外台。戎裝非好武，書記本多才。", "移帳依泉宿，迎人帶雪來。心知玉關道，稀見一花開。"]'),
('yuding-34','望蕭關','朱慶餘','唐','御定全唐诗','yuding','','[]','漸見風沙暗，蕭關欲到時。兒童能探火，婦女解縫旗。',48,'御定全唐詩/json/514.json','["漸見風沙暗，蕭關欲到時。兒童能探火，婦女解縫旗。", "川絕銜魚鷺，林多帶箭麋。暫來戎馬地，不敢苦吟詩。"]'),
('yuding-35','送韓校書赴江西幕','朱慶餘','唐','御定全唐诗','yuding','','[]','從軍五湖外，終是稱詩人。酒後愁將別，塗中過卻春。',72,'御定全唐詩/json/514.json','["從軍五湖外，終是稱詩人。酒後愁將別，塗中過卻春。", "山橋槲葉暗，水館燕巢新。驛舫迎應遠，京書寄自頻。", "野情隨到處，公務日關身。久共趨名利，龍鍾獨滯秦。"]'),
('yuding-36','題寄王秘書','朱慶餘','唐','御定全唐诗','yuding','','[]','唯求買藥價，此外更無機。扶病看紅葉，辭官著白衣。',48,'御定全唐詩/json/514.json','["唯求買藥價，此外更無機。扶病看紅葉，辭官著白衣。", "斷籬通野徑，高樹蔭鄰扉。時馥留僧宿，餘人得見稀。"]'),
('yuding-37','山居','朱慶餘','唐','御定全唐诗','yuding','','[]','歸來青壁下，又見滿籬霜。轉覺琴齋靜，閑從菊地荒。',48,'御定全唐詩/json/514.json','["歸來青壁下，又見滿籬霜。轉覺琴齋靜，閑從菊地荒。", "山泉共鹿飲，林果讓僧嘗。時複收新藥，隨雲過石樑。"]'),
('yuding-38','重過惟貞上人院','朱慶餘','唐','御定全唐诗','yuding','','[]','老去唯求靜，都忘外學名。掃床秋葉滿，對客遠雲生。',48,'御定全唐詩/json/514.json','["老去唯求靜，都忘外學名。掃床秋葉滿，對客遠雲生。", "香合閑留宿，晴階暖共行。窗西暮山色，依舊入詩情。"]'),
('yuding-39','與石晝秀才過普照寺','朱慶餘','唐','御定全唐诗','yuding','','[]','問人知寺路，松竹暗春山。潭黑龍應在，巢空鶴未還。',48,'御定全唐詩/json/514.json','["問人知寺路，松竹暗春山。潭黑龍應在，巢空鶴未還。", "經年為客倦，半日與僧閑。更共嘗新茗，聞鐘笑語間。"]'),
('yuding-40','題任處士幽居','朱慶餘','唐','御定全唐诗','yuding','','[]','惜與幽人別，停舟對草堂。湖雲侵臥位，杉露滴茶床。',48,'御定全唐詩/json/514.json','["惜與幽人別，停舟對草堂。湖雲侵臥位，杉露滴茶床。", "山月吟時在，池花覺後香。生涯無一物，誰與讀書糧。"]'),
('yuding-41','送僧往太原謁李司空','朱慶餘','唐','御定全唐诗','yuding','','[]','已共鄰房別，應無更住心。中時過野店，後夜宿寒林。',48,'御定全唐詩/json/514.json','["已共鄰房別，應無更住心。中時過野店，後夜宿寒林。", "寺去人煙遠，城連塞雪深。禪餘得新句，堪對上公吟。"]'),
('yuding-42','將之上京別淮南書記李侍禦','朱慶餘','唐','御定全唐诗','yuding','','[]','心地偶相見，語多為別難。詩成公府晚，路入翠微寒。',48,'御定全唐詩/json/514.json','["心地偶相見，語多為別難。詩成公府晚，路入翠微寒。", "逢石自應坐，有花誰共看。身為當去雁，雲盡到長安。"]'),
('yuding-43','韓協律相送精舍讀書四韻奉寄呈陸補闕','朱慶餘','唐','御定全唐诗','yuding','','[]','白鶴西山別，更看上去船。遙知尋寺路，應念宿江煙。',48,'御定全唐詩/json/514.json','["白鶴西山別，更看上去船。遙知尋寺路，應念宿江煙。", "到處無閑日，回期已來年。何因陪夜坐，清論諫臣邊。"]'),
('yuding-44','過蘇州曉上人院','朱慶餘','唐','御定全唐诗','yuding','','[]','夏滿律當清，無中景自生。移松不避遠，取石亦親行。',48,'御定全唐詩/json/514.json','["夏滿律當清，無中景自生。移松不避遠，取石亦親行。", "經案離時少，繩床著處平。若將林下比，應只欠泉聲。"]'),
('yuding-45','送僧遊縉雲','朱慶餘','唐','御定全唐诗','yuding','','[]','但望青山去，何山不是緣。寺幽堪講律，月冷稱當禪。',48,'御定全唐詩/json/514.json','["但望青山去，何山不是緣。寺幽堪講律，月冷稱當禪。", "水落無風夜，猿吟欲雨天。尋師若有路，終作緩歸年。"]'),
('yuding-46','贈道者','朱慶餘','唐','御定全唐诗','yuding','','[]','自識來清瘦，尋常語論真。藥成休伏火，符驗不傳人。',48,'御定全唐詩/json/514.json','["自識來清瘦，尋常語論真。藥成休伏火，符驗不傳人。", "獨有年過鶴，曾無病到身。潛教問弟子，居處與誰鄰。"]'),
('yuding-47','杭州盧錄事山亭','朱慶餘','唐','御定全唐诗','yuding','','[]','山色滿公署，到來詩景饒。解衣臨曲榭，隔竹見紅蕉。',72,'御定全唐詩/json/514.json','["山色滿公署，到來詩景饒。解衣臨曲榭，隔竹見紅蕉。", "清漏焚香夕，輕嵐視事朝。靜中看鎖印，高處見迎潮。", "曳履庭蕪近，當身樹葉飄。傍城餘菊在，步入一仙瓢。"]'),
('yuding-48','送品上人入秦','朱慶餘','唐','御定全唐诗','yuding','','[]','獨去何人見，林塘共寂寥。生緣聞磬早，覺路出塵遙。',48,'御定全唐詩/json/514.json','["獨去何人見，林塘共寂寥。生緣聞磬早，覺路出塵遙。", "江雪沾新草，秦園發故條。心知禪定處，石室對芭蕉。"]'),
('yuding-49','題薔薇花','朱慶餘','唐','御定全唐诗','yuding','','[]','四面垂條密，浮陰入夏清。綠攢傷手刺，紅墮斷腸英。',48,'御定全唐詩/json/514.json','["四面垂條密，浮陰入夏清。綠攢傷手刺，紅墮斷腸英。", "粉著蜂須膩，光凝蝶翅明。雨中看亦好，況複值初晴。"]'),
('yuding-50','題胡氏溪亭','朱慶餘','唐','御定全唐诗','yuding','','[]','亭與溪相近，無時不有風。澗松生便黑，野蘚看多紅。',48,'御定全唐詩/json/514.json','["亭與溪相近，無時不有風。澗松生便黑，野蘚看多紅。", "雨足秋聲後，山沈夜色中。主人能守靜，略與客心同。"]'),
('yuding-51','看濤','朱慶餘','唐','御定全唐诗','yuding','','[]','不知來遠近，但見白峨峨。風雨驅寒玉，魚龍迸上波。',48,'御定全唐詩/json/514.json','["不知來遠近，但見白峨峨。風雨驅寒玉，魚龍迸上波。", "聲長勢未盡，曉去夕還過。要路橫天塹，其如造化何。"]'),
('yuding-52','和劉補闕秋園寓興之什十首','朱慶餘','唐','御定全唐诗','yuding','','[]','閑園清氣滿，新興日堪追。隔水蟬鳴後，當簷雁過時。',480,'御定全唐詩/json/514.json','["閑園清氣滿，新興日堪追。隔水蟬鳴後，當簷雁過時。", "雨餘槐穟重，霜近藥苗衰。不以朝簪貴，多將野客期。", "誰言高靜意，不異在衡茅。竹冷人離洞，天晴鶴出巢。", "深籬藏白菌，荒蔓露青匏。幾見中宵月，清光墜樹梢。", "逍遙人事外，杖屨入杉蘿。草色寒猶在，蟲聲晚漸多。", "靜逢山鳥下，幽稱野僧過。幾許新開菊，閑從落葉和。", "留情清景宴，朝罷有餘閑。蝶散紅蘭外，螢飛白露間。", "牆高微見寺，林靜遠分山。吟足期相訪，殘陽自掩關。", "深齋嘗獨處，詎肯厭秋聲。翠筱寒愈靜，孤花晚更明。", "每因逢石坐，多見抱書行。入夜聽疏杵，遙知耿此情。", "蒼翠經宵在，園廬景自深。風淒欲去燕，月思向來砧。", "碧石當莎徑，寒煙冒竹林。杯瓢閑寄詠，清絕是知音。", "門巷唯苔蘚，誰言不稱貧。台閒人下晚，果熟鳥來頻。", "石脈潛通井，松枝靜離塵。殘蔬得晴後，又見一番新。", "捲簾天色靜，近瀨覺衣單。蕉葉猶停翠，桐陰已爽寒。", "雲從高處望，琴愛靜時彈。正去重陽近，吟秋意未闌。", "竹徑通鄰圃，清深稱獨遊。蟲絲交影細，藤子墜聲幽。", "積潤苔紋厚，迎寒薺葉稠。閑來尋古畫，未廢執茶甌。", "風物已蕭颯，晚煙生霽容。斜分紫陌樹，遠隔翠微鐘。", "宿客論文靜，閑燈落燼重。無窮林下意，真得古人風。"]'),
('yuding-53','上翰林蔣防舍人','朱慶餘','唐','御定全唐诗','yuding','','[]','清重可過知內制，從前禮絕外庭人。看花在處多隨駕，',40,'御定全唐詩/json/514.json','["清重可過知內制，從前禮絕外庭人。看花在處多隨駕，", "應憐獨在文場久，十有餘年浪過春。"]'),
('yuding-54','上翰林李舍人','朱慶餘','唐','御定全唐诗','yuding','','[]','記得早年曾拜識，便憐孤進賞文章。免令汩沒慚時輩，',40,'御定全唐詩/json/514.json','["記得早年曾拜識，便憐孤進賞文章。免令汩沒慚時輩，", "雲泥雖隔思長在，縱使無成也不忘。"]'),
('yuding-55','題章正字道正新居','朱慶餘','唐','御定全唐诗','yuding','','[]','獨在禦樓南畔住，生涯還似舊時貧。全無竹可侵行徑，',40,'御定全唐詩/json/514.json','["獨在禦樓南畔住，生涯還似舊時貧。全無竹可侵行徑，", "近來漸覺青莎巷，車馬過從已有塵。"]'),
('yuding-56','送李餘及第歸蜀','朱慶餘','唐','御定全唐诗','yuding','','[]','從得高科名轉盛，亦言歸去滿城知。發時誰不開筵送，',40,'御定全唐詩/json/514.json','["從得高科名轉盛，亦言歸去滿城知。發時誰不開筵送，", "鄉中後輩游門館，半是來求近日詩。"]'),
('yuding-57','送唐中丞開淘西湖夏日遊泛因書示郡人','朱慶餘','唐','御定全唐诗','yuding','','[]','萍岸新淘見碧霄，中流相去忽成遙。空餘孤嶼來詩景，',40,'御定全唐詩/json/514.json','["萍岸新淘見碧霄，中流相去忽成遙。空餘孤嶼來詩景，", "共知浸潤同雷澤，何慮川源有旱苗。"]'),
('yuding-58','過舊宅','朱慶餘','唐','御定全唐诗','yuding','','[]','古巷戟門誰舊宅，早曾聞說屬官家。更無新燕來巢屋，',40,'御定全唐詩/json/514.json','["古巷戟門誰舊宅，早曾聞說屬官家。更無新燕來巢屋，", "榮華事歇皆如此，立馬踟躕到日斜。"]'),
('yuding-59','鄂渚送白舍人赴杭州','朱慶餘','唐','御定全唐诗','yuding','','[]','豈知鸚鵡洲邊路，得見鳳凰池上人。',32,'御定全唐詩/json/514.json','["豈知鸚鵡洲邊路，得見鳳凰池上人。", "從此不同諸客禮，故鄉西與郡城鄰。"]'),
('yuding-60','題崔駙馬林亭','朱慶餘','唐','御定全唐诗','yuding','','[]','選居幽近禦街東，易得詩人聚會同。白練鳥飛深竹裏，',40,'御定全唐詩/json/514.json','["選居幽近禦街東，易得詩人聚會同。白練鳥飛深竹裏，", "何事宦塗猶寂寞，都緣清苦道難通。"]'),
('yuding-61','贈韓協律','朱慶餘','唐','御定全唐诗','yuding','','[]','永日微吟在竹前，骨清唯愛漱寒泉。門閑多有投文客，',40,'御定全唐詩/json/514.json','["永日微吟在竹前，骨清唯愛漱寒泉。門閑多有投文客，", "親知盡怪疏榮祿，的是將心暗學禪。"]'),
('yuding-62','自蕭關望臨洮','朱慶餘','唐','御定全唐诗','yuding','','[]','玉關西路出臨洮，風卷邊沙入馬毛。寺寺院中無竹樹，',40,'御定全唐詩/json/514.json','["玉關西路出臨洮，風卷邊沙入馬毛。寺寺院中無竹樹，", "日暮獨吟秋色裏，平原一望戍樓高。"]'),
('yuding-63','送崔約下第歸淮南覲省','朱慶餘','唐','御定全唐诗','yuding','','[]','遠憶拜親留不住，出門行計與誰同。程塗半是依船上，',40,'御定全唐詩/json/514.json','["遠憶拜親留不住，出門行計與誰同。程塗半是依船上，", "回期須及來春事，莫便江邊逐釣翁。"]'),
('yuding-64','羽林郎','朱慶餘','唐','御定全唐诗','yuding','','[]','紫髯年少奉恩初，直閣將軍盡不如。酒後引兵圍百草，',40,'御定全唐詩/json/514.json','["紫髯年少奉恩初，直閣將軍盡不如。酒後引兵圍百草，", "大笑魯儒年四十，腰間猶未識金魚。"]'),
('yuding-65','歸故園','朱慶餘','唐','御定全唐诗','yuding','','[]','桑柘駢闐數畝間，門前五柳正堪攀。尊中美酒長須滿，',40,'御定全唐詩/json/514.json','["桑柘駢闐數畝間，門前五柳正堪攀。尊中美酒長須滿，", "於焉已是忘機地，何用將金別買山。"]'),
('yuding-66','同友人看花','朱慶餘','唐','御定全唐诗','yuding','','[]','尋花不問春深淺，縱是殘紅也入詩。',32,'御定全唐詩/json/514.json','["尋花不問春深淺，縱是殘紅也入詩。", "每個樹邊行一匝，誰家園裏最多時。"]'),
('yuding-67','種花','朱慶餘','唐','御定全唐诗','yuding','','[]','憶昔兩京官道上，可憐桃李晝陰垂。',32,'御定全唐詩/json/514.json','["憶昔兩京官道上，可憐桃李晝陰垂。", "不知誰作巡花使，空記玄宗遣種時。"]'),
('yuding-68','早發廬江塗中遇雪寄李侍禦','朱慶餘','唐','御定全唐诗','yuding','','[]','蘆葦聲多雁滿陂，濕雲連野見山稀。',32,'御定全唐詩/json/514.json','["蘆葦聲多雁滿陂，濕雲連野見山稀。", "遙知將吏相逢處，半是春城賀雪歸。"]'),
('yuding-69','登望雲亭招友','朱慶餘','唐','御定全唐诗','yuding','','[]','日日恐無雲可望，不辭逐靜望來頻。',32,'御定全唐詩/json/514.json','["日日恐無雲可望，不辭逐靜望來頻。", "共知亭下眠雲遠，解到上頭能幾人。"]'),
('yuding-70','劉補闕西亭晚宴','朱慶餘','唐','御定全唐诗','yuding','','[]','蟲聲已盡菊花幹，共立松陰向晚寒。',32,'御定全唐詩/json/514.json','["蟲聲已盡菊花幹，共立松陰向晚寒。", "對酒看山俱惜去，不知斜月下欄幹。"]'),
('yuding-71','送長安羅少府','朱慶餘','唐','御定全唐诗','yuding','','[]','科名再得年猶少，今日休官更覺賢。去國已辭趨府伴，',40,'御定全唐詩/json/514.json','["科名再得年猶少，今日休官更覺賢。去國已辭趨府伴，", "在處若逢山水住，到時應不及秋前。"]'),
('yuding-72','林下招胡長官','朱慶餘','唐','御定全唐诗','yuding','','[]','語低清貌似休糧，稱著朱衣入草堂。',32,'御定全唐詩/json/514.json','["語低清貌似休糧，稱著朱衣入草堂。", "銷暑近來無別物，桂陰當午滿繩床。"]'),
('yuding-73','與真上人一二禪師題玢寺主院','朱慶餘','唐','御定全唐诗','yuding','','[]','杖屨相隨任處便，不唯空寄上方眠。',32,'御定全唐詩/json/514.json','["杖屨相隨任處便，不唯空寄上方眠。", "歸時亦取湖邊路，晚映楓林共上船。"]'),
('yuding-74','尋僧','朱慶餘','唐','御定全唐诗','yuding','','[]','吟背春城出草遲，天晴紫閣赴僧期。',32,'御定全唐詩/json/514.json','["吟背春城出草遲，天晴紫閣赴僧期。", "山邊樹下行人少，一派新泉日午時。"]'),
('yuding-75','題王丘長史宅','朱慶餘','唐','御定全唐诗','yuding','','[]','更無人吏在門前，不似居官似學仙。藥氣暗侵朝服上，',40,'御定全唐詩/json/514.json','["更無人吏在門前，不似居官似學仙。藥氣暗侵朝服上，", "時見街中騎瘦馬，低頭只是為詩篇。"]'),
('yuding-76','寄劉少府','朱慶餘','唐','御定全唐诗','yuding','','[]','唯愛圖書兼古器，在官猶自未離貧。',32,'御定全唐詩/json/514.json','["唯愛圖書兼古器，在官猶自未離貧。", "更聞縣去青山近，稱與詩人作主人。"]'),
('yuding-77','哭胡遇','朱慶餘','唐','御定全唐诗','yuding','','[]','尋僧昨日尚相隨，忽見緋幡意可知。題處舊詩休更讀，',40,'御定全唐詩/json/514.json','["尋僧昨日尚相隨，忽見緋幡意可知。題處舊詩休更讀，", "每向宣陽裏中過，遙聞哭臨淚先垂。"]'),
('yuding-78','自述','朱慶餘','唐','御定全唐诗','yuding','','[]','詩人甘寂寞，居處遍蒼苔。後夜蟾光滿，鄰家樹影來。',48,'御定全唐詩/json/514.json','["詩人甘寂寞，居處遍蒼苔。後夜蟾光滿，鄰家樹影來。", "豈知蓮帳好，自愛草堂開。願答相思意，援毫愧不才。"]'),
('yuding-0','省試晦日與同志昆明池泛舟','朱慶餘','唐','御定全唐诗','yuding','','[]','故人同泛處，遠色望中明。靜見沙痕露，微思月魄生。',72,'御定全唐詩/json/515.json','["故人同泛處，遠色望中明。靜見沙痕露，微思月魄生。", "周回餘雪在，浩渺暮雲平。戲鳥隨蘭棹，空波蕩石鯨。", "劫灰難問理，島樹偶知名。自省曾追賞，無如此日情。"]'),
('yuding-1','送崔拾遺赴闕','朱慶餘','唐','御定全唐诗','yuding','','[]','清貌淩寒玉，朝來拜拾遺。行承天子詔，去感主人知。',48,'御定全唐詩/json/515.json','["清貌淩寒玉，朝來拜拾遺。行承天子詔，去感主人知。", "劍佩分班日，風霜獨立時。名高住不得，非與九霄期。"]'),
('yuding-2','酬李處士見贈','朱慶餘','唐','御定全唐诗','yuding','','[]','幹上非無援，才多卻累身。雲霄未得路，江海作閒人。',48,'御定全唐詩/json/515.json','["幹上非無援，才多卻累身。雲霄未得路，江海作閒人。", "久別唯謀道，相逢不話貧。行藏一如此，可便老風塵。"]'),
('yuding-3','送僧游溫州','朱慶餘','唐','御定全唐诗','yuding','','[]','夏滿隨所適，江湖非系緣。卷經離嶠寺，隔葦上秋船。',48,'御定全唐詩/json/515.json','["夏滿隨所適，江湖非系緣。卷經離嶠寺，隔葦上秋船。", "水落無風夜，猿啼欲雨天。石門期獨往，謝守有遺篇。"]'),
('yuding-4','夢謝亭','朱慶餘','唐','御定全唐诗','yuding','','[]','夢後何人見，孤亭似舊時。褰開誠得地，冥感竟因詩。',48,'御定全唐詩/json/515.json','["夢後何人見，孤亭似舊時。褰開誠得地，冥感竟因詩。", "不往過應少，悲來下獨遲。顧慚非謝客，靈貺杳難追。"]'),
('yuding-5','河亭','朱慶餘','唐','御定全唐诗','yuding','','[]','孤亭臨絕岸，猿鳥識幽蹊。花落曾誰到，詩成獨未題。',48,'御定全唐詩/json/515.json','["孤亭臨絕岸，猿鳥識幽蹊。花落曾誰到，詩成獨未題。", "潮痕經雨在，石筍與杉齊。謝守便登陟，秋來屐齒低。"]'),
('yuding-6','送吳秀才之山西','朱慶餘','唐','御定全唐诗','yuding','','[]','澤潞西邊路，蘭橈北去人。出門誰恨別，投分不緣貧。',48,'御定全唐詩/json/515.json','["澤潞西邊路，蘭橈北去人。出門誰恨別，投分不緣貧。", "杯酒從年少，知音在日新。東湖發詩意，夏卉竟如春。"]'),
('yuding-7','和處州嚴郎中游南溪','朱慶餘','唐','御定全唐诗','yuding','','[]','四望非人境，從前洞穴深。潭清蒲遠岸，嵐積樹無陰。',48,'御定全唐詩/json/515.json','["四望非人境，從前洞穴深。潭清蒲遠岸，嵐積樹無陰。", "看草初移屐，捫蘿忽並簪。世嫌山水僻，誰伴謝公吟。"]'),
('yuding-8','秋宵宴別盧侍禦','朱慶餘','唐','御定全唐诗','yuding','','[]','風亭弦管絕，玉漏一聲新。綠茗香醒酒，寒燈靜照人。',48,'御定全唐詩/json/515.json','["風亭弦管絕，玉漏一聲新。綠茗香醒酒，寒燈靜照人。", "清班無意戀，素業本來貧。明發青山道，誰逢去馬塵。"]'),
('yuding-9','酬於欣校書見貽','朱慶餘','唐','御定全唐诗','yuding','','[]','能□得從軍，清嬴□□□。綺羅徒滿目，山水不離心。',48,'御定全唐詩/json/515.json','["能□得從軍，清嬴□□□。綺羅徒滿目，山水不離心。", "暫別愁花老，相思倚竹陰。家貧無以養，未可話抽簪。"]'),
('yuding-10','送石協律歸吳興別業','朱慶餘','唐','御定全唐诗','yuding','','[]','識來無定居，此去複何如。一與耕者遇，轉將朝客疏。',48,'御定全唐詩/json/515.json','["識來無定居，此去複何如。一與耕者遇，轉將朝客疏。", "資身唯藥草，教子但詩書。曾許黃庭本，斯言豈合虛。"]'),
('yuding-11','同盧校書遊新興寺','朱慶餘','唐','御定全唐诗','yuding','','[]','山深雲景別，有寺亦堪過。才子將迎遠，林僧氣性和。',48,'御定全唐詩/json/515.json','["山深雲景別，有寺亦堪過。才子將迎遠，林僧氣性和。", "潭清蒲影定，松老鶴聲多。豈不思公府，其如野興何。"]'),
('yuding-12','送馬秀才','朱慶餘','唐','御定全唐诗','yuding','','[]','清貌不識睡，見來嘗苦吟。風塵歸省日，江海寄家心。',48,'御定全唐詩/json/515.json','["清貌不識睡，見來嘗苦吟。風塵歸省日，江海寄家心。", "與鶴期前島，隨僧過遠林。相于竟何事，無語與知音。"]'),
('yuding-13','贈律師院','朱慶餘','唐','御定全唐诗','yuding','','[]','粉壁通蓮徑，扁舟到不迷。葦聲過枕上，湖色滿窗西。',48,'御定全唐詩/json/515.json','["粉壁通蓮徑，扁舟到不迷。葦聲過枕上，湖色滿窗西。", "但見修行苦，誰論夏臘低。閑看種來樹，已覺與身齊。"]'),
('yuding-14','送僧往台岳','朱慶餘','唐','御定全唐诗','yuding','','[]','五城初罷講，海上憶閑行。觸雪麻衣靜，登山竹錫輕。',48,'御定全唐詩/json/515.json','["五城初罷講，海上憶閑行。觸雪麻衣靜，登山竹錫輕。", "天寒嶽寺出，日晚島泉清。坐與幽期遇，何人識此情。"]'),
('yuding-15','送惠雅上人西游','朱慶餘','唐','御定全唐诗','yuding','','[]','五湖僧獨往，此去與誰期。興遠常憐鶴，禪餘肯廢詩。',48,'御定全唐詩/json/515.json','["五湖僧獨往，此去與誰期。興遠常憐鶴，禪餘肯廢詩。", "望雲回寺晚，為講到城遲。還想安居日，應當後夏時。"]'),
('yuding-16','將之上京留別淮南書記李侍禦','朱慶餘','唐','御定全唐诗','yuding','','[]','半似無名位，門當靜處開。人心皆向德，物色不供才。',48,'御定全唐詩/json/515.json','["半似無名位，門當靜處開。人心皆向德，物色不供才。", "酒興春邊過，軍謀意外來。取名榮相府，卻慮詔書催。"]'),
('yuding-17','送祝秀才歸衢州','朱慶餘','唐','御定全唐诗','yuding','','[]','舊隱縠溪上，憶歸年已深。學徒花下別，鄉路雪邊尋。',48,'御定全唐詩/json/515.json','["舊隱縠溪上，憶歸年已深。學徒花下別，鄉路雪邊尋。", "騎吏陪春賞，江僧伴晚吟。高科如在意，當自惜光陰。"]'),
('yuding-18','過孟浩然舊居','朱慶餘','唐','御定全唐诗','yuding','','[]','命合終山水，才非不稱時。塚邊空有樹，身後獨無兒。',48,'御定全唐詩/json/515.json','["命合終山水，才非不稱時。塚邊空有樹，身後獨無兒。", "散盡詩篇本，長存道德碑。平生誰見重，應只是王維。"]'),
('yuding-19','送虛上人游天臺','朱慶餘','唐','御定全唐诗','yuding','','[]','青冥通去路，誰見獨隨緣。此地春前別，何山夜後禪。',48,'御定全唐詩/json/515.json','["青冥通去路，誰見獨隨緣。此地春前別，何山夜後禪。", "石橋隱深樹，朱闕見晴天。好是修行處，師當住幾年。"]'),
('yuding-20','孔尚書致仕因而有寄贈','朱慶餘','唐','御定全唐诗','yuding','','[]','高人心易足，三表乞身閑。與世長疏索，唯僧得往還。',48,'御定全唐詩/json/515.json','["高人心易足，三表乞身閑。與世長疏索，唯僧得往還。", "直聲留闕下，生事在林間。時複逢清景，乘車看遠山。"]'),
('yuding-21','和處州韋使君新開南溪','朱慶餘','唐','御定全唐诗','yuding','','[]','地裏光圖讖，樵人共說深。悠然想高躅，坐使變荒岑。',120,'御定全唐詩/json/515.json','["地裏光圖讖，樵人共說深。悠然想高躅，坐使變荒岑。", "疏鑿因殊舊，亭台亦自今。靜容猿暫下，閑與鶴同尋。", "轉旆馴禽起，褰帷瀑溜侵。石稀潭見底，嵐暗樹無陰。", "躋險難通屐，攀棲稱抱琴。雲風開物意，潭水識人心。", "攜榼巡花遍，移舟惜景沈。世嫌山水僻，誰伴謝公吟。"]'),
('yuding-22','送羅先輩書記歸後卻還閩中留別','朱慶餘','唐','御定全唐诗','yuding','','[]','同是越人從小別，忽歸鄉里見皆驚。湖邊訪舊知誰在，',40,'御定全唐詩/json/515.json','["同是越人從小別，忽歸鄉里見皆驚。湖邊訪舊知誰在，", "況當季父承恩日，廉問南州政已成。"]'),
('yuding-23','送浙東陸中丞','朱慶餘','唐','御定全唐诗','yuding','','[]','坐將文教鎮藩維，花滿東南聖主知。公務肯容私暫入，',40,'御定全唐詩/json/515.json','["坐將文教鎮藩維，花滿東南聖主知。公務肯容私暫入，", "自愛此身居樂土，詠歌林下日忘疲。"]'),
('yuding-24','送元處士游天臺','朱慶餘','唐','御定全唐诗','yuding','','[]','青冥路口絕人行，獨與僧期上赤城。樹列煙嵐春更好，',40,'御定全唐詩/json/515.json','["青冥路口絕人行，獨與僧期上赤城。樹列煙嵐春更好，", "若過石橋看瀑布，不妨高處便題名。"]'),
('yuding-25','吳興新堤','朱慶餘','唐','御定全唐诗','yuding','','[]','春堤一望思無涯，樹勢還同水勢斜。深映菰蒲三十裏，',40,'御定全唐詩/json/515.json','["春堤一望思無涯，樹勢還同水勢斜。深映菰蒲三十裏，", "若與青山長作固，汀洲肯恨柳絲遮。"]'),
('yuding-26','酬蕭員外見寄','朱慶餘','唐','御定全唐诗','yuding','','[]','麥風吹雨正徘徊，忽報書從郡閣來。道薄謬應宗伯選，',48,'御定全唐詩/json/515.json','["麥風吹雨正徘徊，忽報書從郡閣來。道薄謬應宗伯選，", "勝寄幸容溪館宿，龍鍾慚見妓筵開。倘期霽後陪新興，"]'),
('yuding-27','台州鄭員外郡齋雙鶴','朱慶餘','唐','御定全唐诗','yuding','','[]','丹頂分明音響別，況聞來處隔雲濤。情懸碧落飛何晚，',40,'御定全唐詩/json/515.json','["丹頂分明音響別，況聞來處隔雲濤。情懸碧落飛何晚，", "仙郎為爾開籠早，莫慮回翔損羽毛。"]'),
('yuding-28','送竇秀才','朱慶餘','唐','御定全唐诗','yuding','','[]','江南才子日紛紛，少有篇章得似君。清話未同山寺宿，',40,'御定全唐詩/json/515.json','["江南才子日紛紛，少有篇章得似君。清話未同山寺宿，", "通籍名高年又少，回頭應笑晚從軍。"]'),
('yuding-29','送邵州林使君','朱慶餘','唐','御定全唐诗','yuding','','[]','軒車此去也逢時，地近湘南頗入詩。一月計程那是遠，',40,'御定全唐詩/json/515.json','["軒車此去也逢時，地近湘南頗入詩。一月計程那是遠，", "想得化行風土變，州人應為立生祠。"]'),
('yuding-30','送饒州張使君','朱慶餘','唐','御定全唐诗','yuding','','[]','白頭為郡清秋別，山水南行豈覺賒。楚老只應思入境，',40,'御定全唐詩/json/515.json','["白頭為郡清秋別，山水南行豈覺賒。楚老只應思入境，", "務退唯當吟詠苦，留心曾不在生涯。"]'),
('yuding-31','題開元寺','朱慶餘','唐','御定全唐诗','yuding','','[]','西入山門十里程，粉牆書字甚分明。蕭帝壞陵深虎跡，',40,'御定全唐詩/json/515.json','["西入山門十里程，粉牆書字甚分明。蕭帝壞陵深虎跡，", "何必更將空色遣，眼前人事是浮生。"]'),
('yuding-32','與龐複言攜酒望洞庭','朱慶餘','唐','御定全唐诗','yuding','','[]','南湖春色通平遠，貪記詩情忘酒杯。帆自巴陵山下過，',40,'御定全唐詩/json/515.json','["南湖春色通平遠，貪記詩情忘酒杯。帆自巴陵山下過，", "盡日與君同看望，了然勝見畫屏開。"]'),
('yuding-33','送浙東周判官','朱慶餘','唐','御定全唐诗','yuding','','[]','久聞從事滄江外，誰謂無官已白頭。來備戎裝嘶數騎，',40,'御定全唐詩/json/515.json','["久聞從事滄江外，誰謂無官已白頭。來備戎裝嘶數騎，", "到日重陪丞相宴，鏡湖新月在城樓。"]'),
('yuding-34','塞下曲','朱慶餘','唐','御定全唐诗','yuding','','[]','萬里去長征，連年慣野營。入群來擇馬，拋伴去擒生。',48,'御定全唐詩/json/515.json','["萬里去長征，連年慣野營。入群來擇馬，拋伴去擒生。", "箭撚雕翎闊，弓盤鵲角輕。問看行近遠，西過受降城。"]'),
('yuding-35','送僧','朱慶餘','唐','御定全唐诗','yuding','','[]','客行皆有為，師去是閒遊。野望攜金策，禪棲寄石樓。',48,'御定全唐詩/json/515.json','["客行皆有為，師去是閒遊。野望攜金策，禪棲寄石樓。", "山深松翠冷，潭靜菊花秋。幾處題青壁，袈裟濺瀑流。"]'),
('yuding-36','望早日','朱慶餘','唐','御定全唐诗','yuding','','[]','窗下聞雞後，蒼茫映遠林。才分天地色，便禁虎狼心。',48,'御定全唐詩/json/515.json','["窗下聞雞後，蒼茫映遠林。才分天地色，便禁虎狼心。", "是處程塗遠，何山洞府深。此時堪佇望，萬象豁塵襟。"]'),
('yuding-37','旅中秋月有懷','朱慶餘','唐','御定全唐诗','yuding','','[]','久客未還鄉，中秋倍可傷。暮天飛旅雁，故國在衡陽。',48,'御定全唐詩/json/515.json','["久客未還鄉，中秋倍可傷。暮天飛旅雁，故國在衡陽。", "島外歸雲迥，林間墜葉黃。數宵千里夢，時見舊書堂。"]'),
('yuding-38','十六夜月','朱慶餘','唐','御定全唐诗','yuding','','[]','昨夜忽已過，冰輪始覺虧。孤光猶不定，浮世更堪疑。',48,'御定全唐詩/json/515.json','["昨夜忽已過，冰輪始覺虧。孤光猶不定，浮世更堪疑。", "影落澄江海，寒生靜路岐。皎然銀漢外，長有眾星隨。"]'),
('yuding-39','行路難','朱慶餘','唐','御定全唐诗','yuding','','[]','世事澆浮後，艱難向此生。人心不自足，公道為誰平。',48,'御定全唐詩/json/515.json','["世事澆浮後，艱難向此生。人心不自足，公道為誰平。", "德喪淳風盡，年荒蔓草盈。堪悲山下路，非只客中行。"]'),
('yuding-40','閒居冬末寄友人','朱慶餘','唐','御定全唐诗','yuding','','[]','短亭分袂後，倚檻思偏孤。雨雪落殘臘，輪蹄在遠塗。',48,'御定全唐詩/json/515.json','["短亭分袂後，倚檻思偏孤。雨雪落殘臘，輪蹄在遠塗。", "人情難故舊，草色易凋枯。共有男兒事，何年入帝都。"]'),
('yuding-41','望九疑','朱慶餘','唐','御定全唐诗','yuding','','[]','浮生猶役役，未得便尋真。白日如無路，青山豈有人。',48,'御定全唐詩/json/515.json','["浮生猶役役，未得便尋真。白日如無路，青山豈有人。", "煙收遙岫小，雨過晚川新。倚杖何凝望，中宵夢往頻。"]'),
('yuding-42','贈陳逸人','朱慶餘','唐','御定全唐诗','yuding','','[]','樂道辭榮祿，安居桂水東。得閒多事外，知足少年中。',48,'御定全唐詩/json/515.json','["樂道辭榮祿，安居桂水東。得閒多事外，知足少年中。", "藥圃無凡草，松庭有素風。朝昏吟步處，琴酒與誰同。"]'),
('yuding-43','湖中閑夜遣興','朱慶餘','唐','御定全唐诗','yuding','','[]','釣艇同琴酒，良宵背水濱。風波不起處，星月盡隨身。',48,'御定全唐詩/json/515.json','["釣艇同琴酒，良宵背水濱。風波不起處，星月盡隨身。", "浦迥湘煙捲，林香嶽氣春。誰知此中興，寧羨五湖人。"]'),
('yuding-44','題娥皇廟','朱慶餘','唐','御定全唐诗','yuding','','[]','娥皇揮涕處，東望九疑天。往事難重問，孤峰尚慘然。',48,'御定全唐詩/json/515.json','["娥皇揮涕處，東望九疑天。往事難重問，孤峰尚慘然。", "夜深寒峒響，秋近碧蘿鮮。未省明君意，遺蹤萬古傳。"]'),
('yuding-45','送友人赴舉','朱慶餘','唐','御定全唐诗','yuding','','[]','世路□□久，嗟君進取身。十年雖苦志，萬里托何人。',48,'御定全唐詩/json/515.json','["世路□□久，嗟君進取身。十年雖苦志，萬里托何人。", "處困非乖道，求名本為親。惟應□□意，先與化龍鱗。"]'),
('yuding-46','中秋月','朱慶餘','唐','御定全唐诗','yuding','','[]','自古分功定，唯應缺又盈。一宵當皎潔，四海盡澄清。',48,'御定全唐詩/json/515.json','["自古分功定，唯應缺又盈。一宵當皎潔，四海盡澄清。", "靜覺風微起，寒過雪乍傾。孤高稀此遇，吟賞倍牽情。"]'),
('yuding-47','宿山居','朱慶餘','唐','御定全唐诗','yuding','','[]','山店燈前客，酬身未有媒。鄉關貧後別，風雨夜深來。',48,'御定全唐詩/json/515.json','["山店燈前客，酬身未有媒。鄉關貧後別，風雨夜深來。", "上國求丹桂，衡門長綠苔。堪驚雙鬢雪，不待歲寒催。"]'),
('yuding-48','夏末留別洞庭知己','朱慶餘','唐','御定全唐诗','yuding','','[]','清秋時節近，分袂獨淒然。此地折高柳，何門聽暮蟬。',48,'御定全唐詩/json/515.json','["清秋時節近，分袂獨淒然。此地折高柳，何門聽暮蟬。", "浪搖湖外日，山背楚南天。空感迢迢事，榮歸在幾年。"]'),
('yuding-49','過洞庭','朱慶餘','唐','御定全唐诗','yuding','','[]','帆掛狂風起，茫茫既往時。波濤如未息，舟楫亦堪疑。',48,'御定全唐詩/json/515.json','["帆掛狂風起，茫茫既往時。波濤如未息，舟楫亦堪疑。", "旅雁投孤島，長天下四維。前程有平處，誰敢與心期。"]'),
('yuding-50','旅中過重陽','朱慶餘','唐','御定全唐诗','yuding','','[]','一歲重陽至，羈遊在異鄉。登高思舊友，滿目是窮荒。',48,'御定全唐詩/json/515.json','["一歲重陽至，羈遊在異鄉。登高思舊友，滿目是窮荒。", "草際飛雲片，天涯落雁行。故山籬畔菊，今日為誰黃。"]'),
('yuding-51','送人下第歸','朱慶餘','唐','御定全唐诗','yuding','','[]','獨立身難達，新春與志違。異鄉青草長，故國白頭歸。',48,'御定全唐詩/json/515.json','["獨立身難達，新春與志違。異鄉青草長，故國白頭歸。", "岸闊湖波溢，程遙楚岫微。高秋期再會，此去莫忘機。"]'),
('yuding-52','敘吟','朱慶餘','唐','御定全唐诗','yuding','','[]','雅道辛勤久，潛疑鬢雪侵。未能酬片善，難更免孤吟。',48,'御定全唐詩/json/515.json','["雅道辛勤久，潛疑鬢雪侵。未能酬片善，難更免孤吟。", "有景皆牽思，無愁不到心。遙天一輪月，幾夜見西沈。"]'),
('yuding-53','塞下感懷','朱慶餘','唐','御定全唐诗','yuding','','[]','塞下閑為客，鄉心豈易安。程塗過萬里，身事尚孤寒。',48,'御定全唐詩/json/515.json','["塞下閑為客，鄉心豈易安。程塗過萬里，身事尚孤寒。", "竟日風沙急，臨秋草木殘。何年方致主，時拂劍塵看。"]'),
('yuding-54','宿江館','朱慶餘','唐','御定全唐诗','yuding','','[]','江館迢遙處，知音信漸賒。夜深鄉夢覺，窗下月明斜。',48,'御定全唐詩/json/515.json','["江館迢遙處，知音信漸賒。夜深鄉夢覺，窗下月明斜。", "起雁看荒草，驚波尚白沙。那堪動鄉思，故國在天涯。"]'),
('yuding-55','早梅','朱慶餘','唐','御定全唐诗','yuding','','[]','天然根性異，萬物盡難陪。自古承春早，嚴冬鬥雪開。',48,'御定全唐詩/json/515.json','["天然根性異，萬物盡難陪。自古承春早，嚴冬鬥雪開。", "豔寒宜雨露，香冷隔塵埃。堪把依松竹，良塗一處栽。"]'),
('yuding-56','夏日訪貞上人院','朱慶餘','唐','御定全唐诗','yuding','','[]','炎夏尋靈境，高僧澹蕩中。命棋隈綠竹，盡日有清風。',48,'御定全唐詩/json/515.json','["炎夏尋靈境，高僧澹蕩中。命棋隈綠竹，盡日有清風。", "流水離經閣，閑雲入梵宮。此時袪萬慮，直似出塵籠。"]'),
('yuding-57','春日旅次','朱慶餘','唐','御定全唐诗','yuding','','[]','林中鶯又囀，為客恨因循。故里遙千里，青春過數春。',48,'御定全唐詩/json/515.json','["林中鶯又囀，為客恨因循。故里遙千里，青春過數春。", "弟兄來漸少，歲月去何頻。早晚榮歸計，中堂會所親。"]'),
('yuding-58','贈至寂禪師','朱慶餘','唐','御定全唐诗','yuding','','[]','處世唯據衲，禪門幾歲寒。法空無所染，性悟不多看。',48,'御定全唐詩/json/515.json','["處世唯據衲，禪門幾歲寒。法空無所染，性悟不多看。", "竟日門長掩，相逢草自殘。有時尋道侶，飛錫度峰巒。"]'),
('yuding-59','閒居即事','朱慶餘','唐','御定全唐诗','yuding','','[]','深嶂多幽景，閒居野興清。滿庭秋雨過，連夜綠苔生。',48,'御定全唐詩/json/515.json','["深嶂多幽景，閒居野興清。滿庭秋雨過，連夜綠苔生。", "石面橫琴坐，松陰采藥行。超然塵事外，不似絆浮名。"]'),
('yuding-60','廢宅花','朱慶餘','唐','御定全唐诗','yuding','','[]','數樹荒庭上，芬芳映綠苔。自緣逢暖發，不是為人開。',48,'御定全唐詩/json/515.json','["數樹荒庭上，芬芳映綠苔。自緣逢暖發，不是為人開。", "色豔鶯猶在，香消蝶已回。相從無勝事，誰向此傾杯。"]'),
('yuding-61','寄友人','朱慶餘','唐','御定全唐诗','yuding','','[]','當代知音少，相思在此身。一分南北路，長問往來人。',48,'御定全唐詩/json/515.json','["當代知音少，相思在此身。一分南北路，長問往來人。", "是處應為客，何門許掃塵。憑書正惆悵，蜀魄數聲新。"]'),
('yuding-62','途中感懷','朱慶餘','唐','御定全唐诗','yuding','','[]','世上名利牽，途中意慘然。到家能幾日，為客便經年。',48,'御定全唐詩/json/515.json','["世上名利牽，途中意慘然。到家能幾日，為客便經年。", "跡似萍隨水，情同鶴在田。何當功業遂，歸路下遙天。"]'),
('yuding-63','贈道者','朱慶餘','唐','御定全唐诗','yuding','','[]','獨住神仙境，門當瀑布開。地多臨水石，行不惹塵埃。',48,'御定全唐詩/json/515.json','["獨住神仙境，門當瀑布開。地多臨水石，行不惹塵埃。", "風起松花散，琴鳴鶴翅回。還歸九天上，時有故人來。"]'),
('yuding-64','長安春日野中','朱慶餘','唐','御定全唐诗','yuding','','[]','青春思楚地，閒步出秦城。滿眼是岐路，何年見弟兄。',48,'御定全唐詩/json/515.json','["青春思楚地，閒步出秦城。滿眼是岐路，何年見弟兄。", "煙霞裝媚景，霄漢指前程。盡日徘徊處，歸鴻過玉京。"]'),
('yuding-65','長城','朱慶餘','唐','御定全唐诗','yuding','','[]','秦帝防胡虜，關心倍可嗟。一人如有德，四海盡為家。',48,'御定全唐詩/json/515.json','["秦帝防胡虜，關心倍可嗟。一人如有德，四海盡為家。", "往事乾坤在，荒基草木遮。至今徒者骨，猶自哭風沙。"]'),
('yuding-66','酬李躔侍禦','朱慶餘','唐','御定全唐诗','yuding','','[]','此去非關興，君行不當遊。無因兩處馬，共飲一溪流。',24,'御定全唐詩/json/515.json','["此去非關興，君行不當遊。無因兩處馬，共飲一溪流。"]'),
('yuding-67','別李侍禦後亭夜坐卻寄','朱慶餘','唐','御定全唐诗','yuding','','[]','已作亭下別，未忘燈下情。吟多欲就枕，更漏轉分明。',24,'御定全唐詩/json/515.json','["已作亭下別，未忘燈下情。吟多欲就枕，更漏轉分明。"]'),
('yuding-68','題錢宇別墅','朱慶餘','唐','御定全唐诗','yuding','','[]','林居向晚饒清景，惜去非關戀酒杯。石淨每因杉露滴，',40,'御定全唐詩/json/515.json','["林居向晚饒清景，惜去非關戀酒杯。石淨每因杉露滴，", "紅葉閑飄籬落迥，行人遠見草堂開。"]'),
('yuding-69','近試上張籍水部','朱慶餘','唐','御定全唐诗','yuding','','[]','洞房昨夜停紅燭，待曉堂前拜舅姑。',32,'御定全唐詩/json/515.json','["洞房昨夜停紅燭，待曉堂前拜舅姑。", "妝罷低聲問夫婿，畫眉深淺入時無。"]'),
('yuding-70','留別盧玄休歸荊門','朱慶餘','唐','御定全唐诗','yuding','','[]','江邊離別心，言罷各沾襟。以我去帆遠，知君離恨深。',48,'御定全唐詩/json/515.json','["江邊離別心，言罷各沾襟。以我去帆遠，知君離恨深。", "雲開孤鳥出，浪起白鷗沈。更作來年約，陽臺許伴尋。"]'),
('yuding-71','採蓮','朱慶餘','唐','御定全唐诗','yuding','','[]','隔煙花草遠濛濛，恨個來時路不同。',32,'御定全唐詩/json/515.json','["隔煙花草遠濛濛，恨個來時路不同。", "正是停橈相遇處，鴛鴦飛去急流中。"]'),
('yuding-72','都門晚望','朱慶餘','唐','御定全唐诗','yuding','','[]','綠槐花墮禦溝邊，步出都門雨後天。',32,'御定全唐詩/json/515.json','["綠槐花墮禦溝邊，步出都門雨後天。", "日暮野人耕種罷，烽樓原上一條煙。"]'),
('yuding-73','舜井','朱慶餘','唐','御定全唐诗','yuding','','[]','碧甃磷磷不記年，青蘿鎖在小山顛。',32,'御定全唐詩/json/515.json','["碧甃磷磷不記年，青蘿鎖在小山顛。", "向來下視千山水，疑是蒼梧萬里天。"]'),
('yuding-74','商州王中丞留吃枳殼','朱慶餘','唐','御定全唐诗','yuding','','[]','方物就中名最遠，只應愈疾味偏佳。',32,'御定全唐詩/json/515.json','["方物就中名最遠，只應愈疾味偏佳。", "若交盡乞人人與，采盡商山枳殼花。"]'),
('yuding-75','登玄都閣','朱慶餘','唐','御定全唐诗','yuding','','[]','野色晴宜上閣看，樹陰遙映禦溝寒。',32,'御定全唐詩/json/515.json','["野色晴宜上閣看，樹陰遙映禦溝寒。", "豪家舊宅無人住，空見朱門鎖牡丹。"]'),
('yuding-76','贈鳳翔柳司錄','朱慶餘','唐','御定全唐诗','yuding','','[]','杏園北寺題名日，數到如今四十年。',32,'御定全唐詩/json/515.json','["杏園北寺題名日，數到如今四十年。", "點檢生涯與官職，一莖野竹在身邊。"]'),
('yuding-77','啄木兒','朱慶餘','唐','御定全唐诗','yuding','','[]','丁丁向晚急還稀，啄遍庭槐未肯歸。',32,'御定全唐詩/json/515.json','["丁丁向晚急還稀，啄遍庭槐未肯歸。", "終日與君除蠹害，莫嫌無事不頻飛。"]'),
('yuding-78','榜曲','朱慶餘','唐','御定全唐诗','yuding','','[]','荷花明滅水煙空，惆悵來時徑不同。',32,'御定全唐詩/json/515.json','["荷花明滅水煙空，惆悵來時徑不同。", "欲到前洲堪入處，鴛鴦飛出碧流中。"]'),
('yuding-79','逢山人','朱慶餘','唐','御定全唐诗','yuding','','[]','星月相逢現此身，自然無跡又無塵。',32,'御定全唐詩/json/515.json','["星月相逢現此身，自然無跡又無塵。", "秋來若向金天會，便是青蓮葉上人。"]'),
('yuding-80','過耶溪','朱慶餘','唐','御定全唐诗','yuding','','[]','春溪繚繞出無窮，兩岸桃花正好風。',32,'御定全唐詩/json/515.json','["春溪繚繞出無窮，兩岸桃花正好風。", "恰是扁舟堪入處，鴛鴦飛起碧流中。"]'),
('yuding-81','賀張水部員外拜命','朱慶餘','唐','御定全唐诗','yuding','','[]','省中官最美，無似水曹郎。前代佳名遜，當時重姓張。',48,'御定全唐詩/json/515.json','["省中官最美，無似水曹郎。前代佳名遜，當時重姓張。", "白須吟麗句，紅葉吐朝陽。徒有歸山意，君恩未可忘。"]'),
('yuding-82','送璧州劉使君','朱慶餘','唐','御定全唐诗','yuding','','[]','王府登朝後，巴鄉典郡新。江分入峽路，山見采鞭人。',48,'御定全唐詩/json/515.json','["王府登朝後，巴鄉典郡新。江分入峽路，山見采鞭人。", "舊業孤城夢，生祠幾處身。知君素清儉，料得卻來貧。"]'),
('yuding-83','贈江夏盧使君','朱慶餘','唐','御定全唐诗','yuding','','[]','詩人中最屈，無與使君儔。白髮雖求退，明時合見收。',48,'御定全唐詩/json/515.json','["詩人中最屈，無與使君儔。白髮雖求退，明時合見收。", "登山猶自健，縱酒可多愁。好是能騎馬，相逢見鄂州。"]'),
('yuding-84','送崔秀才游江陵','朱慶餘','唐','御定全唐诗','yuding','','[]','樽前荊楚客，雲外思縈回。秦野春已盡，商山花正開。',48,'御定全唐詩/json/515.json','["樽前荊楚客，雲外思縈回。秦野春已盡，商山花正開。", "鷗驚帆乍起，虹見雨初來。自有歸期在，蟬聲處處催。"]'),
('yuding-85','觀濤','朱慶餘','唐','御定全唐诗','yuding','','[]','木落霜飛天地清，空江百里見潮生。鮮飆出海魚龍氣，',40,'御定全唐詩/json/515.json','["木落霜飛天地清，空江百里見潮生。鮮飆出海魚龍氣，", "高樓曉望無窮意，丹葉黃花繞郡城。"]'),
('yuding-86','南湖','朱慶餘','唐','御定全唐诗','yuding','','[]','湖上微風小檻涼，翻翻菱荇滿回塘。野船著岸入春草，',40,'御定全唐詩/json/515.json','["湖上微風小檻涼，翻翻菱荇滿回塘。野船著岸入春草，", "飄然蓬艇東歸客，盡日相看憶楚鄉。"]'),
('yuding-87','鏡湖西島言事','朱慶餘','唐','御定全唐诗','yuding','','[]','慵拙幸便荒僻地，縱聞猿鳥亦何愁。偶因藥酒欺梅雨，',40,'御定全唐詩/json/515.json','["慵拙幸便荒僻地，縱聞猿鳥亦何愁。偶因藥酒欺梅雨，", "世人若便無知己，應向此溪成白頭。"]'),
('yuding-88','送劉思複南河從軍','朱慶餘','唐','御定全唐诗','yuding','','[]','七千里別寧無恨，且貴從軍樂事多。不駐節旄先候發，',40,'御定全唐詩/json/515.json','["七千里別寧無恨，且貴從軍樂事多。不駐節旄先候發，", "遠作受恩身不易，莫拋書劍近笙歌。"]'),
('yuding-0','宣武軍鎮作','王彥威','唐','御定全唐诗','yuding','','[]','天兵十萬勇如貔，正是酬恩報國時。汴水波瀾喧鼓角，',40,'御定全唐詩/json/516.json','["天兵十萬勇如貔，正是酬恩報國時。汴水波瀾喧鼓角，", "寄語長安舊冠蓋，粗官到底是男兒。"]'),
('yuding-1','春雪映早梅','庾敬休','唐','御定全唐诗','yuding','','[]','清晨凝雪彩，新候變庭梅。樹愛春榮遍，窗驚曙色催。',72,'御定全唐詩/json/516.json','["清晨凝雪彩，新候變庭梅。樹愛春榮遍，窗驚曙色催。", "寒江添粉壁，積潤履青苔。分明六出瑞，隱映幾枝開。", "聞笛花疑落，揮琴興轉來。曲成非寡和，長使思悠哉。"]'),
('yuding-2','題雁塔','許玫','唐','御定全唐诗','yuding','','[]','寶輪金地壓人寰，獨坐蒼冥啟玉關。北嶺風煙開魏闕，',40,'御定全唐詩/json/516.json','["寶輪金地壓人寰，獨坐蒼冥啟玉關。北嶺風煙開魏闕，", "暫放塵心遊物外，六街鐘鼓又催還。"]'),
('yuding-3','從軍行','厲玄','唐','御定全唐诗','yuding','','[]','邊草旱不春，劍光增野塵。戰場收驥尾，清瀚怯龍鱗。',48,'御定全唐詩/json/516.json','["邊草旱不春，劍光增野塵。戰場收驥尾，清瀚怯龍鱗。", "帆色起歸越，松聲厭避秦。幾時逢範蠡，處處是通津。"]'),
('yuding-4','寄婺州溫郎中','厲玄','唐','御定全唐诗','yuding','','[]','積雪沒蘭溪，鄰州望不迷。波中分雁宿，樹杪接猿啼。',48,'御定全唐詩/json/516.json','["積雪沒蘭溪，鄰州望不迷。波中分雁宿，樹杪接猿啼。", "婺女家空在，星郎手未攜。故山新寺額，掩泣荷重題。"]'),
('yuding-5','送顧非熊及第歸茅山','厲玄','唐','御定全唐诗','yuding','','[]','故山登第去，不似舊歸難。帆卷江初夜，梅生洞少寒。',48,'御定全唐詩/json/516.json','["故山登第去，不似舊歸難。帆卷江初夜，梅生洞少寒。", "采薇留客飲，折竹掃仙壇。名在儀曹籍，何人肯掛冠。"]'),
('yuding-6','送黃曄明府岳州湘陰赴任','厲玄','唐','御定全唐诗','yuding','','[]','恩沾譴雪幾人同，歸宰湘陰六月中。商嶺馬嘶殘暑雨，',40,'御定全唐詩/json/516.json','["恩沾譴雪幾人同，歸宰湘陰六月中。商嶺馬嘶殘暑雨，", "西省尚嗟君宦遠，水雞啼處莫聽鴻。"]'),
('yuding-7','緱山月夜聞王子晉吹笙','厲玄','唐','御定全唐诗','yuding','','[]','緱山明月夜，岑寂隔塵氛。紫府參差曲，清宵次第聞。',72,'御定全唐詩/json/516.json','["緱山明月夜，岑寂隔塵氛。紫府參差曲，清宵次第聞。", "韻流多入洞，聲度半和雲。拂竹鸞驚侶，經松鶴對群。", "蟾光聽處合，仙路望中分。坐惜千岩曙，遺香過汝墳。"]'),
('yuding-8','和白敏中聖德和平致茲休運歲終功就合詠盛明呈上','魏扶','唐','御定全唐诗','yuding','','[]','蕭關新復舊山川，古戍秦原景象鮮。戎虜乞降歸惠化，',40,'御定全唐詩/json/516.json','["蕭關新復舊山川，古戍秦原景象鮮。戎虜乞降歸惠化，", "左衽盡知歌帝澤，從茲不更備三邊。"]'),
('yuding-9','貢院題','魏扶','唐','御定全唐诗','yuding','','[]','梧桐葉落滿庭陰，鎖閉朱門試院深。',32,'御定全唐詩/json/516.json','["梧桐葉落滿庭陰，鎖閉朱門試院深。", "曾是昔年辛苦地，不將今日負初心。"]'),
('yuding-10','賦愁','魏扶','唐','御定全唐诗','yuding','','[]','愁。迥野，深秋。生枕上，起眉頭。閨閣危坐，風塵遠遊。',68,'御定全唐詩/json/516.json','["愁。迥野，深秋。生枕上，起眉頭。閨閣危坐，風塵遠遊。", "巴猿啼不住，谷水咽還流。送客泊舟入浦，思鄉望月登樓。", "煙波早晚長羈旅，弦管終年樂五侯。"]'),
('yuding-11','登郡中銷暑樓寄東川汝士','楊漢公','唐','御定全唐诗','yuding','','[]','岧嶢下瞰霅溪流，極目煙波望梓州。',32,'御定全唐詩/json/516.json','["岧嶢下瞰霅溪流，極目煙波望梓州。", "雖有清風當夏景，只能銷暑不銷憂。"]'),
('yuding-12','明月樓','楊漢公','唐','御定全唐诗','yuding','','[]','吳興城闕水雲中，畫舫青簾處處通。',32,'御定全唐詩/json/516.json','["吳興城闕水雲中，畫舫青簾處處通。", "溪上玉樓樓上月，清光合作水晶宮。"]'),
('yuding-13','送閬州妓人歸老','何扶','唐','御定全唐诗','yuding','','[]','竹翠嬋娟草徑幽，佳人歸老傍汀洲。玉蟾露冷梁塵暗，',40,'御定全唐詩/json/516.json','["竹翠嬋娟草徑幽，佳人歸老傍汀洲。玉蟾露冷梁塵暗，", "芭蕉半卷西池雨，日暮門前雙白鷗。"]'),
('yuding-14','寄舊同年','何扶','唐','御定全唐诗','yuding','','[]','金榜題名墨尚新，今年依舊去年春。',32,'御定全唐詩/json/516.json','["金榜題名墨尚新，今年依舊去年春。", "花間每被紅妝問，何事重來隻一人。"]'),
('yuding-15','望九華山','柴夔','唐','御定全唐诗','yuding','','[]','九華如劍插雲霓，青靄連空望欲迷。北截吳門疑地盡，',40,'御定全唐詩/json/516.json','["九華如劍插雲霓，青靄連空望欲迷。北截吳門疑地盡，", "惆悵舊遊無複到，會須登此出塵泥。"]'),
('yuding-16','寄妾趙氏','房千里','唐','御定全唐诗','yuding','','[]','鸞鳳分飛海樹秋，忍聽鐘鼓越王樓。只應霜月明君意，',40,'御定全唐詩/json/516.json','["鸞鳳分飛海樹秋，忍聽鐘鼓越王樓。只應霜月明君意，", "相如若返臨邛市，畫舸朱軒萬里遊。"]'),
('yuding-17','早行','劉郇伯','唐','御定全唐诗','yuding','','[]','鐘靜人猶寢，天高月自涼。一星深戍火，殘月半橋霜。',48,'御定全唐詩/json/516.json','["鐘靜人猶寢，天高月自涼。一星深戍火，殘月半橋霜。", "客老愁塵下，蟬寒怨路傍。青山依舊色，宛是馬卿鄉。"]'),
('yuding-18','句','劉郇伯','唐','御定全唐诗','yuding','','[]','人生分外愁。（郇伯與范酂為友，酂得句雲：',51,'御定全唐詩/json/516.json','["人生分外愁。（郇伯與范酂為友，酂得句雲：", "「歲盡天涯雨。」久而莫屬，郇伯云云，范甚賞之。", "見《北夢瑣言》）"]'),
('yuding-19','贈成都僧','李章武','唐','御定全唐诗','yuding','','[]','南宗尚許通方便，何處心中更有經。',32,'御定全唐詩/json/516.json','["南宗尚許通方便，何處心中更有經。", "好去苾芻雲水畔，何山松柏不青青。"]'),
('yuding-20','享太廟樂章','蕭仿','唐','御定全唐诗','yuding','','[]','聖祚無疆，慶傳樂章。金枝繁茂，玉葉延長。',40,'御定全唐詩/json/516.json','["聖祚無疆，慶傳樂章。金枝繁茂，玉葉延長。", "海瀆常晏，波濤不揚。汪汪美化，垂范今王。"]'),
('yuding-21','享太廟樂章','蕭仿','唐','御定全唐诗','yuding','','[]','於鑠丕嗣，惟帝之光。羽鑰象德，金石薦祥。',40,'御定全唐詩/json/516.json','["於鑠丕嗣，惟帝之光。羽鑰象德，金石薦祥。", "聖系無極，景命永昌。神降上哲，維天配長。"]'),
('yuding-22','答楊尚書','柳棠','唐','御定全唐诗','yuding','','[]','未向燕台逢厚禮，幸因社會接餘歡。',32,'御定全唐詩/json/516.json','["未向燕台逢厚禮，幸因社會接餘歡。", "一魚吃了終無愧，鶤化為鵬也不難。"]'),
('yuding-23','席上戲東川楊尚書','柳棠','唐','御定全唐诗','yuding','','[]','莫言名位未相儔，風月何曾阻獻酬。',32,'御定全唐詩/json/516.json','["莫言名位未相儔，風月何曾阻獻酬。", "前輩不須輕後輩，靖安今日在衡州。"]'),
('yuding-24','緱山月夜聞王子晉吹笙','鐘輅','唐','御定全唐诗','yuding','','[]','月滿緱山夜，風傳子晉笙。初聞盈穀遠，漸聽入雲清。',72,'御定全唐詩/json/516.json','["月滿緱山夜，風傳子晉笙。初聞盈穀遠，漸聽入雲清。", "杳異人間曲，遙分鶴上情。孤鸞驚欲舞，萬籟寂無聲。", "此夕留煙駕，何時返玉京。唯愁音響絕，曉色出都城。"]'),
('yuding-0','南溪書院','楊發','唐','御定全唐诗','yuding','','[]','茅屋住來久，山深不置門。草生垂井口，花發接籬根。',48,'御定全唐詩/json/517.json','["茅屋住來久，山深不置門。草生垂井口，花發接籬根。", "入院將雛鳥，攀蘿抱子猿。曾逢異人說，風景似桃源。"]'),
('yuding-1','春園醉醒閑臥小齋','楊發','唐','御定全唐诗','yuding','','[]','酣醉送餘春，醒來恨更頻。花殘蜂蠹物，葉暗鳥欺人。',48,'御定全唐詩/json/517.json','["酣醉送餘春，醒來恨更頻。花殘蜂蠹物，葉暗鳥欺人。", "簾閉高眠貴，齋空浩氣新。從今北窗蝶，長是夢中身。"]'),
('yuding-2','小園秋興','楊發','唐','御定全唐诗','yuding','','[]','誰言帝城裏，獨作野人居。石磴晴看疊，山苗晚自鋤。',48,'御定全唐詩/json/517.json','["誰言帝城裏，獨作野人居。石磴晴看疊，山苗晚自鋤。", "相慚五秉粟，尚癖一車書。昔日揚雄宅，還無卿相輿。"]'),
('yuding-3','與諸公池上待月','楊發','唐','御定全唐诗','yuding','','[]','樹密雲縈岸，池遙水際空。芰開方吐鏡，蘋動欲含風。',48,'御定全唐詩/json/517.json','["樹密雲縈岸，池遙水際空。芰開方吐鏡，蘋動欲含風。", "漸映沙汀白，微分渚葉紅。金波宜共賞，仙棹一宵同。"]'),
('yuding-4','簷雀','楊發','唐','御定全唐诗','yuding','','[]','弱羽怯孤飛，投簷幸所依。銜環唯報德，賀廈本知歸。',48,'御定全唐詩/json/517.json','["弱羽怯孤飛，投簷幸所依。銜環唯報德，賀廈本知歸。", "紅觜休爭顧，丹心自識機。從來攀鳳足，生死戀光輝。"]'),
('yuding-5','殘花','楊發','唐','御定全唐诗','yuding','','[]','已笑良時晚，仍悲別酒催。暖芳隨日薄，殘片逐風回。',48,'御定全唐詩/json/517.json','["已笑良時晚，仍悲別酒催。暖芳隨日薄，殘片逐風回。", "黛斂愁歌扇，妝殘泣鏡臺。繁陰莫矜衒，終是共塵埃。"]'),
('yuding-6','山泉','楊發','唐','御定全唐诗','yuding','','[]','半空飛下水，勢去響如雷。靜徹啼猿寺，高陵坐客台。',72,'御定全唐詩/json/517.json','["半空飛下水，勢去響如雷。靜徹啼猿寺，高陵坐客台。", "耳同經劍閣，身若到天臺。濺樹吹成凍，鄰祠觸作灰。", "深中試榔栗，淺處落莓苔。半夜重城閉，潺湲枕底來。"]'),
('yuding-7','秋晚日少陵原游山泉之什','楊發','唐','御定全唐诗','yuding','','[]','喧濁侵肌性未沈，每來雲外恣幽尋。塵衣更喜秋泉潔，',40,'御定全唐詩/json/517.json','["喧濁侵肌性未沈，每來雲外恣幽尋。塵衣更喜秋泉潔，", "唯憐一夜空山月，似許他年伴獨吟。"]'),
('yuding-8','秋晴獨立南亭','楊發','唐','御定全唐诗','yuding','','[]','晝對南風獨閉關，暗期幽鳥去仍還。如今有待終身貴，',40,'御定全唐詩/json/517.json','["晝對南風獨閉關，暗期幽鳥去仍還。如今有待終身貴，", "開襟自向清風笑，無限秋光為解顏。"]'),
('yuding-9','宿黃花館','楊發','唐','御定全唐诗','yuding','','[]','孤館蕭條槐葉稀，暮蟬聲隔水聲微。年年為客路無盡，',40,'御定全唐詩/json/517.json','["孤館蕭條槐葉稀，暮蟬聲隔水聲微。年年為客路無盡，", "夜深不臥簾猶卷，數點殘螢入戶飛。"]'),
('yuding-10','南野逢田客','楊發','唐','御定全唐诗','yuding','','[]','桑柘悠悠水蘸堤，晚風晴景不妨犁。高機猶織臥蠶子，',40,'御定全唐詩/json/517.json','["桑柘悠悠水蘸堤，晚風晴景不妨犁。高機猶織臥蠶子，", "生時自樂死由命，萬事在天管不迷。"]'),
('yuding-11','東齋夜宴酬紹之起居見贈','楊發','唐','御定全唐诗','yuding','','[]','龍門八上不知津，唯有君心困益親。白社追遊名自遠，',40,'御定全唐詩/json/517.json','["龍門八上不知津，唯有君心困益親。白社追遊名自遠，", "漸老舊交情更重，莫將美酒負良辰。"]'),
('yuding-12','玩殘花','楊發','唐','御定全唐诗','yuding','','[]','十日濃芳一歲程，東風初急眼偏明。',32,'御定全唐詩/json/517.json','["十日濃芳一歲程，東風初急眼偏明。", "低枝似泥幽人醉，莫道無情似有情。"]'),
('yuding-13','詠蛙','楊收','唐','御定全唐诗','yuding','','[]','兔邊分玉樹，龍底耀銅儀。會當同鼓吹，不復問官私。',24,'御定全唐詩/json/517.json','["兔邊分玉樹，龍底耀銅儀。會當同鼓吹，不復問官私。"]'),
('yuding-14','筆','楊收','唐','御定全唐诗','yuding','','[]','雖匪囊中物，何堅不可鑽。一朝操政柄，定使冠三端。',24,'御定全唐詩/json/517.json','["雖匪囊中物，何堅不可鑽。一朝操政柄，定使冠三端。"]'),
('yuding-15','嘲吳人觀者','楊收','唐','御定全唐诗','yuding','','[]','爾幸無羸角，何用觸吾藩。若是升堂者，還應自得門。',24,'御定全唐詩/json/517.json','["爾幸無羸角，何用觸吾藩。若是升堂者，還應自得門。"]'),
('yuding-16','甲子歲書事','楊乘','唐','御定全唐诗','yuding','','[]','豎子未鼎烹，大君尚旰食。風雷隨出師，雲霞有戰色。',192,'御定全唐詩/json/517.json','["豎子未鼎烹，大君尚旰食。風雷隨出師，雲霞有戰色。", "犒功椎萬牛，募勇懸千帛。武士日曳柴，飛將兢執馘。", "喜氣迎捷書，歡聲送羽檄。天兵日雄強，桀犬稍離析。", "賊臂既已斷，賊喉既已扼。樂禍但鯨鯢，同惡為肘腋。", "小大勢難侔，逆順初不敵。違命固天亡，恃險乖長策。", "蠆毒久萌牙，狼顧非日夕。禮貌忽驕狂，疏奏遂指斥。", "動眾豈佳兵，含忍恐無益。鴻恩既已孤，小效不足惜。", "腐儒一鉛刀，投筆時感激。帝閽不敢幹，恓恓坐長畫。"]'),
('yuding-17','南徐春日懷古','楊乘','唐','御定全唐诗','yuding','','[]','六代驕奢地，三春物象繁。靈湖通漲海，天塹隔中原。',168,'御定全唐詩/json/517.json','["六代驕奢地，三春物象繁。靈湖通漲海，天塹隔中原。", "曉渡高帆駛，陰風巨艦翻。旌旗西日落，戈甲夏雲屯。", "豹變資陳武，龍飛擁晉元。風流前事盡，文物舊儀存。", "邪侮嘗移潤，忠貞幾度冤。興亡山兀兀，今古水渾渾。", "露滴蜂偷蕊，鶯啼日到軒。酒腸堆曲糵，詩思繞乾坤。", "愁夢全無蝶，離憂每愧萱。形骸勞大塊，玉石任炎昆。", "出處寧由己，升沈未足言。且應中聖樂，坐起任昏昏。"]'),
('yuding-18','吳中書事','楊乘','唐','御定全唐诗','yuding','','[]','十萬人家天塹東，管弦台榭滿春風。名歸範蠡五湖上，',40,'御定全唐詩/json/517.json','["十萬人家天塹東，管弦台榭滿春風。名歸範蠡五湖上，", "尊前多暇但懷古，盡日愁吟誰與同。"]'),
('yuding-19','建鄴懷古','楊乘','唐','御定全唐诗','yuding','','[]','故城故壘滿江濆，儘是干戈舊苦辛。',32,'御定全唐詩/json/517.json','["故城故壘滿江濆，儘是干戈舊苦辛。", "見此即須知帝力，生來便作太平人。"]'),
('yuding-20','榜句','楊乘','唐','御定全唐诗','yuding','','[]','伶俜乖拙兩何如，晝泥琴聲夜泥書。',32,'御定全唐詩/json/517.json','["伶俜乖拙兩何如，晝泥琴聲夜泥書。", "數拍胡笳彈未熟，故人新命畫胡車。"]'),
('yuding-21','題楊收相公宅','尹璞','唐','御定全唐诗','yuding','','[]','禍福從來路不遙，偶然平地上煙霄。',32,'御定全唐詩/json/517.json','["禍福從來路不遙，偶然平地上煙霄。", "煙霄未穩還平地，門對孤峰占寂寥。"]'),
('yuding-0','明月照高樓','雍陶','唐','御定全唐诗','yuding','','[]','朗月何高高，樓中簾影寒。一婦獨含歎，四坐誰成歡。',96,'御定全唐詩/json/518.json','["朗月何高高，樓中簾影寒。一婦獨含歎，四坐誰成歡。", "時節屢已移，遊旅杳不還。滄溟倘未涸，妾淚終不幹。", "君若無定雲，妾若不動山。雲行出山易，山逐雲去難。", "願為邊塞塵，因風委君顏。君顏良洗多，蕩妾濁水間。"]'),
('yuding-1','酬秘書王丞見寄','雍陶','唐','御定全唐诗','yuding','','[]','朝下有閑思，南溝邊水行。因來見寥落，轉自歎平生。',48,'御定全唐詩/json/518.json','["朝下有閑思，南溝邊水行。因來見寥落，轉自歎平生。", "白首丈夫氣，赤心知己情。留詩本相慰，卻憶苦吟聲。"]'),
('yuding-2','僧金河戍客','雍陶','唐','御定全唐诗','yuding','','[]','慣獵金河路，曾逢雪不迷。射雕青塚北，走馬黑山西。',48,'御定全唐詩/json/518.json','["慣獵金河路，曾逢雪不迷。射雕青塚北，走馬黑山西。", "戍遠旌幡少，年深帳幕低。酬恩須盡敵，休說夢中閨。"]'),
('yuding-3','孤桐','雍陶','唐','御定全唐诗','yuding','','[]','疏桐餘一干，風雨日蕭條。歲晚琴材老，天寒桂葉凋。',48,'御定全唐詩/json/518.json','["疏桐餘一干，風雨日蕭條。歲晚琴材老，天寒桂葉凋。", "已悲根半死，複恐尾全焦。幸在龍門下，知音肯寂寥。"]'),
('yuding-4','秋露','雍陶','唐','御定全唐诗','yuding','','[]','白露曖秋色，月明清漏中。痕沾珠箔重，點落玉盤空。',48,'御定全唐詩/json/518.json','["白露曖秋色，月明清漏中。痕沾珠箔重，點落玉盤空。", "竹動時驚鳥，莎寒暗滴蟲。滿園生永夜，漸欲與霜同。"]'),
('yuding-5','送徐使君赴嶽州','雍陶','唐','御定全唐诗','yuding','','[]','渺渺楚江上，風旗搖去舟。馬歸雲夢晚，猿叫洞庭秋。',48,'御定全唐詩/json/518.json','["渺渺楚江上，風旗搖去舟。馬歸雲夢晚，猿叫洞庭秋。", "別思滿南渡，鄉心生北樓。巴陵山水郡，應稱謝公遊。"]'),
('yuding-6','送裴璋還蜀因亦懷歸','雍陶','唐','御定全唐诗','yuding','','[]','客在劍門外，新年音信稀。自為千里別，已送幾人歸。',48,'御定全唐詩/json/518.json','["客在劍門外，新年音信稀。自為千里別，已送幾人歸。", "陌上月初落，馬前花正飛。離言殊未盡，春雨滿行衣。"]'),
('yuding-7','送前鄠縣李少府','雍陶','唐','御定全唐诗','yuding','','[]','近出圭峰下，還期又不賒。身閑多宿寺，官滿未移家。',48,'御定全唐詩/json/518.json','["近出圭峰下，還期又不賒。身閑多宿寺，官滿未移家。", "罷釣臨秋水，開尊對月華。自當蓬閣選，豈得臥煙霞。"]'),
('yuding-8','送宜春裴明府之任','雍陶','唐','御定全唐诗','yuding','','[]','南行春已滿，路半水茫然。楚望花當渡，湘陰橘滿川。',48,'御定全唐詩/json/518.json','["南行春已滿，路半水茫然。楚望花當渡，湘陰橘滿川。", "山橫湖色上，帆出鳥行前。此任無辭遠，親人貴用還。"]'),
('yuding-9','贈宗靜上人','雍陶','唐','御定全唐诗','yuding','','[]','世上方傳教，山中未得歸。閑花飄講席，馴鴿汙禪衣。',48,'御定全唐詩/json/518.json','["世上方傳教，山中未得歸。閑花飄講席，馴鴿汙禪衣。", "積雨誰過寺，殘鐘自掩扉。寒來垂頂帽，白髮剃應稀。"]'),
('yuding-10','同賈島宿無可上人院','雍陶','唐','御定全唐诗','yuding','','[]','何處銷愁宿，攜囊就遠僧。中宵吟有雪，空屋語無燈。',48,'御定全唐詩/json/518.json','["何處銷愁宿，攜囊就遠僧。中宵吟有雪，空屋語無燈。", "靜境唯聞鐸，寒床但枕肱。還因愛閑客，始得見南能。"]'),
('yuding-11','和劉補闕秋園寓興六首','雍陶','唐','御定全唐诗','yuding','','[]','水木夕陰冷，池塘秋意多。庭風吹故葉，階露淨寒莎。',288,'御定全唐詩/json/518.json','["水木夕陰冷，池塘秋意多。庭風吹故葉，階露淨寒莎。", "愁燕窺燈語，情人見月過。砧聲聽已別，蟲響複相和。", "閉門無事後，此地即山中。但覺鳥聲異，不知人境同。", "晚花開為雨，殘果落因風。獨坐還吟酌，詩成酒已空。", "自得家林趣，常時在外稀。對僧餐野食，迎客著山衣。", "雀鬥翻簷散，蟬驚出樹飛。功成他日後，何必五湖歸。", "秋色庭蕪上，清朝見露華。疏篁抽晚筍，幽藥吐寒芽。", "引水新渠淨，登臺小徑斜。人來多愛此，蕭爽似仙家。", "禁掖朝回後，林園勝賞時。野人來辨藥，庭鶴往看棋。", "晚日明丹棗，朝霜潤紫梨。還因重風景，猶自有秋詩。", "聖代少封事，閒居方屏喧。漏寒雲外闕，木落月中園。", "山鳥宿簷樹，水螢流洞門。無人見清景，林下自開尊。"]'),
('yuding-12','岳陽晚景','雍陶','唐','御定全唐诗','yuding','','[]','漢陽無遠寺，見說過汾城。雲雨經春客，江山幾日程。',48,'御定全唐詩/json/518.json','["漢陽無遠寺，見說過汾城。雲雨經春客，江山幾日程。", "終隨鷗鳥去，只在海潮生。前路逢漁父，多愁問姓名。"]'),
('yuding-13','塞上宿野寺','雍陶','唐','御定全唐诗','yuding','','[]','塞上蕃僧老，天寒疾上關。遠煙平似水，高樹暗如山。',48,'御定全唐詩/json/518.json','["塞上蕃僧老，天寒疾上關。遠煙平似水，高樹暗如山。", "去馬朝常急，行人夜始閑。更深聽刁鬥，時到磬聲間。"]'),
('yuding-14','寒食夜池上對月懷友','雍陶','唐','御定全唐诗','yuding','','[]','人間多別離，處處是相思。海內無煙夜，天涯有月時。',48,'御定全唐詩/json/518.json','["人間多別離，處處是相思。海內無煙夜，天涯有月時。", "跳魚翻荇葉，驚鵲出花枝。親友皆千里，三更獨繞池。"]'),
('yuding-15','自述','雍陶','唐','御定全唐诗','yuding','','[]','萬事誰能問，一名猶未知。貧當多累日，閑過少年時。',48,'御定全唐詩/json/518.json','["萬事誰能問，一名猶未知。貧當多累日，閑過少年時。", "燈下和愁睡，花前帶酒悲。無謀常委命，轉覺命堪疑。"]'),
('yuding-16','送契玄上人南游','雍陶','唐','御定全唐诗','yuding','','[]','紅葉落湘川，楓明映水天。尋鐘過楚寺，擁錫上瀧船。',48,'御定全唐詩/json/518.json','["紅葉落湘川，楓明映水天。尋鐘過楚寺，擁錫上瀧船。", "病客思留藥，迷人待說禪。南中多古跡，應訪虎溪泉。"]'),
('yuding-17','少年行','雍陶','唐','御定全唐诗','yuding','','[]','不倚軍功有俠名，可憐球獵少年情。戴鈴健鶻隨聲下，',40,'御定全唐詩/json/518.json','["不倚軍功有俠名，可憐球獵少年情。戴鈴健鶻隨聲下，", "豈知儒者心偏苦，吟向秋風白髮生。"]'),
('yuding-18','詠雙白鷺','雍陶','唐','御定全唐诗','yuding','','[]','雙鷺應憐水滿池，風飄不動頂絲垂。立當青草人先見，',40,'御定全唐詩/json/518.json','["雙鷺應憐水滿池，風飄不動頂絲垂。立當青草人先見，", "林塘得爾須增價，況與詩家物色宜。"]'),
('yuding-19','晴詩','雍陶','唐','御定全唐诗','yuding','','[]','晚虹斜日塞天昏，一半山川帶雨痕。新水亂侵青草路，',40,'御定全唐詩/json/518.json','["晚虹斜日塞天昏，一半山川帶雨痕。新水亂侵青草路，", "行子喜聞無戰伐，閑看遊騎獵秋原。"]'),
('yuding-20','送徐山人歸睦州舊隱','雍陶','唐','御定全唐诗','yuding','','[]','君在桐廬何處住，草堂應與戴家鄰。初歸山犬翻驚主，',40,'御定全唐詩/json/518.json','["君在桐廬何處住，草堂應與戴家鄰。初歸山犬翻驚主，", "秋風釣艇遙相憶，七裏灘西片月新。"]'),
('yuding-21','到蜀後記途中經歷','雍陶','唐','御定全唐诗','yuding','','[]','劍峰重疊雪雲漫，憶昨來時處處難。大散嶺頭春足雨，',40,'御定全唐詩/json/518.json','["劍峰重疊雪雲漫，憶昨來時處處難。大散嶺頭春足雨，", "自到成都燒酒熟，不思身更入長安。"]'),
('yuding-22','憶山寄僧','雍陶','唐','御定全唐诗','yuding','','[]','塵路誰知蹋雪蹤，到來空認出雲峰。天晴遠見月中樹，',40,'御定全唐詩/json/518.json','["塵路誰知蹋雪蹤，到來空認出雲峰。天晴遠見月中樹，", "新愁舊恨多難說，半在眉間半在胸。"]'),
('yuding-23','贈玉芝觀王尊師','雍陶','唐','御定全唐诗','yuding','','[]','處處煙霞尋總遍，卻來城市喜逢師。時流見說無人在，',40,'御定全唐詩/json/518.json','["處處煙霞尋總遍，卻來城市喜逢師。時流見說無人在，", "長憂一日歸天去，未授靈方遣問誰。"]'),
('yuding-24','哭饒州吳諫議使君','雍陶','唐','御定全唐诗','yuding','','[]','忽聞身謝滿朝驚，俄感鄱陽罷市情。遺愛永存今似古，',40,'御定全唐詩/json/518.json','["忽聞身謝滿朝驚，俄感鄱陽罷市情。遺愛永存今似古，", "授館曾為門下客，幾回垂淚過宣平。"]'),
('yuding-25','經杜甫舊宅','雍陶','唐','御定全唐诗','yuding','','[]','浣花溪裏花多處，為憶先生在蜀時。萬古只應留舊宅，',40,'御定全唐詩/json/518.json','["浣花溪裏花多處，為憶先生在蜀時。萬古只應留舊宅，", "山月不知人事變，夜來江上與誰期。"]'),
('yuding-26','河陰新城','雍陶','唐','御定全唐诗','yuding','','[]','高城新築壓長川，虎踞龍盤氣色全。五裏似雲根不動，',40,'御定全唐詩/json/518.json','["高城新築壓長川，虎踞龍盤氣色全。五裏似雲根不動，", "自有此來當汴口，武牢何用鎖風煙。"]'),
('yuding-27','秋居病中','雍陶','唐','御定全唐诗','yuding','','[]','幽居悄悄何人到，落日清涼滿樹梢。新句有時愁裏得，',40,'御定全唐詩/json/518.json','["幽居悄悄何人到，落日清涼滿樹梢。新句有時愁裏得，", "獨臥南窗秋色晚，一庭紅葉掩衡茅。"]'),
('yuding-28','罷還邊將','雍陶','唐','御定全唐诗','yuding','','[]','白須虜將話邊事，自失公權怨語多。漢主豈勞思李牧，',40,'御定全唐詩/json/518.json','["白須虜將話邊事，自失公權怨語多。漢主豈勞思李牧，", "百戰無功身老去，羨他年少渡黃河。"]'),
('yuding-29','永樂殷堯藩明府縣池嘉蓮詠','雍陶','唐','御定全唐诗','yuding','','[]','青蘋白石匝蓮塘，水裏蓮開帶瑞光。露濕紅芳雙朵重，',40,'御定全唐詩/json/518.json','["青蘋白石匝蓮塘，水裏蓮開帶瑞光。露濕紅芳雙朵重，", "不獨豐祥先有應，更宜花縣對潘郎。"]'),
('yuding-30','酬李紺歲除送酒','雍陶','唐','御定全唐诗','yuding','','[]','歲盡貧生事事須，就中深恨酒錢無。故人充壽能分送，',40,'御定全唐詩/json/518.json','["歲盡貧生事事須，就中深恨酒錢無。故人充壽能分送，", "已供時節深珍重，況許今朝更挈壺。"]'),
('yuding-31','蜀路倦行因有所感','雍陶','唐','御定全唐诗','yuding','','[]','亂峰碎石金牛路，過客應騎鐵馬行。白日欲斜催後乘，',40,'御定全唐詩/json/518.json','["亂峰碎石金牛路，過客應騎鐵馬行。白日欲斜催後乘，", "蹇步不唯傷旅思，此中兼見宦途情。"]'),
('yuding-32','寄永樂殷堯藩明府','雍陶','唐','御定全唐诗','yuding','','[]','古縣蕭條秋景晚，昔年陶令亦如君。頭巾漉酒臨黃菊，',40,'御定全唐詩/json/518.json','["古縣蕭條秋景晚，昔年陶令亦如君。頭巾漉酒臨黃菊，", "相思不恨書來少，佳句多從闕下聞。"]'),
('yuding-33','蜀中戰後感事','雍陶','唐','御定全唐诗','yuding','','[]','蜀道英靈地，山重水又回。文章四子盛，道路五丁開。',120,'御定全唐詩/json/518.json','["蜀道英靈地，山重水又回。文章四子盛，道路五丁開。", "詞客題橋去，忠臣叱馭來。臥龍同駭浪，躍馬比浮埃。", "已謂無妖土，那知有禍胎。蕃兵依濮柳，蠻旆指江梅。", "戰後悲逢血，燒餘恨見灰。空留犀厭怪，無複酒除災。", "歲積萇弘怨，春深杜宇哀。家貧移未得，愁上望鄉台。"]'),
('yuding-34','答蜀中經蠻後友人馬艾見寄','雍陶','唐','御定全唐诗','yuding','','[]','茜馬渡瀘水，北來如鳥輕。幾年朝鳳闕，一日破龜城。',72,'御定全唐詩/json/518.json','["茜馬渡瀘水，北來如鳥輕。幾年朝鳳闕，一日破龜城。", "此地有征戰，誰家無死生。人悲還舊裏，鳥喜下空營。", "弟侄意初定，交朋心尚驚。自從經難後，吟苦似猿聲。"]'),
('yuding-35','盧嶽閒居十韻','雍陶','唐','御定全唐诗','yuding','','[]','擾擾走人寰，爭如占得閒。防愁心付酒，求靜力登山。',120,'御定全唐詩/json/518.json','["擾擾走人寰，爭如占得閒。防愁心付酒，求靜力登山。", "見藥芳時采，逢花好處攀。望雲開病眼，臨澗洗愁顏。", "春色流岩下，秋聲碎竹間。錦文苔點點，錢樣菊斑斑。", "路遠朝無客，門深夜不關。鶴飛高縹緲，鶯語巧綿蠻。", "養拙甘沉默，忘懷絕險艱。更憐雲外路，空去又空還。"]'),
('yuding-36','送於中丞使北蕃','雍陶','唐','御定全唐诗','yuding','','[]','朔將引雙旌，山遙磧雪平。經年通國信，計日得蕃情。',72,'御定全唐詩/json/518.json','["朔將引雙旌，山遙磧雪平。經年通國信，計日得蕃情。", "野次依泉宿，沙中望火行。遠雕秋有力，寒馬夜無聲。", "看獵臨胡帳，思鄉見漢城。來春擁邊騎，新草滿歸程。"]'),
('yuding-37','和河南白尹西池北新葺水齋招賞十二韻','雍陶','唐','御定全唐诗','yuding','','[]','二室峰前水，三川府右亭。亂流深竹徑，分繞小花汀。',144,'御定全唐詩/json/518.json','["二室峰前水，三川府右亭。亂流深竹徑，分繞小花汀。", "池角通泉脈，堂心豁地形。坐中寒瑟瑟，床下細泠泠。", "雨夜思巫峽，秋朝想洞庭。千年孤鏡碧，一片遠天青。", "魚戲搖紅尾，鷗閑退白翎。荷傾瀉珠露，沙亂動金星。", "藤架如紗帳，苔牆似錦屏。龍門人少到，仙棹自多停。", "游憶高僧伴，吟招野客聽。餘波不能惜，便欲養浮萍。"]'),
('yuding-38','感興','雍陶','唐','御定全唐诗','yuding','','[]','貧女貌非醜，要須緣嫁遲。還似求名客，無媒不及時。',24,'御定全唐詩/json/518.json','["貧女貌非醜，要須緣嫁遲。還似求名客，無媒不及時。"]'),
('yuding-39','長安客感','雍陶','唐','御定全唐诗','yuding','','[]','日過千萬家，一家非所依。不及行塵影，猶隨馬蹄歸。',24,'御定全唐詩/json/518.json','["日過千萬家，一家非所依。不及行塵影，猶隨馬蹄歸。"]'),
('yuding-40','春懷舊游','雍陶','唐','御定全唐诗','yuding','','[]','吟想舊經過，花時奈遠何。別來長似見，春夢入關多。',24,'御定全唐詩/json/518.json','["吟想舊經過，花時奈遠何。別來長似見，春夢入關多。"]'),
('yuding-41','離京城宿商山作','雍陶','唐','御定全唐诗','yuding','','[]','山月吟聲苦，春風引思長。無由及塵土，猶帶杏花香。',24,'御定全唐詩/json/518.json','["山月吟聲苦，春風引思長。無由及塵土，猶帶杏花香。"]'),
('yuding-42','秋館雨夜','雍陶','唐','御定全唐诗','yuding','','[]','夜雨空館靜，幽人起裴回。長安醉眠客，豈知新雁來。',24,'御定全唐詩/json/518.json','["夜雨空館靜，幽人起裴回。長安醉眠客，豈知新雁來。"]'),
('yuding-43','聞子規','雍陶','唐','御定全唐诗','yuding','','[]','百鳥有啼時，子規聲不歇。春寒四鄰靜，獨叫三更月。',24,'御定全唐詩/json/518.json','["百鳥有啼時，子規聲不歇。春寒四鄰靜，獨叫三更月。"]'),
('yuding-44','懷無可上人','雍陶','唐','御定全唐诗','yuding','','[]','山寺秋時後，僧家夏滿時。清涼多古跡，幾處有新詩。',24,'御定全唐詩/json/518.json','["山寺秋時後，僧家夏滿時。清涼多古跡，幾處有新詩。"]'),
('yuding-45','長安客感','雍陶','唐','御定全唐诗','yuding','','[]','客淚如危葉，長懸零落心。況是悲秋日，臨風制不禁。',24,'御定全唐詩/json/518.json','["客淚如危葉，長懸零落心。況是悲秋日，臨風制不禁。"]'),
('yuding-46','送客遙望','雍陶','唐','御定全唐诗','yuding','','[]','別遠心更苦，遙將目送君。光華不可見，孤鶴沒秋雲。',24,'御定全唐詩/json/518.json','["別遠心更苦，遙將目送君。光華不可見，孤鶴沒秋雲。"]'),
('yuding-47','傷靡草','雍陶','唐','御定全唐诗','yuding','','[]','靡草似客心，年年亦先死。無由伴花落，暫得因風起。',24,'御定全唐詩/json/518.json','["靡草似客心，年年亦先死。無由伴花落，暫得因風起。"]'),
('yuding-48','放鶴','雍陶','唐','御定全唐诗','yuding','','[]','從今一去不須低，見說遼東好去棲。',32,'御定全唐詩/json/518.json','["從今一去不須低，見說遼東好去棲。", "努力莫辭仙路遠，白雲飛處免群雞。"]'),
('yuding-49','早秋月夜','雍陶','唐','御定全唐诗','yuding','','[]','身閑伴月夜深行，風觸衣裳四體輕。',32,'御定全唐詩/json/518.json','["身閑伴月夜深行，風觸衣裳四體輕。", "為見近來天氣好，幾篇詩興入秋成。"]'),
('yuding-50','蟬','雍陶','唐','御定全唐诗','yuding','','[]','高樹蟬聲入晚雲，不唯愁我亦愁君。',32,'御定全唐詩/json/518.json','["高樹蟬聲入晚雲，不唯愁我亦愁君。", "何時各得身無事，每到聞時似不聞。"]'),
('yuding-51','公子行','雍陶','唐','御定全唐诗','yuding','','[]','公子風流嫌錦繡，新裁白紵作春衣。',32,'御定全唐詩/json/518.json','["公子風流嫌錦繡，新裁白紵作春衣。", "金鞭留當誰家酒，拂柳穿花信馬歸。"]'),
('yuding-52','題情盡橋','雍陶','唐','御定全唐诗','yuding','','[]','從來只有情難盡，何事名為情盡橋。',32,'御定全唐詩/json/518.json','["從來只有情難盡，何事名為情盡橋。", "自此改名為折柳，任他離恨一條條。"]'),
('yuding-53','峽中行','雍陶','唐','御定全唐诗','yuding','','[]','兩崖開盡水回環，一葉才通石罅間。',32,'御定全唐詩/json/518.json','["兩崖開盡水回環，一葉才通石罅間。", "楚客莫言山勢險，世人心更險於山。"]'),
('yuding-54','韋處士郊居','雍陶','唐','御定全唐诗','yuding','','[]','滿庭詩境飄紅葉，繞砌琴聲滴暗泉。',32,'御定全唐詩/json/518.json','["滿庭詩境飄紅葉，繞砌琴聲滴暗泉。", "門外晚晴秋色老，萬條寒玉一溪煙。"]'),
('yuding-55','秋懷','雍陶','唐','御定全唐诗','yuding','','[]','古槐煙薄晚鴉愁，獨向黃昏立禦溝。',32,'御定全唐詩/json/518.json','["古槐煙薄晚鴉愁，獨向黃昏立禦溝。", "南國望中生遠思，一行新雁去汀洲。"]'),
('yuding-56','再下第將歸荊楚上白舍人','雍陶','唐','御定全唐诗','yuding','','[]','窮通應計一時間，今日甘從刖足還。',32,'御定全唐詩/json/518.json','["窮通應計一時間，今日甘從刖足還。", "長倚玉人心自醉，不辭歸去哭荊山。"]'),
('yuding-57','春行武關作','雍陶','唐','御定全唐诗','yuding','','[]','風香春暖展歸程，全勝遊仙入洞情。',32,'御定全唐詩/json/518.json','["風香春暖展歸程，全勝遊仙入洞情。", "一路緣溪花覆水，不妨閑看不妨行。"]'),
('yuding-58','恨別二首','雍陶','唐','御定全唐诗','yuding','','[]','知君餞酒深深意，圖使行人涕不流。',64,'御定全唐詩/json/518.json','["知君餞酒深深意，圖使行人涕不流。", "如今卻恨酒中別，不得一言千里愁。", "人言日遠還疏索，別後都非未別心。", "唯我憶君千里意，一年不見一重深。"]'),
('yuding-59','送人歸吳','雍陶','唐','御定全唐诗','yuding','','[]','遠愛春波正滿湖，羨君東去是歸途。',32,'御定全唐詩/json/518.json','["遠愛春波正滿湖，羨君東去是歸途。", "吟詩好向月中宿，一叫水天沙鶴孤。"]'),
('yuding-60','喜夢歸','雍陶','唐','御定全唐诗','yuding','','[]','旅館歲闌頻有夢，分明最似此宵希。',32,'御定全唐詩/json/518.json','["旅館歲闌頻有夢，分明最似此宵希。", "覺來莫道還無益，未得歸時且當歸。"]'),
('yuding-61','路中問程知欲達青雲驛','雍陶','唐','御定全唐诗','yuding','','[]','行愁驛路問來人，西去經過願一聞。',32,'御定全唐詩/json/518.json','["行愁驛路問來人，西去經過願一聞。", "落日回鞭相指點，前程從此是青雲。"]'),
('yuding-62','題君山','雍陶','唐','御定全唐诗','yuding','','[]','風波不動影沉沉，翠色全微碧色深。',32,'御定全唐詩/json/518.json','["風波不動影沉沉，翠色全微碧色深。", "應是水仙梳洗處，一螺青黛鏡中心。"]'),
('yuding-63','離家後作','雍陶','唐','御定全唐诗','yuding','','[]','世上無媒似我希，一身惟有影相隨。',32,'御定全唐詩/json/518.json','["世上無媒似我希，一身惟有影相隨。", "出門便作焚舟計，生不成名死不歸。"]'),
('yuding-64','寄題峴亭','雍陶','唐','御定全唐诗','yuding','','[]','峴亭留恨為傷杯，未得醒醒看便回。',32,'御定全唐詩/json/518.json','["峴亭留恨為傷杯，未得醒醒看便回。", "卻想醉遊如夢見，直疑元本不曾來。"]'),
('yuding-65','病鶴','雍陶','唐','御定全唐诗','yuding','','[]','憶得當時病未遭，身為仙馭雪為毛。',32,'御定全唐詩/json/518.json','["憶得當時病未遭，身為仙馭雪為毛。", "今來沙上飛無力，羞見檣烏立處高。"]'),
('yuding-66','狀春','雍陶','唐','御定全唐诗','yuding','','[]','含春笑日花心豔，帶雨牽風柳態妖。',32,'御定全唐詩/json/518.json','["含春笑日花心豔，帶雨牽風柳態妖。", "珍重兩般堪比處，醉時紅臉舞時腰。"]'),
('yuding-67','春詠','雍陶','唐','御定全唐诗','yuding','','[]','風惱花枝不耐頻，等閒飛落易愁人。',32,'御定全唐詩/json/518.json','["風惱花枝不耐頻，等閒飛落易愁人。", "殷勤最是章台柳，一樹千條管帶春。"]'),
('yuding-68','非酒','雍陶','唐','御定全唐诗','yuding','','[]','人人慢說酒消憂，我道翻為引恨由。',32,'御定全唐詩/json/518.json','["人人慢說酒消憂，我道翻為引恨由。", "一夜醒來燈火暗，不應愁事亦成愁。"]'),
('yuding-69','苦寒','雍陶','唐','御定全唐诗','yuding','','[]','今年無異去年寒，何事朝來獨忍難。',32,'御定全唐詩/json/518.json','["今年無異去年寒，何事朝來獨忍難。", "應是漸為貧客久，錦衣著盡布衣單。"]'),
('yuding-70','送客','雍陶','唐','御定全唐诗','yuding','','[]','若論秋思人人苦，最覺愁多客又深。',32,'御定全唐詩/json/518.json','["若論秋思人人苦，最覺愁多客又深。", "何況病來惆悵盡，不知爭作送君心。"]'),
('yuding-71','人問應舉','雍陶','唐','御定全唐诗','yuding','','[]','莫驚西上獨遲回，只為衡門未有媒。',32,'御定全唐詩/json/518.json','["莫驚西上獨遲回，只為衡門未有媒。", "惆悵賦成身不去，一名閒事逐秋回。"]'),
('yuding-72','送客不及','雍陶','唐','御定全唐诗','yuding','','[]','水闊江天兩不分，行人兩處更相聞。',32,'御定全唐詩/json/518.json','["水闊江天兩不分，行人兩處更相聞。", "遙遙已失風帆影，半日虛銷指點雲。"]'),
