('yuding-121','蔚州晏內遇新雪','雍陶','唐','御定全唐诗','yuding','','[]','胡盧河畔逢秋雪，疑是風飄白鶴毛。',32,'御定全唐詩/json/518.json','["胡盧河畔逢秋雪，疑是風飄白鶴毛。", "坐客停杯看未定，將軍已濕褐花袍。"]'),
('yuding-122','句','雍陶','唐','御定全唐诗','yuding','','[]','古木閩州道，驅羸落照間。投村礙野水，問店隔荒山。',24,'御定全唐詩/json/518.json','["古木閩州道，驅羸落照間。投村礙野水，問店隔荒山。"]'),
('yuding-0','立春日','李遠','唐','御定全唐诗','yuding','','[]','暖日傍簾曉，濃春開篋紅。釵斜穿彩燕，羅薄剪春蟲。',48,'御定全唐詩/json/519.json','["暖日傍簾曉，濃春開篋紅。釵斜穿彩燕，羅薄剪春蟲。", "巧著金刀力，寒侵玉指風。娉婷何處戴，山鬢綠成叢。"]'),
('yuding-1','翦彩','李遠','唐','御定全唐诗','yuding','','[]','翦彩贈相親，銀釵綴鳳真。雙雙銜綬鳥，兩兩度橋人。',48,'御定全唐詩/json/519.json','["翦彩贈相親，銀釵綴鳳真。雙雙銜綬鳥，兩兩度橋人。", "葉逐金刀出，花隨玉指新。願君千萬歲，無歲不逢春。"]'),
('yuding-2','題僧院','李遠','唐','御定全唐诗','yuding','','[]','不用問湯休，何人免白頭。百年如過鳥，萬事盡浮漚。',48,'御定全唐詩/json/519.json','["不用問湯休，何人免白頭。百年如過鳥，萬事盡浮漚。", "別緒長牽夢，情由亂種愁。卻嫌風景麗，窗外碧雲秋。"]'),
('yuding-3','觀廉女真葬','李遠','唐','御定全唐诗','yuding','','[]','玉窗拋翠管，輕袖掩銀鸞。錯落雲車斷，丁泠金磬寒。',48,'御定全唐詩/json/519.json','["玉窗拋翠管，輕袖掩銀鸞。錯落雲車斷，丁泠金磬寒。", "鶴尋深院宿，人借舊書看。寂寞焚香處，紅花滿石壇。"]'),
('yuding-4','閒居','李遠','唐','御定全唐诗','yuding','','[]','塵事久相棄，沈浮皆不知。牛羊歸古巷，燕雀繞疏籬。',48,'御定全唐詩/json/519.json','["塵事久相棄，沈浮皆不知。牛羊歸古巷，燕雀繞疏籬。", "買藥經年曬，留僧盡日棋。唯憂釣魚伴，秋水隔波時。"]'),
('yuding-5','及第後送家兄游蜀','李遠','唐','御定全唐诗','yuding','','[]','人誰無遠別，此別意多違。正鵠雖言中，冥鴻不共飛。',48,'御定全唐詩/json/519.json','["人誰無遠別，此別意多違。正鵠雖言中，冥鴻不共飛。", "玉京煙雨斷，巴國夢魂歸。若過嚴家瀨，殷勤看釣磯。"]'),
('yuding-6','送人入蜀','李遠','唐','御定全唐诗','yuding','','[]','蜀客本多愁，君今是勝遊。碧藏雲外樹，紅露驛邊樓。',48,'御定全唐詩/json/519.json','["蜀客本多愁，君今是勝遊。碧藏雲外樹，紅露驛邊樓。", "杜魄呼名語，巴江作字流。不知煙雨夜，何處夢刀州。"]'),
('yuding-7','游故王駙馬池亭','李遠','唐','御定全唐诗','yuding','','[]','花樹杳玲瓏，漁舟處處通。醉銷羅綺豔，香暖芰荷風。',48,'御定全唐詩/json/519.json','["花樹杳玲瓏，漁舟處處通。醉銷羅綺豔，香暖芰荷風。", "野鳥翻萍綠，斜橋印水紅。子猷簫管絕，誰愛碧鮮濃。"]'),
('yuding-8','悲銅雀台','李遠','唐','御定全唐诗','yuding','','[]','西陵樹已盡，銅雀思偏多。雪密疑樓閣，花開想綺羅。',48,'御定全唐詩/json/519.json','["西陵樹已盡，銅雀思偏多。雪密疑樓閣，花開想綺羅。", "影銷堂上舞，聲斷帳前歌。唯有漳河水，年年舊綠波。"]'),
('yuding-9','陪新及第赴同年會','李遠','唐','御定全唐诗','yuding','','[]','曾攀芳桂英，處處共君行。今日杏園宴，當時天樂聲。',48,'御定全唐詩/json/519.json','["曾攀芳桂英，處處共君行。今日杏園宴，當時天樂聲。", "柳濃堪系馬，花上未藏鶯。滿座皆仙侶，同年別有情。"]'),
('yuding-10','詠雁','李遠','唐','御定全唐诗','yuding','','[]','早晚辭沙漠，南來處處飛。關山多雨雪，風水損毛衣。',48,'御定全唐詩/json/519.json','["早晚辭沙漠，南來處處飛。關山多雨雪，風水損毛衣。", "碧海魂應斷，紅樓信自稀。不知矰繳外，留得幾行歸。"]'),
('yuding-11','與碧溪上人別','李遠','唐','御定全唐诗','yuding','','[]','欲入鳳城遊，西溪別惠休。色隨花旋落，年共水爭流。',48,'御定全唐詩/json/519.json','["欲入鳳城遊，西溪別惠休。色隨花旋落，年共水爭流。", "客思偏來夜，蟬聲覺送秋。明朝逢舊侶，唯擬上歌樓。"]'),
('yuding-12','贈殷山人','李遠','唐','御定全唐诗','yuding','','[]','有客抱琴宿，值予多怨懷。啼烏弦易斷，嘯鶴調難諧。',48,'御定全唐詩/json/519.json','["有客抱琴宿，值予多怨懷。啼烏弦易斷，嘯鶴調難諧。", "曲罷月移幌，韻清風滿齋。誰能將此妙，一為奏金階。"]'),
('yuding-13','詠壁魚','李遠','唐','御定全唐诗','yuding','','[]','鱗細粉光鮮，開書亂眼前。透窗疑漏網，落硯似流泉。',48,'御定全唐詩/json/519.json','["鱗細粉光鮮，開書亂眼前。透窗疑漏網，落硯似流泉。", "潛穴河圖內，吞鉤乙字邊。莫言鬐鬣小，食盡白蘋篇。"]'),
('yuding-14','聽話叢台','李遠','唐','御定全唐诗','yuding','','[]','有客新從趙地回，自言曾上古叢台。雲遮襄國天邊去，',40,'御定全唐詩/json/519.json','["有客新從趙地回，自言曾上古叢台。雲遮襄國天邊去，", "金輿玉輦無行跡，風雨惟知長綠苔。"]'),
('yuding-15','失鶴','李遠','唐','御定全唐诗','yuding','','[]','秋風吹卻九皋禽，一片閑雲萬里心。碧落有情應悵望，',40,'御定全唐詩/json/519.json','["秋風吹卻九皋禽，一片閑雲萬里心。碧落有情應悵望，", "華表柱頭留語後，更無消息到如今。"]'),
('yuding-16','贈寫禦容李長史','李遠','唐','御定全唐诗','yuding','','[]','玉座塵消硯水清，龍髯不動彩毫輕。初分隆准山河秀，',40,'御定全唐詩/json/519.json','["玉座塵消硯水清，龍髯不動彩毫輕。初分隆准山河秀，", "三朝供奉無人敵，始覺僧繇浪得名。"]'),
('yuding-17','贈潼關不下山僧','李遠','唐','御定全唐诗','yuding','','[]','與君同在苦空間，君得空門我愛閑。禁足已教修雁塔，',40,'御定全唐詩/json/519.json','["與君同在苦空間，君得空門我愛閑。禁足已教修雁塔，", "香茗一甌從此別，轉蓬流水幾時還。"]'),
('yuding-18','過舊遊見雙鶴愴然有懷','李遠','唐','御定全唐诗','yuding','','[]','謝公何歲掩松楸，雙鶴依然傍玉樓。朱頂巑岏荒草上，',40,'御定全唐詩/json/519.json','["謝公何歲掩松楸，雙鶴依然傍玉樓。朱頂巑岏荒草上，", "他日若來華表上，更添多少令威愁。"]'),
('yuding-19','贈友人','李遠','唐','御定全唐诗','yuding','','[]','鳳城煙靄思偏多，曾向劉郎住處過。銀燭焰前貪勸酒，',40,'御定全唐詩/json/519.json','["鳳城煙靄思偏多，曾向劉郎住處過。銀燭焰前貪勸酒，", "今日重來門巷改，出牆桐樹綠婆娑。"]'),
('yuding-20','贈南嶽僧','李遠','唐','御定全唐诗','yuding','','[]','曾住衡陽岳寺邊，門開江水與雲連。數州城郭藏寒樹，',40,'御定全唐詩/json/519.json','["曾住衡陽岳寺邊，門開江水與雲連。數州城郭藏寒樹，", "今朝惆悵紅塵裏，惟憶閑陪盡日眠。"]'),
('yuding-21','贈弘文杜校書','李遠','唐','御定全唐诗','yuding','','[]','高倚霞梯萬丈餘，共看移步入宸居。曉隨鵷鷺排金鎖，',40,'御定全唐詩/json/519.json','["高倚霞梯萬丈餘，共看移步入宸居。曉隨鵷鷺排金鎖，", "還聞漢帝親詞賦，好為從容奏子虛。"]'),
('yuding-22','聽王氏話歸州昭君廟','李遠','唐','御定全唐诗','yuding','','[]','獻之閑坐說歸州，曾到昭君廟裏遊。自古行人多怨恨，',40,'御定全唐詩/json/519.json','["獻之閑坐說歸州，曾到昭君廟裏遊。自古行人多怨恨，", "河畔猶殘翠眉樣，有時新月傍簾鉤。"]'),
('yuding-23','過馬嵬山','李遠','唐','御定全唐诗','yuding','','[]','金甲雲旗盡日回，倉皇羅袖滿塵埃。濃香猶自飄鑾輅，',40,'御定全唐詩/json/519.json','["金甲雲旗盡日回，倉皇羅袖滿塵埃。濃香猶自飄鑾輅，", "唯餘坡上彎環月，時送殘蛾入帝台。"]'),
('yuding-24','吳越懷古','李遠','唐','御定全唐诗','yuding','','[]','吳越千年奈怨何，兩宮清吹作樵歌。姑蘇一敗雲無色，',40,'御定全唐詩/json/519.json','["吳越千年奈怨何，兩宮清吹作樵歌。姑蘇一敗雲無色，", "行人欲問西施館，江鳥寒飛碧草多。"]'),
('yuding-25','長安即事寄友人','李遠','唐','御定全唐诗','yuding','','[]','綺陌千年思斷蓬，今來還宿鳳城東。瑤台鐘鼓長依舊，',40,'御定全唐詩/json/519.json','["綺陌千年思斷蓬，今來還宿鳳城東。瑤台鐘鼓長依舊，", "何時更伴劉郎去，卻見夭桃滿樹紅。"]'),
('yuding-26','聞明上人逝寄友人','李遠','唐','御定全唐诗','yuding','','[]','蕭寺曾過最上方，碧桐濃葉覆西廊。遊人縹緲紅衣亂，',40,'御定全唐詩/json/519.json','["蕭寺曾過最上方，碧桐濃葉覆西廊。遊人縹緲紅衣亂，", "他時若更相隨去，只是含酸對影堂。"]'),
('yuding-27','贈咸陽李少府','李遠','唐','御定全唐诗','yuding','','[]','美貌雄才已少齊，寶書仙簡兩看題。金刀片片裁新錦，',40,'御定全唐詩/json/519.json','["美貌雄才已少齊，寶書仙簡兩看題。金刀片片裁新錦，", "蓬瀛宴罷試回首，一望塵中路正迷。"]'),
('yuding-28','鄰人自金仙觀移竹','李遠','唐','御定全唐诗','yuding','','[]','移居新竹已堪看，劚破莓苔得幾竿。圓節不教傷粉籜，',40,'御定全唐詩/json/519.json','["移居新竹已堪看，劚破莓苔得幾竿。圓節不教傷粉籜，", "第一莫教漁父見，且從蕭颯滿朱欄。"]'),
('yuding-29','慈恩寺避暑','李遠','唐','御定全唐诗','yuding','','[]','香荷疑散麝，風鐸似調琴。不覺清涼晚，歸人滿柳陰。',24,'御定全唐詩/json/519.json','["香荷疑散麝，風鐸似調琴。不覺清涼晚，歸人滿柳陰。"]'),
('yuding-30','讀田光傳','李遠','唐','御定全唐诗','yuding','','[]','秦滅燕丹怨正深，古來豪客盡沾襟。',32,'御定全唐詩/json/519.json','["秦滅燕丹怨正深，古來豪客盡沾襟。", "荊卿不了真閒事，辜負田光一片心。"]'),
('yuding-31','友人下第因以贈之','李遠','唐','御定全唐诗','yuding','','[]','劉毅雖然不擲盧，誰人不道解樗蒲。',32,'御定全唐詩/json/519.json','["劉毅雖然不擲盧，誰人不道解樗蒲。", "黃金百萬終須得，只有挼莎更一呼。"]'),
('yuding-32','詠鴛鴦','李遠','唐','御定全唐诗','yuding','','[]','鴛鴦離別傷，人意似鴛鴦。試取鴛鴦看，多應斷寸腸。',24,'御定全唐詩/json/519.json','["鴛鴦離別傷，人意似鴛鴦。試取鴛鴦看，多應斷寸腸。"]'),
('yuding-33','贈箏妓伍卿','李遠','唐','御定全唐诗','yuding','','[]','輕輕沒後更無箏，玉腕紅紗到伍卿。',32,'御定全唐詩/json/519.json','["輕輕沒後更無箏，玉腕紅紗到伍卿。", "座客滿筵都不語，一行哀雁十三聲。"]'),
('yuding-34','黃陵廟詞','李遠','唐','御定全唐诗','yuding','','[]','黃陵廟前莎草春，黃陵女兒蒨裙新。',32,'御定全唐詩/json/519.json','["黃陵廟前莎草春，黃陵女兒蒨裙新。", "輕舟小楫唱歌去，水遠山長愁殺人。"]'),
('yuding-35','句','李遠','唐','御定全唐诗','yuding','','[]','人事三杯酒，流年一局棋。。',30,'御定全唐詩/json/519.json','["人事三杯酒，流年一局棋。。", "青山不厭三杯酒，長日惟消一局棋。。"]'),
('yuding-0','感懷詩一首','杜牧','唐','御定全唐诗','yuding','','[]','高文會隋季，提劍徇天意。扶持萬代人，步驟三皇地。',577,'御定全唐詩/json/520.json','["高文會隋季，提劍徇天意。扶持萬代人，步驟三皇地。", "聖雲繼之神，神仍用文治。德澤酌生靈，沉酣熏骨髓。", "旄頭騎箕尾，風塵薊門起。胡兵殺漢兵，屍滿咸陽市。", "宣皇走豪傑，談笑開中否。蟠聯兩河間，燼萌終不弭。", "號為精兵處，齊蔡燕趙魏。合環千里疆，爭為一家事。", "逆子嫁虜孫，西鄰聘東裏。急熱同手足，唱和如宮征。", "法制自作為，禮文爭僭擬。壓階螭鬥角，畫屋龍交尾。", "署紙日替名，分財賞稱賜。刳隍by萬尋，繚垣疊千雉。", "誓將付孱孫，血絕然方已。九廟仗神靈，四海為輸委。", "如何七十年，汗赩含羞恥。韓彭不再生，英衛皆為鬼。", "凶門爪牙輩，穰穰如兒戲。累聖但日籲，閫外將誰寄。", "屯田數十萬，堤防常懾惴。急征赴軍須，厚賦資凶器。", "因隳畫一法，且逐隨時利。流品極蒙尨，網羅漸離弛。", "夷狄日開張，黎元愈憔悴。邈矣遠太平，蕭然盡煩費。", "至於貞元末，風流恣綺靡。艱極泰循來，元和聖天子。", "元和聖天子，英明湯武上。茅茨覆宮殿，封章綻帷帳。", "伍旅拔雄兒，夢卜庸真相。勃雲走轟霆，河南一平蕩。", "繼于長慶初，燕趙終舁繈。攜妻負子來，北闕爭頓顙。", "故老撫兒孫，爾生今有望。茹鯁喉尚隘，負重力未壯。", "坐幄無奇兵，吞舟漏疏網。骨添薊垣沙，血漲滹沱浪。", "只雲徒有征，安能問無狀。一日五諸侯，奔亡如鳥往。", "取之難梯天，失之易反掌。蒼然太行路，翦翦還榛莽。", "關西賤男子，誓肉虜杯羹。請數系虜事，誰其為我聽。", "蕩蕩乾坤大，曈曈日月明。叱起文武業，可以豁洪溟。"]'),
('yuding-1','杜秋娘詩','杜牧','唐','御定全唐诗','yuding','','[]','京江水清滑，生女白如脂。其間杜秋者，不勞朱粉施。',576,'御定全唐詩/json/520.json','["京江水清滑，生女白如脂。其間杜秋者，不勞朱粉施。", "老濞即山鑄，後庭千雙眉。秋持玉斝醉，與唱金縷衣。", "濞既白首叛，秋亦紅淚滋。吳江落日渡，灞岸綠楊垂。", "聯裾見天子，盼眄獨依依。椒壁懸錦幕，鏡奩蟠蛟螭。", "低鬟認新寵，窈嫋複融怡。月上白璧門，桂影涼參差。", "金階露新重，閑撚紫簫吹。莓苔夾城路，南苑雁初飛。", "紅粉羽林杖，獨賜辟邪旗。歸來煮豹胎，饜飫不能飴。", "咸池升日慶，銅雀分香悲。雷音後車遠，事往落花時。", "燕禖得皇子，壯發綠緌緌。畫堂授傅姆，天人親捧持。", "虎睛珠絡褓，金盤犀鎮帷。長楊射熊羆，武帳弄啞咿。", "漸拋竹馬劇，稍出舞雞奇。嶄嶄整冠佩，侍宴坐瑤池。", "眉宇儼圖畫，神秀射朝輝。一尺桐偶人，江充知自欺。", "王幽茅土削，秋放故鄉歸。觚棱拂鬥極，回首尚遲遲。", "四朝三十載，似夢複疑非。潼關識舊吏，吏發已如絲。", "卻喚吳江渡，舟人那得知。歸來四鄰改，茂苑草菲菲。", "清血灑不盡，仰天知問誰。寒衣一匹素，夜借鄰人機。", "我昨金陵過，聞之為歔欷。自古皆一貫，變化安能推。", "夏姬滅兩國，逃作巫臣姬。西子下姑蘇，一舸逐鴟夷。", "織室魏豹俘，作漢太平基。誤置代籍中，兩朝尊母儀。", "光武紹高祖，本系生唐兒。珊瑚破高齊，作婢舂黃糜。", "蕭後去揚州，突厥為閼氏。女子固不定，士林亦難期。", "射鉤後呼父，釣翁王者師。無國要孟子，有人毀仲尼。", "秦因逐客令，柄歸丞相斯。安知魏齊首，見斷簀中屍。", "給喪蹶張輩，廊廟冠峨危。珥貂七葉貴，何妨戎虜支。"]'),
('yuding-2','郡齋獨酌','杜牧','唐','御定全唐诗','yuding','','[]','前年鬢生雪，今年須帶霜。時節序鱗次，古今同雁行。',442,'御定全唐詩/json/520.json','["前年鬢生雪，今年須帶霜。時節序鱗次，古今同雁行。", "甘英窮西海，四萬到洛陽。東南我所見，北可計幽荒。", "中畫一萬國，角角棋布方。地頑壓不穴，天迥老不僵。", "屈指百萬世，過如霹靂忙。人生落其內，何者為彭殤？", "促束自系縛，儒衣寬且長。旗亭雪中過，敢問當壚娘。", "我愛李侍中，標標七尺強。白羽八紮弓，髀壓綠檀槍。", "風前略橫陣，紫髯分兩傍。淮西萬虎士，怒目不敢當。", "功成賜宴麟德殿，猿超鶻掠廣球場。三千宮女側頭看，", "我愛朱處士，三吳當中央。罷亞百頃稻，西風吹半黃。", "尚可活鄉里，豈唯滿囷倉？後嶺翠撲撲，前溪碧泱泱。", "霧曉起鳧雁，日晚下牛羊。叔舅欲飲我，社甕爾來嘗。", "伯姊子欲歸，彼亦有壺漿。西阡下柳塢，東陌繞荷塘。", "姻親骨肉舍，煙火遙相望。太守政如水，長官貪似狼。", "征輸一雲畢，任爾自存亡。我昔造其室，羽儀鸞鶴翔。", "交橫碧流上，竹映琴書床。出語無近俗，堯舜禹武湯。", "問今天子少，誰人為棟樑？我曰天子聖，晉公提紀綱。", "聯兵數十萬，附海正誅滄。謂言大義小不義，", "豈知三載幾百戰，鉤車不得望其牆！答雲此山外，", "醺酣更唱太平曲，仁聖天子壽無疆。"]'),
('yuding-3','張好好詩','杜牧','唐','御定全唐诗','yuding','','[]','君為豫章姝，十三才有餘。翠茁鳳生尾，丹葉蓮含跗。',348,'御定全唐詩/json/520.json','["君為豫章姝，十三才有餘。翠茁鳳生尾，丹葉蓮含跗。", "高閣倚天半，章江聯碧虛。此地試君唱，特使華筵鋪。", "主人顧四座，始訝來踟躕。吳娃起引贊，低徊映長裾。", "雙鬟可高下，才過青羅襦。盼盼乍垂袖，一聲雛鳳呼。", "繁弦迸關紐，塞管裂圓蘆。眾音不能逐，嫋嫋穿雲衢。", "主人再三歎，謂言天下殊。贈之天馬錦，副以水犀梳。", "龍沙看秋浪，明月游朱湖。自此每相見，三日已為疏。", "玉質隨月滿，豔態逐春舒。絳唇漸輕巧，雲步轉虛徐。", "旌旆忽東下，笙歌隨舳艫。霜凋謝樓樹，沙暖句溪蒲。", "身外任塵土，樽前極歡娛。飄然集仙客，諷賦欺相如。", "聘之碧瑤佩，載以紫雲車。洞閉水聲遠，月高蟾影孤。", "爾來未幾歲，散盡高陽徒。洛城重相見，婥婥為當壚。", "怪我苦何事，少年垂白須。朋遊今在否，落拓更能無。", "門館慟哭後，水雲秋景初。斜日掛衰柳，涼風生座隅。", "灑盡滿襟淚，短歌聊一書。"]'),
('yuding-4','冬至日寄小侄阿宜詩','杜牧','唐','御定全唐诗','yuding','','[]','小侄名阿宜，未得三尺長。頭圓筋骨緊，兩眼明且光。',516,'御定全唐詩/json/520.json','["小侄名阿宜，未得三尺長。頭圓筋骨緊，兩眼明且光。", "去年學官人，竹馬繞四廊。指揮群兒輩，意氣何堅剛。", "今年始讀書，下口三五行。隨兄旦夕去，斂手整衣裳。", "去歲冬至日，拜我立我旁。祝爾願爾貴，仍且壽命長。", "今年我江外，今日生一陽。憶爾不可見，祝爾傾一觴。", "陽德比君子，初生甚微茫。排陰出九地，萬物隨開張。", "一似小兒學，日就複月將。勤勤不自已，二十能文章。", "仕宦至公相，致君作堯湯。我家公相家，劍佩嘗丁當。", "舊第開朱門，長安城中央。第中無一物，萬卷書滿堂。", "家集二百編，上下馳皇王。多是撫州寫，今來五紀強。", "尚可與爾讀，助爾為賢良。經書括根本，史書閱興亡。", "高摘屈宋豔，濃熏班馬香。李杜泛浩浩，韓柳摩蒼蒼。", "近者四君子，與古爭強梁。願爾一祝後，讀書日日忙。", "一日讀十紙，一月讀一箱。朝廷用文治，大開官職場。", "願爾出門去，取官如驅羊。吾兄苦好古，學問不可量。", "晝居府中治，夜歸書滿床。後貴有金玉，必不為汝藏。", "崔昭生崔芸，李兼生窟郎。堆錢一百屋，破散何披猖。", "今雖未即死，餓凍幾欲僵。參軍與縣尉，塵土驚劻勷。", "一語不中治，笞棰身滿瘡。官罷得絲發，好買百樹桑。", "稅錢未輸足，得米不敢嘗。願爾聞我語，歡喜入心腸。", "大明帝宮闕，杜曲我池塘。我若自潦倒，看汝爭翱翔。", "總語諸小道，此詩不可忘。"]'),
('yuding-5','李甘詩','杜牧','唐','御定全唐诗','yuding','','[]','太和八九年，訓注極虓虎。潛身九地底，轉上青天去。',408,'御定全唐詩/json/520.json','["太和八九年，訓注極虓虎。潛身九地底，轉上青天去。", "四海鏡清澄，千官雲片縷。公私各閒暇，追游日相伍。", "豈知禍亂根，枝葉潛滋莽。九年夏四月，天誡若言語。", "烈風駕地震，獰雷驅猛雨。夜於正殿階，拔去千年樹。", "吾君不省覺，二凶日威武。操持北斗柄，開閉天門路。", "森森明庭士，縮縮循牆鼠。平生負奇節，一旦如奴虜。", "指名為錮黨，狀跡誰告訴。喜無李杜誅，敢憚髡鉗苦。", "時當秋夜月，日值曰庚午。喧喧皆傳言，明晨相登注。", "予時與和鼎，官班各持斧。和鼎顧予言，我死知處所。", "當庭裂詔書，退立須鼎俎。君門曉日開，赭案橫霞布。", "儼雅千官容，勃鬱吾累怒。適屬命鄜將，昨之傳者誤。", "明日詔書下，謫斥南荒去。夜登青泥阪，墜車傷左股。", "病妻尚在床，稚子初離乳。幽蘭思楚澤，恨水啼湘渚。", "怳怳三閭魂，悠悠一千古。其冬二凶敗，渙汗開湯罟。", "賢者須喪亡，讒人尚堆堵。予於後四年，諫官事明主。", "常欲雪幽冤，于時一裨補。拜章豈艱難，膽薄多憂懼。", "如何干鬥氣，竟作炎荒土。題此涕滋筆，以代投湘賦。"]'),
('yuding-6','洛中送冀處士東游','杜牧','唐','御定全唐诗','yuding','','[]','處士有儒術，走可挾車輈。壇宇寬帖帖，符彩高酋酋。',372,'御定全唐詩/json/520.json','["處士有儒術，走可挾車輈。壇宇寬帖帖，符彩高酋酋。", "不愛事耕稼，不樂幹王侯。四十餘年中，超超為浪遊。", "元和五六歲，客于幽魏州。幽魏多壯士，意氣相淹留。", "劉濟願跪履，田興請建籌。處士拱兩手，笑之但掉頭。", "自此南走越，尋山入羅浮。願學不死藥，粗知其來由。", "卻于童頂上，蕭蕭玄發抽。我作八品吏，洛中如系囚。", "忽遭冀處士，豁若登高樓。拂榻與之坐，十日語不休。", "論今星璨璨，考古寒颼颼。治亂掘根本，蔓延相牽鉤。", "武事何駿壯，文理何優柔。顏回捧俎豆，項羽橫戈矛。", "祥雲繞毛髮，高浪開咽喉。但可感神鬼，安能為獻酬。", "好入天子夢，刻像來爾求。胡為去吳會，欲浮滄海舟。", "贈以蜀馬棰，副之胡罽裘。餞酒載三鬥，東郊黃葉稠。", "我感有淚下，君唱高歌酬。嵩山高萬尺，洛水流千秋。", "往事不可問，天地空悠悠。四百年炎漢，三十代宗周。", "二三裏遺堵，八九所高丘。人生一世內，何必多悲愁。", "歌闋解攜去，信非吾輩流。"]'),
('yuding-7','送沈士赴蘇州，李中丞招以詩贈行','杜牧','唐','御定全唐诗','yuding','','[]','山城樹葉紅，下有碧溪水。溪橋向吳路，酒旗誇酒美。',313,'御定全唐詩/json/520.json','["山城樹葉紅，下有碧溪水。溪橋向吳路，酒旗誇酒美。", "下馬此送君，高歌為君醉。念君苞材能，百工在城壘。", "空山三十年，鹿裘掛窗睡。自言隴西公，飄然我知己。", "舉酒屬吳門，今朝為君起。懸弓三百斤，囊書數萬紙。", "戰賊即戰賊，為吏即為吏。盡我所有無，惟公之指使。", "予曰隴西公，滔滔大君子。常思掄群材，一為國家治。", "譬如匠見木，礙眼皆不棄。大者粗十圍，小者細一指。", "cq橛與棟樑，施之皆有位。忽然豎明堂，一揮立能致。", "予亦何為者，亦受公恩紀。處士有常言，殘虜為犬豕。", "常恨兩手空，不得一馬棰。今依隴西公，如虎傅兩翅。", "公非刺史材，當坐岩廊地。處士魁奇姿，必展平生志。", "東吳饒風光，翠巘多名寺。疏煙亹亹秋，獨酌平生思。", "因書問故人，能忘批紙尾。公或憶姓名，為說都憔悴。"]'),
('yuding-8','長安送友人游湖南','杜牧','唐','御定全唐诗','yuding','','[]','子性劇弘和，愚衷深褊狷。相舍囂譊中，吾過何由鮮。',72,'御定全唐詩/json/520.json','["子性劇弘和，愚衷深褊狷。相舍囂譊中，吾過何由鮮。", "楚南饒風煙，湘岸苦縈宛。山密夕陽多，人稀芳草遠。", "青梅繁枝低，斑筍新梢短。莫哭葬魚人，酒醒且眠飯。"]'),
('yuding-9','皇風','杜牧','唐','御定全唐诗','yuding','','[]','仁聖天子神且武，內興文教外披攘。以德化人漢文帝，',40,'御定全唐詩/json/520.json','["仁聖天子神且武，內興文教外披攘。以德化人漢文帝，", "何當提筆侍巡狩，前驅白旆吊河湟。"]'),
('yuding-10','雪中書懷','杜牧','唐','御定全唐诗','yuding','','[]','臘雪一尺厚，雲凍寒頑癡。孤城大澤畔，人疏煙火微。',192,'御定全唐詩/json/520.json','["臘雪一尺厚，雲凍寒頑癡。孤城大澤畔，人疏煙火微。", "憤悱欲誰語，憂慍不能持。天子號仁聖，任賢如事師。", "凡稱曰治具，小大無不施。明庭開廣敞，才雋受羈維。", "如日月縆升，若鸞鳳葳蕤。人才自朽下，棄去亦其宜。", "北虜壞亭障，聞屯千里師。牽連久不解，他盜恐旁窺。", "臣實有長策，彼可徐鞭笞。如蒙一召議，食肉寢其皮。", "斯乃廟堂事，爾微非爾知。向來躐等語，長作陷身機。", "行當臘欲破，酒齊不可遲。且想春候暖，甕間傾一卮。"]'),
('yuding-11','雨中作','杜牧','唐','御定全唐诗','yuding','','[]','賤子本幽慵，多為雋賢侮。得州荒僻中，更值連江雨。',84,'御定全唐詩/json/520.json','["賤子本幽慵，多為雋賢侮。得州荒僻中，更值連江雨。", "一褐擁秋寒，小窗侵竹塢。濁醪氣色嚴，皤腹瓶罌古。", "酣酣天地寬，怳怳嵇劉伍。但為適性情，豈是藏鱗羽。", "一世一萬朝，朝朝醉中去。"]'),
('yuding-12','偶游石盎僧舍','杜牧','唐','御定全唐诗','yuding','','[]','敬岑草浮光，句沚水解脈。益鬱乍怡融，凝嚴忽頹坼。',132,'御定全唐詩/json/520.json','["敬岑草浮光，句沚水解脈。益鬱乍怡融，凝嚴忽頹坼。", "梅纇暖眠酣，風緒和無力。鳧浴漲汪汪，雛嬌村冪冪。", "落日美樓臺，輕煙飾阡陌。瀲綠古津遠，積潤苔基釋。", "孰謂漢陵人，來作江汀客。載筆念無能，捧籌慚所畫。", "任轡偶追閑，逢幽果遭適。僧語淡如雲，塵事繁堪織。", "今古幾輩人，而我何能息。"]'),
('yuding-13','赴京初入汴口，曉景即事，先寄兵部李郎中','杜牧','唐','御定全唐诗','yuding','','[]','清淮控隋漕，北走長安道。檣形櫛櫛斜，浪態迤迤好。',132,'御定全唐詩/json/520.json','["清淮控隋漕，北走長安道。檣形櫛櫛斜，浪態迤迤好。", "初旭紅可染，明河澹如掃。澤闊鳥來遲，村饑人語早。", "露蔓蟲絲多，風蒲燕雛老。秋思高蕭蕭，客愁長嫋嫋。", "因懷京洛間，宦游何戚草。什伍持津梁，澒湧爭追討。", "翾便詎可尋，幾秘安能考。小人乏馨香，上下將何禱。", "唯有君子心，顯豁知幽抱。"]'),
('yuding-14','獨酌','杜牧','唐','御定全唐诗','yuding','','[]','長空碧杳杳，萬古一飛鳥。生前酒伴閑，愁醉閑多少。',48,'御定全唐詩/json/520.json','["長空碧杳杳，萬古一飛鳥。生前酒伴閑，愁醉閑多少。", "煙深隋家寺，殷葉暗相照。獨佩一壺游，秋毫泰山小。"]'),
('yuding-15','惜春','杜牧','唐','御定全唐诗','yuding','','[]','春半年已除，其餘強為有。即此醉殘花，便同嘗臘酒。',48,'御定全唐詩/json/520.json','["春半年已除，其餘強為有。即此醉殘花，便同嘗臘酒。", "悵望送春杯，殷勤掃花帚。誰為駐東流，年年長在手。"]'),
('yuding-16','題安州浮雲寺樓寄湖州張郎中','杜牧','唐','御定全唐诗','yuding','','[]','去夏疏雨餘，同倚朱闌語。當時樓下水，今日到何處。',48,'御定全唐詩/json/520.json','["去夏疏雨餘，同倚朱闌語。當時樓下水，今日到何處。", "恨如春草多，事與孤鴻去。楚岸柳何窮，別愁紛若絮。"]'),
('yuding-17','過驪山作','杜牧','唐','御定全唐诗','yuding','','[]','始皇東游出周鼎，劉項縱觀皆引頸。削平天下實辛勤，',40,'御定全唐詩/json/520.json','["始皇東游出周鼎，劉項縱觀皆引頸。削平天下實辛勤，", "牧童火入九泉底，燒作灰時猶未枯。"]'),
('yuding-18','池州送孟遲先輩','杜牧','唐','御定全唐诗','yuding','','[]','昔子來陵陽，時當苦炎熱。我雖在金台，頭角長垂折。',538,'御定全唐詩/json/520.json','["昔子來陵陽，時當苦炎熱。我雖在金台，頭角長垂折。", "奉披塵意驚，立語平生豁。寺樓最鶱軒，坐送飛鳥沒。", "一樽中夜酒，半破前峰月。煙院松飄蕭，風廊竹交戛。", "時步郭西南，繚徑苔圓折。好鳥響丁丁，小溪光汃汃。", "籬落見娉婷，機絲弄啞軋。煙濕樹姿嬌，雨餘山態活。", "仲秋往曆陽，同上牛磯歇。大江吞天去，一練橫坤抹。", "千帆美滿風，曉日殷鮮血。曆陽裴太守，襟韻苦超越。", "鞔鼓畫麒麟，看君擊狂節。離袖颭應勞，恨粉啼還咽。", "明年忝諫官，綠樹秦川闊。子提健筆來，勢若誇父渴。", "九衢林馬撾，千門織車轍。秦台破心膽，黥陣驚毛髮。", "子既屈一鳴，餘固宜三刖。慵憂長者來，病怯長街喝。", "僧爐風雪夜，相對眠一褐。暖灰重擁瓶，曉粥還分缽。", "青雲馬生角，黃州使持節。秦嶺望樊川，只得回頭別。", "商山四皓祠，心與樗蒲說。大澤蒹葭風，孤城狐兔窟。", "且複考詩書，無因見簪笏。古訓屹如山，古風冷刮骨。", "周鼎列瓶罌，荊璧橫拋摋。力盡不可取，忽忽狂歌發。", "三年未為苦，兩郡非不達。秋浦倚吳江，去楫飛青鶻。", "溪山好畫圖，洞壑深閨闥。竹岡森羽林，花塢團宮纈。", "景物非不佳，獨坐如鞲絏。丹鵲東飛來，喃喃送君劄。", "呼兒旋供衫，走門空踏襪。手把一枝物，桂花香帶雪。", "喜極至無言，笑餘翻不悅。人生直作百歲翁，", "蓬萊頂上斡海水，水盡到底看海空。月於何處去，", "離別豈足更關意，衰老相隨可奈何。"]'),
('yuding-19','重送','杜牧','唐','御定全唐诗','yuding','','[]','手撚金僕姑，腰懸玉轆轤。爬頭峰北正好去，',20,'御定全唐詩/json/520.json','["手撚金僕姑，腰懸玉轆轤。爬頭峰北正好去，"]'),
('yuding-20','題池州弄水亭','杜牧','唐','御定全唐诗','yuding','','[]','弄水亭前溪，颭灩翠綃舞。綺席草芊芊，紫嵐峰伍伍。',312,'御定全唐詩/json/520.json','["弄水亭前溪，颭灩翠綃舞。綺席草芊芊，紫嵐峰伍伍。", "螭蟠得形勢，翬飛如軒戶。一鏡奩曲堤，萬丸跳猛雨。", "檻前燕雁棲，枕上巴帆去。叢筠侍修廊，密蕙媚幽圃。", "杉樹碧為幢，花駢紅作堵。停樽遲晚月，咽咽上幽渚。", "客舟耿孤燈，萬里人夜語。漫流罥苔槎，饑鳧曬雪羽。", "玄絲落鉤餌，冰鱗看吞吐。斷霓天帔垂，狂燒漢旗怒。", "曠朗半秋曉，蕭瑟好風露。光潔疑可攬，欲以襟懷貯。", "幽抱吟九歌，羈情思湘浦。四時皆異狀，終日為良遇。", "小山浸石棱，撐舟入幽處。孤歌倚桂岩，晚酒眠松塢。", "紆餘帶竹村，蠶鄉足砧杵。塍泉落環佩，畦苗差纂組。", "風俗知所尚，豪強恥孤侮。鄰喪不相舂，公租無詬負。", "農時貴伏臘，簪瑱事禮賂。鄉校富華禮，征行產強弩。", "不能自勉去，但愧來何暮。故園漢上林，信美非吾土。"]'),
('yuding-21','題宣州開元寺','杜牧','唐','御定全唐诗','yuding','','[]','南朝謝脁城，東吳最深處。亡國去如鴻，遺寺藏煙塢。',96,'御定全唐詩/json/520.json','["南朝謝脁城，東吳最深處。亡國去如鴻，遺寺藏煙塢。", "樓飛九十尺，廊環四百柱。高高下下中，風繞松桂樹。", "青苔照朱閣，白鳥兩相語。溪聲入僧夢，月色暉粉堵。", "閱景無旦夕，憑闌有今古。留我酒一樽，前山看春雨。"]'),
('yuding-22','大雨行','杜牧','唐','御定全唐诗','yuding','','[]','東垠黑風駕海水，海底卷上天中央。三吳六月忽淒慘，',112,'御定全唐詩/json/520.json','["東垠黑風駕海水，海底卷上天中央。三吳六月忽淒慘，", "神鞭鬼馭載陰帝，來往噴灑何顛狂。四面崩騰玉京仗，", "百川氣勢苦豪俊，坤關密鎖愁開張。太和六年亦如此，", "盡召邑中豪健者，闊展朱盤開酒場。奔觥槌鼓助聲勢，", "景物不盡人自老，誰知前事堪悲傷。"]'),
('yuding-23','自宣州赴官入京，路逢裴坦判官歸宣州，因題贈','杜牧','唐','御定全唐诗','yuding','','[]','敬亭山下百頃竹，中有詩人小謝城。城高跨樓滿金碧，',116,'御定全唐詩/json/520.json','["敬亭山下百頃竹，中有詩人小謝城。城高跨樓滿金碧，", "縈風酒旆掛朱閣，半醉遊人聞弄笙。我初到此未三十，", "老閑腰下丈二組，塵土高懸千載名。重遊鬢白事皆改，", "雲罍看人捧，波臉任他橫。一醉六十日，古來聞阮生。", "是非離別際，始見醉中情。今日送君話前事，"]'),
('yuding-24','贈宣州元處士','杜牧','唐','御定全唐诗','yuding','','[]','陵陽北郭隱，身世兩忘者。蓬蒿三畝居，寬於一天下。',48,'御定全唐詩/json/520.json','["陵陽北郭隱，身世兩忘者。蓬蒿三畝居，寬於一天下。", "樽酒對不酌，默與玄相話。人生自不足，愛歎遭逢寡。"]'),
('yuding-25','村行','杜牧','唐','御定全唐诗','yuding','','[]','春半南陽西，柔桑過村塢。嫋嫋垂柳風，點點回塘雨。',48,'御定全唐詩/json/520.json','["春半南陽西，柔桑過村塢。嫋嫋垂柳風，點點回塘雨。", "蓑唱牧牛兒，籬窺蒨裙女。半濕解征衫，主人饋雞黍。"]'),
('yuding-26','史將軍二首','杜牧','唐','御定全唐诗','yuding','','[]','長鉟周都尉，閑如秋嶺雲。取蝥弧登壘，以駢鄰翼軍。',96,'御定全唐詩/json/520.json','["長鉟周都尉，閑如秋嶺雲。取蝥弧登壘，以駢鄰翼軍。", "百戰百勝價，河南河北聞。今遇太平日，老去誰憐君。", "壯氣蓋燕趙，耽耽魁傑人。彎弧五百步，長戟八十斤。", "河湟非內地，安史有遺塵。何日武台坐，兵符授虎臣。"]'),
('yuding-0','華清宮三十韻','杜牧','唐','御定全唐诗','yuding','','[]','繡嶺明珠殿，層巒下繚牆。仰窺丹檻影，猶想赭袍光。',360,'御定全唐詩/json/521.json','["繡嶺明珠殿，層巒下繚牆。仰窺丹檻影，猶想赭袍光。", "昔帝登封後，中原自古強。一千年際會，三萬里農桑。", "幾席延堯舜，軒墀接禹湯。雷霆馳號令，星斗煥文章。", "釣築乘時用，芝蘭在處芳。北扉閑木索，南面富循良。", "至道思玄圃，平居厭未央。鉤陳裹岩谷，文陛壓青蒼。", "歌吹千秋節，樓臺八月涼。神仙高縹緲，環佩碎丁當。", "泉暖涵窗鏡，雲嬌惹粉囊。嫩嵐滋翠葆，清渭照紅妝。", "帖泰生靈壽，歡娛歲序長。月聞仙曲調，霓作舞衣裳。", "雨露偏金穴，乾坤入醉鄉。玩兵師漢武，回手倒幹將。", "鯨鬣掀東海，胡牙揭上陽。喧呼馬嵬血，零落羽林槍。", "傾國留無路，還魂怨有香。蜀峰橫慘澹，秦樹遠微茫。", "鼎重山難轉，天扶業更昌。望賢餘故老，花萼舊池塘。", "往事人誰問，幽襟淚獨傷。碧簷斜送日，殷葉半凋霜。", "迸水傾瑤砌，疏風罅玉房。塵埃羯鼓索，片段荔枝筐。", "鳥啄摧寒木，蝸涎蠹畫梁。孤煙知客恨，遙起泰陵傍。"]'),
('yuding-1','長安雜題長句六首','杜牧','唐','御定全唐诗','yuding','','[]','觚棱金碧照山高，萬國珪璋捧赭袍。舐筆和鉛欺賈馬，',240,'御定全唐詩/json/521.json','["觚棱金碧照山高，萬國珪璋捧赭袍。舐筆和鉛欺賈馬，", "四海一家無一事，將軍攜鏡泣霜毛。", "晴雲似絮惹低空，紫陌微微弄袖風。韓嫣金丸莎覆綠，", "自笑苦無樓護智，可憐鉛槧竟何功。", "雨晴九陌鋪江練，嵐嫩千峰疊海濤。南苑草芳眠錦雉，", "江碧柳深人盡醉，一瓢顏巷日空高。", "束帶謬趨文石陛，有章曾拜皂囊封。期嚴無奈睡留癖，", "九原可作吾誰與，師友琅琊邴曼容。", "洪河清渭天池浚，太白終南地軸橫。祥雲輝映漢宮紫，", "六飛南幸芙蓉苑，十裏飄香入夾城。", "豐貂長組金張輩，駟馬文衣許史家。白鹿原頭回獵騎，", "誰識大君謙讓德，一毫名利鬥蛙蟆。"]'),
('yuding-2','河湟','杜牧','唐','御定全唐诗','yuding','','[]','元載相公曾借箸，憲宗皇帝亦留神。旋見衣冠就東市，',40,'御定全唐詩/json/521.json','["元載相公曾借箸，憲宗皇帝亦留神。旋見衣冠就東市，", "唯有涼州歌舞曲，流傳天下樂閒人。"]'),
('yuding-3','許七侍御棄官東歸瀟灑江南頗聞自適高秋企望題詩寄贈十韻','杜牧','唐','御定全唐诗','yuding','','[]','天子繡衣吏，東吳美退居。有園同庾信，避事學相如。',120,'御定全唐詩/json/521.json','["天子繡衣吏，東吳美退居。有園同庾信，避事學相如。", "蘭畹晴香嫩，筠溪翠影疏。江山九秋後，風月六朝餘。", "錦帙開詩軸，青囊結道書。霜岩紅薜荔，露沼白芙蕖。", "睡雨高梧密，棋燈小閣虛。凍醪元亮秫，寒鱠季鷹魚。", "塵意迷今古，雲情識卷舒。他年雪中棹，陽羨訪吾廬。"]'),
('yuding-4','李給事中敏二首','杜牧','唐','御定全唐诗','yuding','','[]','一章緘拜皂囊中，懍懍朝廷有古風。元禮去歸緱氏學，',88,'御定全唐詩/json/521.json','["一章緘拜皂囊中，懍懍朝廷有古風。元禮去歸緱氏學，", "曲突徙薪人不會，海邊今作釣魚翁。", "晚發悶還梳，憶君秋醉餘。可憐劉校尉，曾訟石中書。", "消長雖殊事，仁賢每自如。因看魯褒論，何處是吾廬。"]'),
('yuding-5','題永崇西平王宅太尉愬院六韻','杜牧','唐','御定全唐诗','yuding','','[]','天下無雙將，關西第一雄。授符黃石老，學劍白猿翁。',72,'御定全唐詩/json/521.json','["天下無雙將，關西第一雄。授符黃石老，學劍白猿翁。", "矯矯雲長勇，恂恂郤縠風。家呼小太尉，國號大樑公。", "半夜龍驤去，中原虎穴空。隴山兵十萬，嗣子握雕弓。"]'),
('yuding-6','東兵長句十韻','杜牧','唐','御定全唐诗','yuding','','[]','上黨爭為天下脊，邯鄲四十萬秦坑。狂童何者欲專地，',88,'御定全唐詩/json/521.json','["上黨爭為天下脊，邯鄲四十萬秦坑。狂童何者欲專地，", "雄如馬武皆彈劍，少似終軍亦請纓。屈指廟堂無失策，", "即墨龍文光照曜，常山蛇陣勢縱橫。落雕都尉萬人敵，", "凱歌應是新年唱，便逐春風浩浩聲。"]'),
('yuding-7','過勤政樓','杜牧','唐','御定全唐诗','yuding','','[]','千秋令節名空在，承露絲囊世已無。',32,'御定全唐詩/json/521.json','["千秋令節名空在，承露絲囊世已無。", "唯有紫苔偏得意，年年因雨上金鋪。"]'),
('yuding-8','過魏文貞公宅','杜牧','唐','御定全唐诗','yuding','','[]','蟪蛄寧與雪霜期，賢哲難教俗士知。',32,'御定全唐詩/json/521.json','["蟪蛄寧與雪霜期，賢哲難教俗士知。", "可憐貞觀太平後，天且不留封德彝。"]'),
('yuding-9','早春閣下寓直蕭九舍人亦直內署，因寄書懷四韻','杜牧','唐','御定全唐诗','yuding','','[]','禦水初銷凍，宮花尚怯寒。千峰橫紫翠，雙闕憑闌幹。',48,'御定全唐詩/json/521.json','["禦水初銷凍，宮花尚怯寒。千峰橫紫翠，雙闕憑闌幹。", "玉漏輕風順，金莖淡日殘。王喬在何處，清漢正驂鸞。"]'),
('yuding-10','秋晚與沈十七舍人期游樊川不至','杜牧','唐','御定全唐诗','yuding','','[]','邀侶以官解，泛然成獨遊。川光初媚日，山色正矜秋。',48,'御定全唐詩/json/521.json','["邀侶以官解，泛然成獨遊。川光初媚日，山色正矜秋。", "野竹疏還密，岩泉咽複流。杜村連潏水，晚步見垂鉤。"]'),
('yuding-11','念昔遊三首','杜牧','唐','御定全唐诗','yuding','','[]','十載飄然繩檢外，樽前自獻自為酬。',96,'御定全唐詩/json/521.json','["十載飄然繩檢外，樽前自獻自為酬。", "秋山春雨閑吟處，倚遍江南寺寺樓。", "雲門寺外逢猛雨，林黑山高雨腳長。", "曾奉郊宮為近侍，分明羽林槍。", "李白題詩水西寺，古木回岩樓閣風。", "半醒半醉遊三日，紅白花開山雨中。"]'),
('yuding-12','今皇帝陛下一詔徵兵不日功集河湟諸郡次第歸降臣獲睹聖功輒獻歌詠','杜牧','唐','御定全唐诗','yuding','','[]','捷書皆應睿謀期，十萬曾無一鏃遺。漢武慚誇朔方地，',40,'御定全唐詩/json/521.json','["捷書皆應睿謀期，十萬曾無一鏃遺。漢武慚誇朔方地，", "聽取滿城歌舞曲，涼州聲韻喜參差。"]'),
('yuding-13','奉和白相公聖德和平致茲休運歲終功就合詠盛明呈上三相公長句四韻','杜牧','唐','御定全唐诗','yuding','','[]','行看臘破好年光，萬壽南山對未央。黠戛可汗修職貢，',40,'御定全唐詩/json/521.json','["行看臘破好年光，萬壽南山對未央。黠戛可汗修職貢，", "吉甫裁詩歌盛業，一篇江漢美宣王。"]'),
('yuding-14','過華清宮絕句三首','杜牧','唐','御定全唐诗','yuding','','[]','長安回望繡成堆，山頂千門次第開。',96,'御定全唐詩/json/521.json','["長安回望繡成堆，山頂千門次第開。", "一騎紅塵妃子笑，無人知是荔枝來。", "新豐綠樹起黃埃，數騎漁陽探使回。", "霓裳一曲千峰上，舞破中原始下來。", "萬國笙歌醉太平，倚天樓殿月分明。", "雲中亂拍祿山舞，風過重巒下笑聲。"]'),
('yuding-15','登樂游原','杜牧','唐','御定全唐诗','yuding','','[]','長空澹澹孤鳥沒，萬古銷沉向此中。',32,'御定全唐詩/json/521.json','["長空澹澹孤鳥沒，萬古銷沉向此中。", "看取漢家何事業，五陵無樹起秋風。"]'),
('yuding-16','聞慶州趙縱使君與黨項戰中箭身死，輒書長句','杜牧','唐','御定全唐诗','yuding','','[]','將軍獨乘鐵驄馬，榆溪戰中金僕姑。死綏卻是古來有，',40,'御定全唐詩/json/521.json','["將軍獨乘鐵驄馬，榆溪戰中金僕姑。死綏卻是古來有，", "誰知我亦輕生者，不得君王丈二殳。"]'),
('yuding-17','送容州唐中丞赴鎮','杜牧','唐','御定全唐诗','yuding','','[]','交址同星座，龍泉佩鬥文。燒香翠羽帳，看舞郁金裙。',48,'御定全唐詩/json/521.json','["交址同星座，龍泉佩鬥文。燒香翠羽帳，看舞郁金裙。", "鷁首沖瀧浪，犀渠拂嶺雲。莫教銅柱北，空說馬將軍。"]'),
('yuding-18','夏州崔常侍自少常亞列出領麾幢十韻','杜牧','唐','御定全唐诗','yuding','','[]','帝命詩書將，登壇禮樂卿。三邊要高枕，萬里得長城。',120,'御定全唐詩/json/521.json','["帝命詩書將，登壇禮樂卿。三邊要高枕，萬里得長城。", "對客猶褒博，填門已旆旌。腰間五綬貴，天下一家榮。", "野水差新燕，芳郊哢夏鶯。別風嘶玉勒，殘日望金莖。", "榆塞孤煙媚，銀川綠草明。戈矛虓虎士，弓箭落雕兵。", "魏絳言堪采，陳湯事偶成。若須垂竹帛，靜勝是功名。"]'),
('yuding-19','街西長句','杜牧','唐','御定全唐诗','yuding','','[]','碧池新漲浴嬌鴉，分鎖長安富貴家。游騎偶同人鬥酒，',40,'御定全唐詩/json/521.json','["碧池新漲浴嬌鴉，分鎖長安富貴家。游騎偶同人鬥酒，", "一曲將軍何處笛，連雲芳草日初斜。"]'),
('yuding-20','春申君','杜牧','唐','御定全唐诗','yuding','','[]','烈士思酬國士恩，春申誰與快冤魂。',32,'御定全唐詩/json/521.json','["烈士思酬國士恩，春申誰與快冤魂。", "三千賓客總珠履，欲使何人殺李園。"]'),
('yuding-21','奉陵宮人','杜牧','唐','御定全唐诗','yuding','','[]','相如死後無詞客，延壽亡來絕畫工。',32,'御定全唐詩/json/521.json','["相如死後無詞客，延壽亡來絕畫工。", "玉顏不是黃金少，淚滴秋山入壽宮。"]'),
('yuding-22','讀韓杜集','杜牧','唐','御定全唐诗','yuding','','[]','杜詩韓集愁來讀，似倩麻姑癢處抓。',32,'御定全唐詩/json/521.json','["杜詩韓集愁來讀，似倩麻姑癢處抓。", "天外鳳凰誰得髓，無人解合續弦膠。"]'),
('yuding-23','春日言懷寄虢州李常侍十韻','杜牧','唐','御定全唐诗','yuding','','[]','岸蘚生紅藥，岩泉漲碧塘。地分蓮嶽秀，草接鼎原芳。',120,'御定全唐詩/json/521.json','["岸蘚生紅藥，岩泉漲碧塘。地分蓮嶽秀，草接鼎原芳。", "雨派潈漴急，風畦芷若香。織蓬眠舴艋，驚夢起鴛鴦。", "論吐開冰室，詩陳曝錦張。貂簪荊玉潤，丹穴鳳毛光。", "今日還珠守，何年執戟郎。且嫌游晝短，莫問積薪長。", "無計披清裁，唯持祝壽觴。願公如衛武，百歲尚康強。"]'),
('yuding-24','李侍郎於陽羨里富有泉石牧亦於陽羨粗有薄產敘舊述懷因獻長句四韻','杜牧','唐','御定全唐诗','yuding','','[]','冥鴻不下非無意，塞馬歸來是偶然。紫綬公卿今放曠，',40,'御定全唐詩/json/521.json','["冥鴻不下非無意，塞馬歸來是偶然。紫綬公卿今放曠，", "欲與明公操履杖，願聞休去是何年。"]'),
('yuding-25','贈李處士長句四韻','杜牧','唐','御定全唐诗','yuding','','[]','玉函怪牒鎖靈篆，紫洞香風吹碧桃。老翁四目牙爪利，',40,'御定全唐詩/json/521.json','["玉函怪牒鎖靈篆，紫洞香風吹碧桃。老翁四目牙爪利，", "三山朝去應非久，姹女當窗繡羽袍。"]'),
('yuding-26','送國棋王逢','杜牧','唐','御定全唐诗','yuding','','[]','玉子紋楸一路饒，最宜簷雨竹蕭蕭。羸形暗去春泉長，',40,'御定全唐詩/json/521.json','["玉子紋楸一路饒，最宜簷雨竹蕭蕭。羸形暗去春泉長，", "浮生七十更萬日，與子期於局上銷。"]'),
('yuding-27','重送絕句','杜牧','唐','御定全唐诗','yuding','','[]','絕藝如君天下少，閒人似我世間無。',32,'御定全唐詩/json/521.json','["絕藝如君天下少，閒人似我世間無。", "別後竹窗風雪夜，一燈明暗覆吳圖。"]'),
('yuding-28','少年行','杜牧','唐','御定全唐诗','yuding','','[]','連環羈玉聲光碎，綠錦蔽泥虯卷高。',32,'御定全唐詩/json/521.json','["連環羈玉聲光碎，綠錦蔽泥虯卷高。", "春風細雨走馬去，珠落璀璀白罽袍。"]'),
('yuding-29','奉和門下相公送西川相公兼領相印出鎮全蜀詩十八韻','杜牧','唐','御定全唐诗','yuding','','[]','盛業冠伊唐，臺階翊戴光。無私天雨露，有截舜衣裳。',216,'御定全唐詩/json/521.json','["盛業冠伊唐，臺階翊戴光。無私天雨露，有截舜衣裳。", "蜀輟新衡鏡，池留舊鳳凰。同心真石友，寫恨蔑河梁。", "虎騎搖風旆，貂冠韻水蒼。彤弓隨武庫，金印逐文房。", "棧壓嘉陵咽，峰橫劍閣長。前驅二星去，開險五丁忙。", "回首崢嶸盡，連天草樹芳。丹心懸魏闕，往事愴甘棠。", "治化輕諸葛，威聲懾夜郎。君平教說卦，夫子召升堂。", "塞接西山雪，橋維萬里檣。奪霞紅錦爛，撲地酒壚香。", "忝逐三千客，曾依數仞牆。滯頑堪白屋，攀附亦同行。", "肉管伶倫曲，簫韶清廟章。唱高知和寡，小子斐然狂。"]'),
('yuding-30','朱坡','杜牧','唐','御定全唐诗','yuding','','[]','下杜鄉園古，泉聲繞舍啼。靜思長慘切，薄宦與乖暌。',240,'御定全唐詩/json/521.json','["下杜鄉園古，泉聲繞舍啼。靜思長慘切，薄宦與乖暌。", "北闕千門外，南山午穀西。倚川紅葉嶺，連寺綠楊堤。", "迥野翹霜鶴，澄潭舞錦雞。濤驚堆萬岫，舸急轉千溪。", "眉點萱牙嫩，風條柳幄迷。岸藤梢虺尾，沙渚印麑蹄。", "火燎湘桃塢，波光碧繡畦。日痕縆翠巘，陂影墮晴霓。", "蝸壁斕斑蘚，銀筵豆蔻泥。洞雲生片段，苔徑繚高低。", "偃蹇松公老，森嚴竹陣齊。小蓮娃欲語，幽筍稚相攜。", "漢館留餘趾，周台接故蹊。蟠蛟岡隱隱，班雉草萋萋。", "樹老蘿紆組，岩深石啟閨。侵窗紫桂茂，拂面翠禽棲。", "有計冠終掛，無才筆謾提。自塵何太甚，休笑觸藩羝。"]'),
('yuding-31','早春寄岳州李使君，李善棋愛酒，情地閒雅','杜牧','唐','御定全唐诗','yuding','','[]','城高倚峭巘，地勝足樓臺。朔漠暖鴻去，瀟湘春水來。',120,'御定全唐詩/json/521.json','["城高倚峭巘，地勝足樓臺。朔漠暖鴻去，瀟湘春水來。", "縈盈幾多思，掩抑若為裁。返照三聲角，寒香一樹梅。", "烏林芳草遠，赤壁健帆開。往事空遺恨，東流豈不回。", "分符潁川政，吊屈洛陽才。拂匣調珠柱，磨鉛勘玉杯。", "棋翻小窟勢，壚撥凍醪醅。此興予非薄，何時得奉陪。"]'),
('yuding-32','送王侍禦赴夏口座主幕','杜牧','唐','御定全唐诗','yuding','','[]','君為珠履三千客，我是青衿七十徒。禮數全優知隗始，',24,'御定全唐詩/json/521.json','["君為珠履三千客，我是青衿七十徒。禮數全優知隗始，"]'),
('yuding-33','自貽','杜牧','唐','御定全唐诗','yuding','','[]','杜陵蕭次君，遷少去官頻。寂寞憐吾道，依稀似古人。',48,'御定全唐詩/json/521.json','["杜陵蕭次君，遷少去官頻。寂寞憐吾道，依稀似古人。", "飾心無彩繢，到骨是風塵。自嫌如匹素，刀尺不由身。"]'),
('yuding-34','自遣','杜牧','唐','御定全唐诗','yuding','','[]','四十已雲老，況逢憂窘餘。且抽持板手，卻展小年書。',72,'御定全唐詩/json/521.json','["四十已雲老，況逢憂窘餘。且抽持板手，卻展小年書。", "嗜酒狂嫌阮，知非晚笑蘧。聞流寧歎吒，待俗不親疏。", "遇事知裁剪，操心識卷舒。還稱二千石，於我意何如。"]'),
('yuding-35','題桐葉','杜牧','唐','御定全唐诗','yuding','','[]','去年桐落故溪上，把筆偶題歸燕詩。江樓今日送歸燕，',96,'御定全唐詩/json/521.json','["去年桐落故溪上，把筆偶題歸燕詩。江樓今日送歸燕，", "笑筵歌席反惆悵，明月清風愴別離。莊叟彭殤同在夢，", "哆侈不勞文似錦，進趨何必利如錐。錢神任爾知無敵，", "樽香輕泛數枝菊，簷影斜侵半局棋。休指宦遊論巧拙，"]'),
('yuding-36','沈下賢','杜牧','唐','御定全唐诗','yuding','','[]','斯人清唱何人和，草徑苔蕪不可尋。',32,'御定全唐詩/json/521.json','["斯人清唱何人和，草徑苔蕪不可尋。", "一夕小敷山下夢，水如環佩月如襟。"]'),
('yuding-37','李和鼎','杜牧','唐','御定全唐诗','yuding','','[]','鵩鳥飛來庚子直，謫去日蝕辛卯年。',32,'御定全唐詩/json/521.json','["鵩鳥飛來庚子直，謫去日蝕辛卯年。", "由來枉死賢才事，消長相持勢自然。"]'),
('yuding-38','贈沈學士張歌人','杜牧','唐','御定全唐诗','yuding','','[]','拖袖事當年，郎教唱客前。斷時輕裂玉，收處遠繰煙。',72,'御定全唐詩/json/521.json','["拖袖事當年，郎教唱客前。斷時輕裂玉，收處遠繰煙。", "孤直縆雲定，光明滴水圓。泥情遲急管，流恨咽長弦。", "吳苑春風起，河橋酒旆懸。憑君更一醉，家在杜陵邊。"]'),
('yuding-39','憶游朱坡四韻','杜牧','唐','御定全唐诗','yuding','','[]','秋草樊川路，斜陽覆盎門。獵逢韓嫣騎，樹識館陶園。',48,'御定全唐詩/json/521.json','["秋草樊川路，斜陽覆盎門。獵逢韓嫣騎，樹識館陶園。", "帶雨經荷沼，盤煙下竹村。如今歸不得，自戴望天盆。"]'),
('yuding-40','朱坡絕句三首','杜牧','唐','御定全唐诗','yuding','','[]','故國池塘倚禦渠，江城三詔換魚書。',96,'御定全唐詩/json/521.json','["故國池塘倚禦渠，江城三詔換魚書。", "賈生辭賦恨流落，只向長沙住歲餘。", "煙深苔巷唱樵兒，花落寒輕倦客歸。", "藤岸竹洲相掩映，滿池春雨鸊鵜飛。", "乳肥春洞生鵝管，沼避回岩勢犬牙。", "自笑卷懷頭角縮，歸盤煙磴恰如蝸。"]'),
('yuding-41','出宮人二首','杜牧','唐','御定全唐诗','yuding','','[]','閑吹玉殿昭華管，醉折梨園縹蒂花。',64,'御定全唐詩/json/521.json','["閑吹玉殿昭華管，醉折梨園縹蒂花。", "十年一夢歸人世，絳縷猶封系臂紗。", "平陽拊背穿馳道，銅雀分香下璧門。", "幾向綴珠深殿裏，妒拋羞態臥黃昏。"]'),
('yuding-42','長安秋望','杜牧','唐','御定全唐诗','yuding','','[]','樓倚霜樹外，鏡天無一毫。南山與秋色，氣勢兩相高。',24,'御定全唐詩/json/521.json','["樓倚霜樹外，鏡天無一毫。南山與秋色，氣勢兩相高。"]'),
('yuding-43','獨酌','杜牧','唐','御定全唐诗','yuding','','[]','窗外正風雪，擁爐開酒缸。何如釣船雨，篷底睡秋江。',24,'御定全唐詩/json/521.json','["窗外正風雪，擁爐開酒缸。何如釣船雨，篷底睡秋江。"]'),
('yuding-44','醉眠','杜牧','唐','御定全唐诗','yuding','','[]','秋醪雨中熟，寒齋落葉中。幽人本多睡，更酌一樽空。',24,'御定全唐詩/json/521.json','["秋醪雨中熟，寒齋落葉中。幽人本多睡，更酌一樽空。"]'),
('yuding-45','不飲贈酒','杜牧','唐','御定全唐诗','yuding','','[]','細算人生事，彭殤共一籌。與愁爭底事，要爾作戈矛。',24,'御定全唐詩/json/521.json','["細算人生事，彭殤共一籌。與愁爭底事，要爾作戈矛。"]'),
('yuding-46','昔事文皇帝三十二韻','杜牧','唐','御定全唐诗','yuding','','[]','昔事文皇帝，叨官在諫垣。奏章為得地，齰齒負明恩。',384,'御定全唐詩/json/521.json','["昔事文皇帝，叨官在諫垣。奏章為得地，齰齒負明恩。", "金虎知難動，毛厘亦恥言。掩頭雖欲吐，到口卻成吞。", "照膽常懸鏡，窺天自戴盆。周鐘既窕槬，黥陣亦瘢痕。", "鳳闕觚棱影，仙盤曉日暾。雨晴文石滑，風暖戟衣翻。", "每慮號無告，長憂駭不存。隨行唯局蹐，出語但寒暄。", "宮省咽喉任，戈矛羽衛屯。光塵皆影附，車馬定西奔。", "億萬持衡價，錙銖挾契論。堆時過北斗，積處滿西園。", "接棹隋河溢，連蹄蜀棧刓。漉空滄海水，搜盡卓王孫。", "鬥巧猴雕刺，誇趫索掛跟。狐威假白額，梟嘯得黃昏。", "馥馥芝蘭圃，森森枳棘藩。吠聲嗾國猘，公議怯膺門。", "竄逐諸丞相，蒼茫遠帝閽。一名為起士，誰免吊湘魂。", "間世英明主，中興道德尊。昆岡憐積火，河漢注清源。", "川口堤防決，陰車鬼怪掀。重雲開朗照，九地雪幽冤。", "我實剛腸者，形甘短褐髡。曾經觸蠆尾，猶得憑熊軒。", "杜若芳洲翠，嚴光釣瀨喧。溪山侵越角，封壤盡吳根。", "客恨縈春細，鄉愁壓思繁。祝堯千萬壽，再拜揖餘樽。"]'),
('yuding-47','道一大尹存之庭美二學士簡于聖明自致霄漢皆與舍弟昔年還往牧支離窮悴竊於一麾書美歌詩兼自言志因成長句四韻呈上三君子','杜牧','唐','御定全唐诗','yuding','','[]','九金神鼎重丘山，五玉諸侯雜佩環。星座通霄狼鬣暗，',40,'御定全唐詩/json/521.json','["九金神鼎重丘山，五玉諸侯雜佩環。星座通霄狼鬣暗，", "若念西河舊交友，魚符應許出函關。"]'),
('yuding-48','杏園','杜牧','唐','御定全唐诗','yuding','','[]','夜來微雨洗芳塵，公子驊騮步貼勻。',32,'御定全唐詩/json/521.json','["夜來微雨洗芳塵，公子驊騮步貼勻。", "莫怪杏園憔悴去，滿城多少插花人。"]'),
('yuding-49','春晚題韋家亭子','杜牧','唐','御定全唐诗','yuding','','[]','擁鼻侵襟花草香，高臺春去恨茫茫。',32,'御定全唐詩/json/521.json','["擁鼻侵襟花草香，高臺春去恨茫茫。", "蔫紅半落平池晚，曲渚飄成錦一張。"]'),
('yuding-50','過田家宅','杜牧','唐','御定全唐诗','yuding','','[]','安邑南門外，誰家板築高。奉誠園裏地，牆缺見蓬蒿。',24,'御定全唐詩/json/521.json','["安邑南門外，誰家板築高。奉誠園裏地，牆缺見蓬蒿。"]'),
('yuding-51','見宋拾遺題名處，感而成詩','杜牧','唐','御定全唐诗','yuding','','[]','竄逐窮荒與死期，餓唯蒿藿病無醫。',32,'御定全唐詩/json/521.json','["竄逐窮荒與死期，餓唯蒿藿病無醫。", "憐君更抱重泉恨，不見崇山謫去時。"]'),
('yuding-52','雪晴訪趙嘏街西所居三韻','杜牧','唐','御定全唐诗','yuding','','[]','命代風騷將，誰登李杜壇。少陵鯨海動，翰苑鶴天寒。',40,'御定全唐詩/json/521.json','["命代風騷將，誰登李杜壇。少陵鯨海動，翰苑鶴天寒。", "今日訪君還有意，三條冰雪獨來看。"]'),
('yuding-53','將赴吳興登樂游原一絕','杜牧','唐','御定全唐诗','yuding','','[]','清時有味是無能，閑愛孤雲靜愛僧。',32,'御定全唐詩/json/521.json','["清時有味是無能，閑愛孤雲靜愛僧。", "欲把一麾江海去，樂游原上望昭陵。"]'),
('yuding-54','洛陽長句二首','杜牧','唐','御定全唐诗','yuding','','[]','草色人心相與閑，是非名利有無間。橋橫落照虹堪畫，',80,'御定全唐詩/json/521.json','["草色人心相與閑，是非名利有無間。橋橫落照虹堪畫，", "君王謙讓泥金事，蒼翠空高萬歲山。", "天漢東穿白玉京，日華浮動翠光生。橋邊遊女佩環委，", "連昌繡嶺行宮在，玉輦何時父老迎。"]'),
('yuding-55','洛中監察病假滿，送韋楚老拾遺歸朝','杜牧','唐','御定全唐诗','yuding','','[]','洛橋風暖細翻衣，春引仙官去玉墀。獨鶴初沖太虛日，',40,'御定全唐詩/json/521.json','["洛橋風暖細翻衣，春引仙官去玉墀。獨鶴初沖太虛日，", "十載丈夫堪恥處，朱雲猶掉直言旗。"]'),
('yuding-56','東都送鄭處誨校書歸上都','杜牧','唐','御定全唐诗','yuding','','[]','悠悠渠水清，雨霽洛陽城。槿墮初開豔，蟬聞第一聲。',48,'御定全唐詩/json/521.json','["悠悠渠水清，雨霽洛陽城。槿墮初開豔，蟬聞第一聲。", "故人容易去，白髮等閒生。此別無多語，期君晦盛名。"]'),
('yuding-57','故洛陽城有感','杜牧','唐','御定全唐诗','yuding','','[]','一片宮牆當道危，行人為爾去遲遲。篳圭苑裏秋風後，',40,'御定全唐詩/json/521.json','["一片宮牆當道危，行人為爾去遲遲。篳圭苑裏秋風後，", "千燒萬戰坤靈死，慘慘終年鳥雀悲。"]'),
('yuding-0','揚州三首','杜牧','唐','御定全唐诗','yuding','','[]','煬帝雷塘土，迷藏有舊樓。誰家唱水調，明月滿揚州。',156,'御定全唐詩/json/522.json','["煬帝雷塘土，迷藏有舊樓。誰家唱水調，明月滿揚州。", "駿馬宜閑出，千金好舊游。喧闐醉年少，半脫紫茸裘。", "秋風放螢苑，春草鬥雞台。金絡擎雕去，鸞環拾翠來。", "蜀船紅錦重，越橐水沈堆。處處皆華表，淮王奈卻回。", "街垂千步柳，霞映兩重城。天碧台閣麗，風涼歌管清。", "纖腰間長袖，玉佩雜繁纓。拖軸誠為壯，豪華不可名。", "自是荒淫罪，何妨作帝京。"]'),
('yuding-1','潤州二首','杜牧','唐','御定全唐诗','yuding','','[]','句吳亭東千里秋，放歌曾作昔年遊。青苔寺裏無馬跡，',80,'御定全唐詩/json/522.json','["句吳亭東千里秋，放歌曾作昔年遊。青苔寺裏無馬跡，", "月明更想桓伊在，一笛聞吹出塞愁。", "謝脁詩中佳麗地，夫差傳裏水犀軍。城高鐵甕橫強弩，", "揚州塵土試回首，不惜千金借與君。"]'),
('yuding-2','題揚州禪智寺','杜牧','唐','御定全唐诗','yuding','','[]','雨過一蟬噪，飄蕭松桂秋。青苔滿階砌，白鳥故遲留。',48,'御定全唐詩/json/522.json','["雨過一蟬噪，飄蕭松桂秋。青苔滿階砌，白鳥故遲留。", "暮靄生深樹，斜陽下小樓。誰知竹西路，歌吹是揚州。"]'),
('yuding-3','西江懷古','杜牧','唐','御定全唐诗','yuding','','[]','上吞巴漢控瀟湘，怒似連山淨鏡光。魏帝縫囊真戲劇，',24,'御定全唐詩/json/522.json','["上吞巴漢控瀟湘，怒似連山淨鏡光。魏帝縫囊真戲劇，"]'),
('yuding-4','江南懷古','杜牧','唐','御定全唐诗','yuding','','[]','車書混一業無窮，井邑山川今古同。',32,'御定全唐詩/json/522.json','["車書混一業無窮，井邑山川今古同。", "戊辰年向金陵過，惆悵閑吟憶庾公。"]'),
('yuding-5','江南春絕句','杜牧','唐','御定全唐诗','yuding','','[]','千里鶯啼綠映紅，水村山郭酒旗風。',32,'御定全唐詩/json/522.json','["千里鶯啼綠映紅，水村山郭酒旗風。", "南朝四百八十寺，多少樓臺煙雨中。"]'),
('yuding-6','將赴宣州留題揚州禪智寺','杜牧','唐','御定全唐诗','yuding','','[]','故里溪頭松柏雙，來時盡日倚松窗。',32,'御定全唐詩/json/522.json','["故里溪頭松柏雙，來時盡日倚松窗。", "杜陵隋苑已絕國，秋晚南游更渡江。"]'),
('yuding-7','題宣州開元寺水閣閣下宛溪夾溪居人','杜牧','唐','御定全唐诗','yuding','','[]','六朝文物草連空，天淡雲閑今古同。鳥去鳥來山色裏，',40,'御定全唐詩/json/522.json','["六朝文物草連空，天淡雲閑今古同。鳥去鳥來山色裏，", "惆悵無因見範蠡，參差煙樹五湖東。"]'),
('yuding-8','宣州送裴坦判官往舒州，時牧欲赴官歸京','杜牧','唐','御定全唐诗','yuding','','[]','日暖泥融雪半銷，行人芳草馬聲驕。九華山路雲遮寺，',40,'御定全唐詩/json/522.json','["日暖泥融雪半銷，行人芳草馬聲驕。九華山路雲遮寺，", "同來不得同歸去，故國逢春一寂寥。"]'),
('yuding-9','句溪夏日送盧霈秀才歸王屋山將欲赴舉','杜牧','唐','御定全唐诗','yuding','','[]','野店正紛泊，繭蠶初引絲。行人碧溪渡，系馬綠楊枝。',48,'御定全唐詩/json/522.json','["野店正紛泊，繭蠶初引絲。行人碧溪渡，系馬綠楊枝。", "苒苒跡始去，悠悠心所期。秋山念君別，惆悵桂花時。"]'),
('yuding-10','自宣城赴官上京','杜牧','唐','御定全唐诗','yuding','','[]','瀟灑江湖十過秋，酒杯無日不淹留。謝公城畔溪驚夢，',40,'御定全唐詩/json/522.json','["瀟灑江湖十過秋，酒杯無日不淹留。謝公城畔溪驚夢，", "塵冠掛卻知閒事，終擬蹉跎訪舊遊。"]'),
('yuding-11','春末題池州弄水亭','杜牧','唐','御定全唐诗','yuding','','[]','使君四十四，兩佩左銅魚。為吏非循吏，論書讀底書。',96,'御定全唐詩/json/522.json','["使君四十四，兩佩左銅魚。為吏非循吏，論書讀底書。", "晚花紅豔靜，高樹綠陰初。亭宇清無比，溪山畫不如。", "嘉賓能嘯詠，宮妓巧妝梳。逐日愁皆碎，隨時醉有餘。", "偃須求五鼎，陶只愛吾廬。趣向人皆異，賢豪莫笑渠。"]'),
('yuding-12','登池州九峰樓寄張祜','杜牧','唐','御定全唐诗','yuding','','[]','百感中來不自由，角聲孤起夕陽樓。碧山終日思無盡，',40,'御定全唐詩/json/522.json','["百感中來不自由，角聲孤起夕陽樓。碧山終日思無盡，", "誰人得似張公子，千首詩輕萬戶侯。"]'),
('yuding-13','齊安郡晚秋','杜牧','唐','御定全唐诗','yuding','','[]','柳岸風來影漸疏，使君家似野人居。雲容水態還堪賞，',40,'御定全唐詩/json/522.json','["柳岸風來影漸疏，使君家似野人居。雲容水態還堪賞，", "可憐赤壁爭雄渡，唯有蓑翁坐釣魚。"]'),
('yuding-14','九日齊安登高','杜牧','唐','御定全唐诗','yuding','','[]','江涵秋影雁初飛，與客攜壺上翠微。塵世難逢開口笑，',40,'御定全唐詩/json/522.json','["江涵秋影雁初飛，與客攜壺上翠微。塵世難逢開口笑，", "古往今來只如此，牛山何必淚沾衣。"]'),
('yuding-15','池州春送前進士蒯希逸','杜牧','唐','御定全唐诗','yuding','','[]','芳草複芳草，斷腸還斷腸。自然堪下淚，何必更殘陽。',48,'御定全唐詩/json/522.json','["芳草複芳草，斷腸還斷腸。自然堪下淚，何必更殘陽。", "楚岸千萬里，燕鴻三兩行。有家歸不得，況舉別君觴。"]'),
('yuding-16','齊安郡中偶題二首','杜牧','唐','御定全唐诗','yuding','','[]','兩竿落日溪橋上，半縷輕煙柳影中。',64,'御定全唐詩/json/522.json','["兩竿落日溪橋上，半縷輕煙柳影中。", "多少綠荷相倚恨，一時回首背西風。", "秋聲無不攪離心，夢澤蒹葭楚雨深。", "自滴階前大梧葉，幹君何事動哀吟。"]'),
('yuding-17','齊安郡後池絕句','杜牧','唐','御定全唐诗','yuding','','[]','菱透浮萍綠錦池，夏鶯千囀弄薔薇。',32,'御定全唐詩/json/522.json','["菱透浮萍綠錦池，夏鶯千囀弄薔薇。", "盡日無人看微雨，鴛鴦相對浴紅衣。"]'),
('yuding-18','題齊安城樓','杜牧','唐','御定全唐诗','yuding','','[]','嗚咽江樓角一聲，微陽瀲瀲落寒汀。',32,'御定全唐詩/json/522.json','["嗚咽江樓角一聲，微陽瀲瀲落寒汀。", "不用憑闌苦回首，故鄉七十五長亭。"]'),
('yuding-19','池州李使君沒後十一日處州新命始到後見歸妓感而成詩','杜牧','唐','御定全唐诗','yuding','','[]','縉雲新命詔初行，才是孤魂壽器成。黃壤不知新雨露，',40,'御定全唐詩/json/522.json','["縉雲新命詔初行，才是孤魂壽器成。黃壤不知新雨露，", "多少四年遺愛事，鄉閭生子李為名。"]'),
('yuding-20','見劉秀才與池州妓別','杜牧','唐','御定全唐诗','yuding','','[]','遠風南浦萬重波，未似生離別恨多。楚管能吹柳花怨，',40,'御定全唐詩/json/522.json','["遠風南浦萬重波，未似生離別恨多。楚管能吹柳花怨，", "待得枚皋相見日，自應妝鏡笑蹉跎。"]'),
('yuding-21','池州廢林泉寺','杜牧','唐','御定全唐诗','yuding','','[]','廢寺林溪上，頹垣倚亂峰。看棲歸樹鳥，猶想過山鐘。',36,'御定全唐詩/json/522.json','["廢寺林溪上，頹垣倚亂峰。看棲歸樹鳥，猶想過山鐘。", "石路尋僧去，此生應不逢。"]'),
('yuding-22','憶齊安郡','杜牧','唐','御定全唐诗','yuding','','[]','平生睡足處，雲夢澤南州。一夜風欺竹，連江雨送秋。',48,'御定全唐詩/json/522.json','["平生睡足處，雲夢澤南州。一夜風欺竹，連江雨送秋。", "格卑常汩汩，力學強悠悠。終掉塵中手，瀟湘釣漫流。"]'),
('yuding-23','池州清溪','杜牧','唐','御定全唐诗','yuding','','[]','弄溪終日到黃昏，照數秋來白髮根。',32,'御定全唐詩/json/522.json','["弄溪終日到黃昏，照數秋來白髮根。", "何物賴君千遍洗，筆頭塵土漸無痕。"]'),
('yuding-24','游池州林泉寺金碧洞','杜牧','唐','御定全唐诗','yuding','','[]','袖拂霜林下石棱，潺湲聲斷滿溪冰。',32,'御定全唐詩/json/522.json','["袖拂霜林下石棱，潺湲聲斷滿溪冰。", "攜茶臘月游金碧，合有文章病茂陵。"]'),
('yuding-25','即事','杜牧','唐','御定全唐诗','yuding','','[]','因思上党三年戰，閑詠周公七月詩。竹帛未聞書死節，',40,'御定全唐詩/json/522.json','["因思上党三年戰，閑詠周公七月詩。竹帛未聞書死節，", "莫笑一麾東下計，滿江秋浪碧參差。"]'),
('yuding-26','贈李秀才','杜牧','唐','御定全唐诗','yuding','','[]','骨清年少眼如冰，鳳羽參差五色層。',32,'御定全唐詩/json/522.json','["骨清年少眼如冰，鳳羽參差五色層。", "天上麒麟時一下，人間不獨有徐陵。"]'),
('yuding-27','寄李起居四韻','杜牧','唐','御定全唐诗','yuding','','[]','楚女梅簪白雪姿，前溪碧水凍醪時。雲罍心凸知難捧，',40,'御定全唐詩/json/522.json','["楚女梅簪白雪姿，前溪碧水凍醪時。雲罍心凸知難捧，", "自憐窮律窮途客，正怯孤燈一局棋。"]'),
('yuding-28','題池州貴池亭','杜牧','唐','御定全唐诗','yuding','','[]','勢比淩歊宋武台，分明百里遠帆開。',32,'御定全唐詩/json/522.json','["勢比淩歊宋武台，分明百里遠帆開。", "蜀江雪浪西江滿，強半春寒去卻來。"]'),
('yuding-29','蘭溪','杜牧','唐','御定全唐诗','yuding','','[]','蘭溪春盡碧泱泱，映水蘭花雨發香。',32,'御定全唐詩/json/522.json','["蘭溪春盡碧泱泱，映水蘭花雨發香。", "楚國大夫憔悴日，應尋此路去瀟湘。"]'),
('yuding-30','睦州四韻','杜牧','唐','御定全唐诗','yuding','','[]','州在釣台邊，溪山實可憐。有家皆掩映，無處不潺湲。',48,'御定全唐詩/json/522.json','["州在釣台邊，溪山實可憐。有家皆掩映，無處不潺湲。", "好樹鳴幽鳥，晴樓入野煙。殘春杜陵客，中酒落花前。"]'),
('yuding-31','秋晚早發新定','杜牧','唐','御定全唐诗','yuding','','[]','解印書千軸，重陽酒百缸。涼風滿紅樹，曉月下秋江。',48,'御定全唐詩/json/522.json','["解印書千軸，重陽酒百缸。涼風滿紅樹，曉月下秋江。", "岩壑會歸去，塵埃終不降。懸纓未敢濯，嚴瀨碧淙淙。"]'),
('yuding-32','除官歸京睦州雨霽','杜牧','唐','御定全唐诗','yuding','','[]','秋半吳天霽，清凝萬里光。水聲侵笑語，嵐翠撲衣裳。',120,'御定全唐詩/json/522.json','["秋半吳天霽，清凝萬里光。水聲侵笑語，嵐翠撲衣裳。", "遠樹疑羅帳，孤雲認粉囊。溪山侵兩越，時節到重陽。", "顧我能甘賤，無由得自強。誤曾公觸尾，不敢夜循牆。", "豈意籠飛鳥，還為錦帳郎。網今開傅燮，書舊識黃香。", "姹女真虛語，饑兒欲一行。淺深須揭厲，休更學張綱。"]'),
('yuding-33','夜泊桐廬眠先寄蘇台盧郎中','杜牧','唐','御定全唐诗','yuding','','[]','水檻桐廬館，歸舟系石根。笛吹孤戍月，犬吠隔溪村。',48,'御定全唐詩/json/522.json','["水檻桐廬館，歸舟系石根。笛吹孤戍月，犬吠隔溪村。", "十載違清裁，幽懷未一論。蘇台菊花節，何處與開樽。"]'),
('yuding-34','新轉南曹未敘朝散初秋暑退出守吳興書此篇以自見志','杜牧','唐','御定全唐诗','yuding','','[]','捧詔汀洲去，全家羽翼飛。喜拋新錦帳，榮借舊朱衣。',96,'御定全唐詩/json/522.json','["捧詔汀洲去，全家羽翼飛。喜拋新錦帳，榮借舊朱衣。", "且免材為累，何妨拙有機。宋株聊自守，魯酒怕旁圍。", "清尚寧無素，光陰亦未晞。一杯寬幕席，五字弄珠璣。", "越浦黃柑嫩，吳溪紫蟹肥。平生江海志，佩得左魚歸。"]'),
('yuding-35','題白蘋洲','杜牧','唐','御定全唐诗','yuding','','[]','山鳥飛紅帶，亭薇拆紫花。溪光初透徹，秋色正清華。',48,'御定全唐詩/json/522.json','["山鳥飛紅帶，亭薇拆紫花。溪光初透徹，秋色正清華。", "靜處知生樂，喧中見死誇。無多珪組累，終不負煙霞。"]'),
('yuding-36','題茶山','杜牧','唐','御定全唐诗','yuding','','[]','山實東吳秀，茶稱瑞草魁。剖符雖俗吏，修貢亦仙才。',168,'御定全唐詩/json/522.json','["山實東吳秀，茶稱瑞草魁。剖符雖俗吏，修貢亦仙才。", "溪盡停蠻棹，旗張卓翠苔。柳村穿窈窕，松澗渡喧豗。", "等級雲峰峻，寬平洞府開。拂天聞笑語，特地見樓臺。", "泉嫩黃金湧，牙香紫璧裁。拜章期沃日，輕騎疾奔雷。", "舞袖嵐侵澗，歌聲穀答回。磬音藏葉鳥，雪豔照潭梅。", "好是全家到，兼為奉詔來。樹陰香作帳，花徑落成堆。", "景物殘三月，登臨愴一杯。重遊難自克，俯首入塵埃。"]'),
('yuding-37','茶山下作','杜牧','唐','御定全唐诗','yuding','','[]','春風最窈窕，日曉柳村西。嬌雲光占岫，健水鳴分溪。',48,'御定全唐詩/json/522.json','["春風最窈窕，日曉柳村西。嬌雲光占岫，健水鳴分溪。", "燎岩野花遠，戛瑟幽鳥啼。把酒坐芳草，亦有佳人攜。"]'),
('yuding-38','入茶山下題水口草市絕句','杜牧','唐','御定全唐诗','yuding','','[]','倚溪侵嶺多高樹，誇酒書旗有小樓。',32,'御定全唐詩/json/522.json','["倚溪侵嶺多高樹，誇酒書旗有小樓。", "驚起鴛鴦豈無恨，一雙飛去卻回頭。"]'),
('yuding-39','春日茶山病不飲酒，因呈賓客','杜牧','唐','御定全唐诗','yuding','','[]','笙歌登畫船，十日清明前。山秀白雲膩，溪光紅粉鮮。',48,'御定全唐詩/json/522.json','["笙歌登畫船，十日清明前。山秀白雲膩，溪光紅粉鮮。", "欲開未開花，半陰半晴天。誰知病太守，猶得作茶仙。"]'),
('yuding-40','不飲贈官妓','杜牧','唐','御定全唐诗','yuding','','[]','芳草正得意，汀洲日欲西。無端千樹柳，更拂一條溪。',48,'御定全唐詩/json/522.json','["芳草正得意，汀洲日欲西。無端千樹柳，更拂一條溪。", "幾朵梅堪折，何人手好攜。誰憐佳麗地，春恨卻淒淒。"]'),
('yuding-41','早春贈軍事薛判官','杜牧','唐','御定全唐诗','yuding','','[]','雪後新正半，春來四刻長。晴梅朱粉豔，嫩水碧羅光。',48,'御定全唐詩/json/522.json','["雪後新正半，春來四刻長。晴梅朱粉豔，嫩水碧羅光。", "弦管開雙調，花鈿坐兩行。唯君莫惜醉，認取少年場。"]'),
('yuding-42','代吳興妓春初寄薛軍事','杜牧','唐','御定全唐诗','yuding','','[]','霧冷侵紅粉，春陰撲翠鈿。自悲臨曉鏡，誰與惜流年。',48,'御定全唐詩/json/522.json','["霧冷侵紅粉，春陰撲翠鈿。自悲臨曉鏡，誰與惜流年。", "柳暗霏微雨，花愁黯淡天。金釵有幾隻，抽當酒家錢。"]'),
('yuding-43','八月十二日得替後移居霅溪館，因題長句四韻','杜牧','唐','御定全唐诗','yuding','','[]','萬家相慶喜秋成，處處樓臺歌板聲。千歲鶴歸猶有恨，',40,'御定全唐詩/json/522.json','["萬家相慶喜秋成，處處樓臺歌板聲。千歲鶴歸猶有恨，", "景物登臨閑始見，願為閑客此閑行。"]'),
('yuding-44','初冬夜飲','杜牧','唐','御定全唐诗','yuding','','[]','淮陽多病偶求歡，客袖侵霜與燭盤。',32,'御定全唐詩/json/522.json','["淮陽多病偶求歡，客袖侵霜與燭盤。", "砌下梨花一堆雪，明年誰此憑闌幹。"]'),
('yuding-45','栽竹','杜牧','唐','御定全唐诗','yuding','','[]','本因遮日種，卻似為溪移。歷歷羽林影，疏疏煙露姿。',48,'御定全唐詩/json/522.json','["本因遮日種，卻似為溪移。歷歷羽林影，疏疏煙露姿。", "蕭騷寒雨夜，敲劼晚風時。故國何年到，塵冠掛一枝。"]'),
('yuding-46','梅','杜牧','唐','御定全唐诗','yuding','','[]','輕盈照溪水，掩斂下瑤台。妒雪聊相比，欺春不逐來。',48,'御定全唐詩/json/522.json','["輕盈照溪水，掩斂下瑤台。妒雪聊相比，欺春不逐來。", "偶同佳客見，似為凍醪開。若在秦樓畔，堪為弄玉媒。"]'),
('yuding-47','山石榴','杜牧','唐','御定全唐诗','yuding','','[]','似火山榴映小山，繁中能薄豔中閑。',32,'御定全唐詩/json/522.json','["似火山榴映小山，繁中能薄豔中閑。", "一朵佳人玉釵上，只疑燒卻翠雲鬟。"]'),
('yuding-48','柳長句','杜牧','唐','御定全唐诗','yuding','','[]','日落水流西複東，春光不盡柳何窮。巫娥廟裏低含雨，',40,'御定全唐詩/json/522.json','["日落水流西複東，春光不盡柳何窮。巫娥廟裏低含雨，", "灞上漢南千萬樹，幾人遊宦別離中。"]'),
('yuding-49','隋堤柳','杜牧','唐','御定全唐诗','yuding','','[]','夾岸垂楊三百里，只應圖畫最相宜。',32,'御定全唐詩/json/522.json','["夾岸垂楊三百里，只應圖畫最相宜。", "自嫌流落西歸疾，不見東風二月時。"]'),
('yuding-50','柳絕句','杜牧','唐','御定全唐诗','yuding','','[]','數樹新開翠影齊，倚風情態被春迷。',32,'御定全唐詩/json/522.json','["數樹新開翠影齊，倚風情態被春迷。", "依依故國樊川恨，半掩村橋半掩溪。"]'),
('yuding-51','獨柳','杜牧','唐','御定全唐诗','yuding','','[]','含煙一株柳，拂地搖風久。佳人不忍折，悵望回纖手。',24,'御定全唐詩/json/522.json','["含煙一株柳，拂地搖風久。佳人不忍折，悵望回纖手。"]'),
('yuding-52','早雁','杜牧','唐','御定全唐诗','yuding','','[]','金河秋半虜弦開，雲外驚飛四散哀。仙掌月明孤影過，',40,'御定全唐詩/json/522.json','["金河秋半虜弦開，雲外驚飛四散哀。仙掌月明孤影過，", "莫厭瀟湘少人處，水多菰米岸莓苔。"]'),
('yuding-53','鵁鶄','杜牧','唐','御定全唐诗','yuding','','[]','芝莖抽紺趾，清唳擲金梭。日翅閑張錦，風池去罥羅。',48,'御定全唐詩/json/522.json','["芝莖抽紺趾，清唳擲金梭。日翅閑張錦，風池去罥羅。", "靜眠依翠荇，暖戲折高荷。山陰豈無爾，繭字換群鵝。"]'),
('yuding-54','鸚鵡','杜牧','唐','御定全唐诗','yuding','','[]','華堂日漸高，雕檻系紅絛。故國隴山樹，美人金剪刀。',48,'御定全唐詩/json/522.json','["華堂日漸高，雕檻系紅絛。故國隴山樹，美人金剪刀。", "避籠交翠尾，罅嘴靜新毛。不念三緘事，世途皆爾曹。"]'),
('yuding-55','鶴','杜牧','唐','御定全唐诗','yuding','','[]','清音迎曉月，愁思立寒蒲。丹頂西施頰，霜毛四皓須。',48,'御定全唐詩/json/522.json','["清音迎曉月，愁思立寒蒲。丹頂西施頰，霜毛四皓須。", "碧雲行止躁，白鷺性靈粗。終日無群伴，溪邊吊影孤。"]'),
('yuding-56','鴉','杜牧','唐','御定全唐诗','yuding','','[]','擾擾複翻翻，黃昏颺冷煙。毛欺皇后發，聲感楚姬弦。',48,'御定全唐詩/json/522.json','["擾擾複翻翻，黃昏颺冷煙。毛欺皇后發，聲感楚姬弦。", "蔓壘盤風下，霜林接翅眠。只如西旅樣，頭白豈無緣。"]'),
('yuding-57','鷺鷥','杜牧','唐','御定全唐诗','yuding','','[]','雪衣雪發青玉觜，群捕魚兒溪影中。',32,'御定全唐詩/json/522.json','["雪衣雪發青玉觜，群捕魚兒溪影中。", "驚飛遠映碧山去，一樹梨花落晚風。"]'),
('yuding-58','村舍燕','杜牧','唐','御定全唐诗','yuding','','[]','漢宮一百四十五，多下珠簾閉瑣窗。',32,'御定全唐詩/json/522.json','["漢宮一百四十五，多下珠簾閉瑣窗。", "何處營巢夏將半，茅簷煙裏語雙雙。"]'),
('yuding-59','歸燕','杜牧','唐','御定全唐诗','yuding','','[]','畫堂歌舞喧喧地，社去社來人不看。',32,'御定全唐詩/json/522.json','["畫堂歌舞喧喧地，社去社來人不看。", "長是江樓使君伴，黃昏猶待倚闌幹。"]'),
('yuding-60','傷猿','杜牧','唐','御定全唐诗','yuding','','[]','獨折南園一朵梅，重尋幽坎已生苔。',32,'御定全唐詩/json/522.json','["獨折南園一朵梅，重尋幽坎已生苔。", "無端晚吹驚高樹，似嫋長枝欲下來。"]'),
('yuding-61','還俗老僧','杜牧','唐','御定全唐诗','yuding','','[]','雪發不長寸，秋寒力更微。獨尋一徑葉，猶挈衲殘衣。',36,'御定全唐詩/json/522.json','["雪發不長寸，秋寒力更微。獨尋一徑葉，猶挈衲殘衣。", "日暮千峰裏，不知何處歸。"]'),
('yuding-62','斫竹','杜牧','唐','御定全唐诗','yuding','','[]','寺廢竹色死，宦家寧爾留。霜根漸隨斧，風玉尚敲秋。',36,'御定全唐詩/json/522.json','["寺廢竹色死，宦家寧爾留。霜根漸隨斧，風玉尚敲秋。", "江南苦吟客，何處送悠悠。"]'),
('yuding-63','將赴湖州留題亭菊','杜牧','唐','御定全唐诗','yuding','','[]','陶菊手自種，楚蘭心有期。遙知渡江日，正是擷芳時。',24,'御定全唐詩/json/522.json','["陶菊手自種，楚蘭心有期。遙知渡江日，正是擷芳時。"]'),
('yuding-64','折菊','杜牧','唐','御定全唐诗','yuding','','[]','籬東菊徑深，折得自孤吟。雨中衣半濕，擁鼻自知心。',24,'御定全唐詩/json/522.json','["籬東菊徑深，折得自孤吟。雨中衣半濕，擁鼻自知心。"]'),
('yuding-65','雲','杜牧','唐','御定全唐诗','yuding','','[]','盡日看雲首不回，無心都大似無才。',32,'御定全唐詩/json/522.json','["盡日看雲首不回，無心都大似無才。", "可憐光彩一片玉，萬里晴天何處來。"]'),
('yuding-66','醉後題僧院','杜牧','唐','御定全唐诗','yuding','','[]','離心忽忽複淒淒，雨晦傾瓶取醉泥。',32,'御定全唐詩/json/522.json','["離心忽忽複淒淒，雨晦傾瓶取醉泥。", "可羨高僧共心語，一如攜稚往東西。"]'),
('yuding-67','題禪院','杜牧','唐','御定全唐诗','yuding','','[]','觥船一棹百分空，十歲青春不負公。',32,'御定全唐詩/json/522.json','["觥船一棹百分空，十歲青春不負公。", "今日鬢絲禪榻畔，茶煙輕颺落花風。"]'),
('yuding-68','哭李給事中敏','杜牧','唐','御定全唐诗','yuding','','[]','陽陵郭門外，陂阤丈五墳。九泉如結友，茲地好埋君。',24,'御定全唐詩/json/522.json','["陽陵郭門外，陂阤丈五墳。九泉如結友，茲地好埋君。"]'),
('yuding-69','黃州竹徑鬥','杜牧','唐','御定全唐诗','yuding','','[]','竹濁蟠小徑，屈折鬥蛇來。三年得歸去，知繞幾千回。',24,'御定全唐詩/json/522.json','["竹濁蟠小徑，屈折鬥蛇來。三年得歸去，知繞幾千回。"]'),
('yuding-70','題敬愛寺樓','杜牧','唐','御定全唐诗','yuding','','[]','暮景千山雪，春寒百尺樓。獨登還獨下，誰會我悠悠。',24,'御定全唐詩/json/522.json','["暮景千山雪，春寒百尺樓。獨登還獨下，誰會我悠悠。"]'),
('yuding-71','送劉秀才歸江陵','杜牧','唐','御定全唐诗','yuding','','[]','彩服鮮華覲渚宮，鱸魚新熟別江東。劉郎浦夜侵船月，',40,'御定全唐詩/json/522.json','["彩服鮮華覲渚宮，鱸魚新熟別江東。劉郎浦夜侵船月，", "誰人世上為金口，借取明時一薦雄。"]'),
('yuding-72','見吳秀才與池妓別，因成絕句','杜牧','唐','御定全唐诗','yuding','','[]','紅燭短時羌笛怨，清歌咽處蜀弦高。',32,'御定全唐詩/json/522.json','["紅燭短時羌笛怨，清歌咽處蜀弦高。", "萬里分飛兩行淚，滿江寒雨正蕭騷。"]'),
('yuding-73','湖南正初招李郢秀才','杜牧','唐','御定全唐诗','yuding','','[]','行樂及時時已晚，對酒當歌歌不成。千里暮山重疊翠，',40,'御定全唐詩/json/522.json','["行樂及時時已晚，對酒當歌歌不成。千里暮山重疊翠，", "看著白蘋芽欲吐，雪舟相訪勝閑行。"]'),
('yuding-74','贈朱道靈','杜牧','唐','御定全唐诗','yuding','','[]','劉根丹篆三千字，郭璞青囊兩卷書。',32,'御定全唐詩/json/522.json','["劉根丹篆三千字，郭璞青囊兩卷書。", "朱渚磯南謝山北，白雲深處有岩居。"]'),
('yuding-75','屏風絕句','杜牧','唐','御定全唐诗','yuding','','[]','屏風周昉畫纖腰，歲久丹青色半銷。',32,'御定全唐詩/json/522.json','["屏風周昉畫纖腰，歲久丹青色半銷。", "斜倚玉窗鸞發女，拂塵猶自妒嬌嬈。"]'),
('yuding-76','哭韓綽','杜牧','唐','御定全唐诗','yuding','','[]','平明送葬上都門，紼翣交橫逐去魂。',32,'御定全唐詩/json/522.json','["平明送葬上都門，紼翣交橫逐去魂。", "歸來冷笑悲身事，喚婦呼兒索酒盆。"]'),
('yuding-77','新定途中','杜牧','唐','御定全唐诗','yuding','','[]','無端偶效張文紀，下杜鄉園別五秋。',32,'御定全唐詩/json/522.json','["無端偶效張文紀，下杜鄉園別五秋。", "重過江南更千里，萬山深處一孤舟。"]'),
('yuding-78','題新定八松院小石','杜牧','唐','御定全唐诗','yuding','','[]','雨滴珠璣碎，苔生紫翠重。故關何日到，且看小三峰。',24,'御定全唐詩/json/522.json','["雨滴珠璣碎，苔生紫翠重。故關何日到，且看小三峰。"]'),
('yuding-79','往年隨故府吳興公夜泊蕪湖口今赴官西去再宿蕪湖感舊傷懷因成十六韻','杜牧','唐','御定全唐诗','yuding','','[]','南指陵陽路，東流似昔年。重恩山未答，雙鬢雪飄然。',192,'御定全唐詩/json/522.json','["南指陵陽路，東流似昔年。重恩山未答，雙鬢雪飄然。", "數仞慚投跡，群公愧拍肩。駑駘蒙錦繡，塵土浴潺湲。", "郭隗黃金峻，虞卿白璧鮮。貔貅環玉帳，鸚鵡破蠻箋。", "極浦沈碑會，秋花落帽筵。旌旗明迥野，冠佩照神仙。", "籌畫言何補，優容道實全。謳謠人撲地，雞犬樹連天。", "紫鳳超如電，青襟散似煙。蒼生未經濟，墳草已芊綿。", "往事惟沙月，孤燈但客船。峴山雲影畔，棠葉水聲前。", "故國還歸去，浮生亦可憐。高歌一曲淚，明日夕陽邊。"]'),
('yuding-0','懷鐘陵舊遊四首','杜牧','唐','御定全唐诗','yuding','','[]','一謁征南最少年，虞卿雙璧截肪鮮。歌謠千里春長暖，',160,'御定全唐詩/json/523.json','["一謁征南最少年，虞卿雙璧截肪鮮。歌謠千里春長暖，", "陸公餘德機雲在，如我酬恩合執鞭。", "滕閣中春綺席開，柘枝蠻鼓殷晴雷。垂樓萬幕青雲合，", "連巴控越知何事，珠翠沉檀處處堆。", "十頃平湖堤柳合，岸秋蘭芷綠纖纖。一聲明月採蓮女，", "斜輝更落西山影，千步虹橋氣象兼。", "控壓平江十萬家，秋來江靜鏡新磨。城頭晚鼓雷霆後，", "昔年行樂穠桃畔，醉與龍沙揀蜀羅。"]'),
('yuding-1','台城曲二首','杜牧','唐','御定全唐诗','yuding','','[]','整整複斜斜，隨旗簇晚沙。門外韓擒虎，樓頭張麗華。',72,'御定全唐詩/json/523.json','["整整複斜斜，隨旗簇晚沙。門外韓擒虎，樓頭張麗華。", "誰憐容足地，卻羨井中蛙。", "王頒兵勢急，鼓下坐蠻奴。瀲灩倪塘水，叉牙出骨須。", "幹蘆一炬火，回首是平蕪。"]'),
('yuding-2','江上雨寄崔碣','杜牧','唐','御定全唐诗','yuding','','[]','春半平江雨，圓文破蜀羅。聲眠篷底客，寒濕釣來蓑。',48,'御定全唐詩/json/523.json','["春半平江雨，圓文破蜀羅。聲眠篷底客，寒濕釣來蓑。", "暗澹遮山遠，空蒙著柳多。此時懷舊恨，相望意如何。"]'),
('yuding-3','罷鐘陵幕吏十三年，來泊湓浦，感舊為詩','杜牧','唐','御定全唐诗','yuding','','[]','青梅雨中熟，檣倚酒旗邊。故國殘春夢，孤舟一褐眠。',48,'御定全唐詩/json/523.json','["青梅雨中熟，檣倚酒旗邊。故國殘春夢，孤舟一褐眠。", "搖搖遠堤柳，暗暗十程煙。南奏鐘陵道，無因似昔年。"]'),
('yuding-4','商山麻澗','杜牧','唐','御定全唐诗','yuding','','[]','雲光嵐彩四面合，柔柔垂柳十餘家。雉飛鹿過芳草遠，',40,'御定全唐詩/json/523.json','["雲光嵐彩四面合，柔柔垂柳十餘家。雉飛鹿過芳草遠，", "征車自念塵土計，惆悵溪邊書細沙。"]'),
('yuding-5','商山富水驛','杜牧','唐','御定全唐诗','yuding','','[]','益戇由來未覺賢，終須南去吊湘川。當時物議朱雲小，',40,'御定全唐詩/json/523.json','["益戇由來未覺賢，終須南去吊湘川。當時物議朱雲小，", "驛名不合輕移改，留警朝天者惕然。"]'),
('yuding-6','丹水','杜牧','唐','御定全唐诗','yuding','','[]','何事苦縈回，離腸不自裁。恨身隨夢去，春態逐雲來。',48,'御定全唐詩/json/523.json','["何事苦縈回，離腸不自裁。恨身隨夢去，春態逐雲來。", "沈定藍光徹，喧盤粉浪開。翠岩三百尺，誰作子陵台。"]'),
('yuding-7','題武關','杜牧','唐','御定全唐诗','yuding','','[]','碧溪留我武關東，一笑懷王跡自窮。鄭袖嬌嬈酣似醉，',40,'御定全唐詩/json/523.json','["碧溪留我武關東，一笑懷王跡自窮。鄭袖嬌嬈酣似醉，", "今日聖神家四海，戍旗長卷夕陽中。"]'),
('yuding-8','除官赴闕商山道中絕句','杜牧','唐','御定全唐诗','yuding','','[]','水疊鳴珂樹如帳，長楊春殿九門珂。',32,'御定全唐詩/json/523.json','["水疊鳴珂樹如帳，長楊春殿九門珂。", "我來惆悵不自決，欲去欲住終如何。"]'),
('yuding-9','漢江','杜牧','唐','御定全唐诗','yuding','','[]','溶溶漾漾白鷗飛，綠淨春深好染衣。',32,'御定全唐詩/json/523.json','["溶溶漾漾白鷗飛，綠淨春深好染衣。", "南去北來人自老，夕陽長送釣船歸。"]'),
('yuding-10','襄陽雪夜感懷','杜牧','唐','御定全唐诗','yuding','','[]','往事起獨念，飄然自不勝。前灘急夜響，密雪映寒燈。',48,'御定全唐詩/json/523.json','["往事起獨念，飄然自不勝。前灘急夜響，密雪映寒燈。", "的的三年夢，迢迢一線縆。明朝楚山上，莫上最高層。"]'),
('yuding-11','詠歌聖德，遠懷天寶，因題關亭長句四韻','杜牧','唐','御定全唐诗','yuding','','[]','聖敬文思業太平，海寰天下唱歌行。秋來氣勢洪河壯，',40,'御定全唐詩/json/523.json','["聖敬文思業太平，海寰天下唱歌行。秋來氣勢洪河壯，", "君王若悟治安論，安史何人敢弄兵。"]'),
('yuding-12','途中作','杜牧','唐','御定全唐诗','yuding','','[]','綠樹南陽道，千峰勢遠隨。碧溪風澹態，芳樹雨餘姿。',48,'御定全唐詩/json/523.json','["綠樹南陽道，千峰勢遠隨。碧溪風澹態，芳樹雨餘姿。", "野渡雲初暖，征人袖半垂。殘花不足醉，行樂是何時。"]'),
('yuding-13','重到襄陽，哭亡友韋壽朋','杜牧','唐','御定全唐诗','yuding','','[]','故人墳樹立秋風，伯道無兒跡更空。',32,'御定全唐詩/json/523.json','["故人墳樹立秋風，伯道無兒跡更空。", "重到笙歌分散地，隔江吹笛月明中。"]'),
('yuding-14','赤壁','杜牧','唐','御定全唐诗','yuding','','[]','折戟沈沙鐵未銷，自將磨洗認前朝。',32,'御定全唐詩/json/523.json','["折戟沈沙鐵未銷，自將磨洗認前朝。", "東風不與周郎便，銅雀春深鎖二喬。"]'),
('yuding-15','雲夢澤','杜牧','唐','御定全唐诗','yuding','','[]','日旗龍旆想飄揚，一索功高縛楚王。',32,'御定全唐詩/json/523.json','["日旗龍旆想飄揚，一索功高縛楚王。", "直是超然五湖客，未如終始郭汾陽。"]'),
('yuding-16','除官行至昭應，聞友人出官因寄','杜牧','唐','御定全唐诗','yuding','','[]','賤子來千里，明公去一麾。可能休涕淚，豈獨感恩知。',48,'御定全唐詩/json/523.json','["賤子來千里，明公去一麾。可能休涕淚，豈獨感恩知。", "草木窮秋後，山川落照時。如何望故國，驅馬卻遲遲。"]'),
('yuding-17','寄浙東韓八評事','杜牧','唐','御定全唐诗','yuding','','[]','一笑五雲溪上舟，跳丸日月十經秋。鬢衰酒減欲誰泥，',40,'御定全唐詩/json/523.json','["一笑五雲溪上舟，跳丸日月十經秋。鬢衰酒減欲誰泥，", "無窮塵土無聊事，不得清言解不休。"]'),
('yuding-18','泊秦淮','杜牧','唐','御定全唐诗','yuding','','[]','煙籠寒水月籠沙，夜泊秦淮近酒家。',32,'御定全唐詩/json/523.json','["煙籠寒水月籠沙，夜泊秦淮近酒家。", "商女不知亡國恨，隔江猶唱後庭花。"]'),
('yuding-19','秋浦途中','杜牧','唐','御定全唐诗','yuding','','[]','蕭蕭山路窮秋雨，淅淅溪風一岸蒲。',32,'御定全唐詩/json/523.json','["蕭蕭山路窮秋雨，淅淅溪風一岸蒲。", "為問寒沙新到雁，來時還下杜陵無。"]'),
('yuding-20','題桃花夫人廟','杜牧','唐','御定全唐诗','yuding','','[]','細腰宮裏露桃新，脈脈無言度幾春。',32,'御定全唐詩/json/523.json','["細腰宮裏露桃新，脈脈無言度幾春。", "至竟息亡緣底事，可憐金谷墜樓人。"]'),
('yuding-21','初春有感，寄歙州邢員外','杜牧','唐','御定全唐诗','yuding','','[]','雪漲前溪水，啼聲已繞灘。梅衰未減態，春嫩不禁寒。',48,'御定全唐詩/json/523.json','["雪漲前溪水，啼聲已繞灘。梅衰未減態，春嫩不禁寒。", "跡去夢一覺，年來事百般。聞君亦多感，何處倚闌幹。"]'),
('yuding-22','書懷寄中朝往還','杜牧','唐','御定全唐诗','yuding','','[]','平生自許少塵埃，為吏塵中勢自回。朱紱久慚官借與，',40,'御定全唐詩/json/523.json','["平生自許少塵埃，為吏塵中勢自回。朱紱久慚官借與，", "霄漢幾多同學伴，可憐頭角盡卿材。"]'),
('yuding-23','寄崔鈞','杜牧','唐','御定全唐诗','yuding','','[]','緘書報子玉，為我謝平津。自愧掃門士，誰為乞火人。',48,'御定全唐詩/json/523.json','["緘書報子玉，為我謝平津。自愧掃門士，誰為乞火人。", "詞臣陪羽獵，戰將騁騏驎。兩地差池恨，江汀醉送君。"]'),
('yuding-24','初春雨中舟次和州橫江裴使君見迎李趙二秀才同來因書四韻兼寄江南許渾先輩','杜牧','唐','御定全唐诗','yuding','','[]','芳草渡頭微雨時，萬株楊柳拂波垂。蒲根水暖雁初浴，',40,'御定全唐詩/json/523.json','["芳草渡頭微雨時，萬株楊柳拂波垂。蒲根水暖雁初浴，", "江南仲蔚多情調，悵望春陰幾首詩。"]'),
('yuding-25','和州絕句','杜牧','唐','御定全唐诗','yuding','','[]','江湖醉渡十年春，牛渚山邊六問津。',32,'御定全唐詩/json/523.json','["江湖醉渡十年春，牛渚山邊六問津。", "曆陽前事知何實，高位紛紛見陷人。"]'),
('yuding-26','題烏江亭','杜牧','唐','御定全唐诗','yuding','','[]','勝敗兵家事不期，包羞忍恥是男兒。',32,'御定全唐詩/json/523.json','["勝敗兵家事不期，包羞忍恥是男兒。", "江東子弟多才俊，捲土重來未可知。"]'),
('yuding-27','題橫江館','杜牧','唐','御定全唐诗','yuding','','[]','孫家兄弟晉龍驤，馳騁功名業帝王。',32,'御定全唐詩/json/523.json','["孫家兄弟晉龍驤，馳騁功名業帝王。", "至竟江山誰是主，苔磯空屬釣魚郎。"]'),
('yuding-28','寄澧州張舍人笛','杜牧','唐','御定全唐诗','yuding','','[]','發勻肉好生春嶺，截玉鑽星寄使君。檀的染時痕半月，',40,'御定全唐詩/json/523.json','["發勻肉好生春嶺，截玉鑽星寄使君。檀的染時痕半月，", "遙想紫泥封詔罷，夜深應隔禁牆聞。"]'),
('yuding-29','寄揚州韓綽判官','杜牧','唐','御定全唐诗','yuding','','[]','青山隱隱水迢迢，秋盡江南草木凋。',32,'御定全唐詩/json/523.json','["青山隱隱水迢迢，秋盡江南草木凋。", "二十四橋明月夜，玉人何處教吹簫。"]'),
('yuding-30','送李群玉赴舉','杜牧','唐','御定全唐诗','yuding','','[]','故人別來面如雪，一榻拂雲秋影中。',32,'御定全唐詩/json/523.json','["故人別來面如雪，一榻拂雲秋影中。", "玉白花紅三百首，五陵誰唱與春風。"]'),
('yuding-31','送薛種游湖南','杜牧','唐','御定全唐诗','yuding','','[]','賈傅松醪酒，秋來美更香。憐君片雲思，一去繞瀟湘。',24,'御定全唐詩/json/523.json','["賈傅松醪酒，秋來美更香。憐君片雲思，一去繞瀟湘。"]'),
('yuding-32','題壽安縣甘棠館禦溝','杜牧','唐','御定全唐诗','yuding','','[]','一渠東注芳華苑，苑鎖池塘百歲空。',32,'御定全唐詩/json/523.json','["一渠東注芳華苑，苑鎖池塘百歲空。", "水殿半傾蟾口澀，為誰流下蓼花中。"]'),
('yuding-33','汴河懷古','杜牧','唐','御定全唐诗','yuding','','[]','錦纜龍舟隋煬帝，平臺複道漢梁王。',32,'御定全唐詩/json/523.json','["錦纜龍舟隋煬帝，平臺複道漢梁王。", "遊人閑起前朝念，折柳孤吟斷殺腸。"]'),
('yuding-34','汴河阻凍','杜牧','唐','御定全唐诗','yuding','','[]','千里長河初凍時，玉珂瑤佩響參差。',32,'御定全唐詩/json/523.json','["千里長河初凍時，玉珂瑤佩響參差。", "浮生卻似冰底水，日夜東流人不知。"]'),
('yuding-35','酬張祜處士見寄長句四韻','杜牧','唐','御定全唐诗','yuding','','[]','七子論詩誰似公，曹劉須在指揮中。薦衡昔日知文舉，',40,'御定全唐詩/json/523.json','["七子論詩誰似公，曹劉須在指揮中。薦衡昔日知文舉，", "可憐故國三千里，虛唱歌詞滿六宮。"]'),
('yuding-36','寄宣州鄭諫議','杜牧','唐','御定全唐诗','yuding','','[]','大夫官重醉江東，瀟灑名儒振古風。文石陛前辭聖主。',64,'御定全唐詩/json/523.json','["大夫官重醉江東，瀟灑名儒振古風。文石陛前辭聖主。", "碧雲天外作冥鴻。五言甯謝顏光祿，百歲須齊衛武公。", "再拜宜同丈人行，過庭交分有無同。"]'),
('yuding-37','題元處士高亭','杜牧','唐','御定全唐诗','yuding','','[]','水接西江天外聲，小齋松影拂雲平。',32,'御定全唐詩/json/523.json','["水接西江天外聲，小齋松影拂雲平。", "何人教我吹長笛，與倚春風弄月明。"]'),
('yuding-38','鄭瓘協律','杜牧','唐','御定全唐诗','yuding','','[]','廣文遺韻留樗散，雞犬圖書共一船。',32,'御定全唐詩/json/523.json','["廣文遺韻留樗散，雞犬圖書共一船。", "自說江湖不歸事，阻風中酒過年年。"]'),
('yuding-39','和野人殷潛之題籌筆驛十四韻','杜牧','唐','御定全唐诗','yuding','','[]','三吳裂婺女，九錫獄孤兒。霸主業未半，本朝心是誰。',168,'御定全唐詩/json/523.json','["三吳裂婺女，九錫獄孤兒。霸主業未半，本朝心是誰。", "永安宮受詔，籌筆驛沉思。畫地乾坤在，濡毫勝負知。", "艱難同草創，得失計毫釐。寂默經千慮，分明渾一期。", "川流縈智思，山聳助扶持。慷慨匡時略，從容問罪師。", "褒中秋鼓角，渭曲晚旌旗。仗義懸無敵，鳴攻故有辭。", "若非天奪去，豈複慮能支。子夜星才落，鴻毛鼎便移。", "郵亭世自換，白日事長垂。何處躬耕者，猶題殄瘁詩。"]'),
('yuding-40','重題絕句一首','杜牧','唐','御定全唐诗','yuding','','[]','郵亭寄人世，人世寄郵亭。何如自籌度，鴻路有冥冥。',24,'御定全唐詩/json/523.json','["郵亭寄人世，人世寄郵亭。何如自籌度，鴻路有冥冥。"]'),
('yuding-41','送陸洿郎中棄官東歸','杜牧','唐','御定全唐诗','yuding','','[]','少微星動照春雲，魏闕衡門路自分。',32,'御定全唐詩/json/523.json','["少微星動照春雲，魏闕衡門路自分。", "倏去忽來應有意，世間塵土謾疑君。"]'),
('yuding-42','寄瑉笛與宇文舍人','杜牧','唐','御定全唐诗','yuding','','[]','調高銀字聲還側，物比柯亭韻校奇。',32,'御定全唐詩/json/523.json','["調高銀字聲還側，物比柯亭韻校奇。", "寄與玉人天上去，桓將軍見不教吹。"]'),
('yuding-43','寄內兄和州崔員外十二韻','杜牧','唐','御定全唐诗','yuding','','[]','曆陽崔太守，何日不含情。恩義同鐘李，塤篪實弟兄。',144,'御定全唐詩/json/523.json','["曆陽崔太守，何日不含情。恩義同鐘李，塤篪實弟兄。", "光塵能混合，擘畫最分明。台閣仁賢譽，閨門孝友聲。", "西方像教毀，南海繡衣行。金橐寧回顧，珠簟肯一棖。", "只宜裁密詔，何自取專城。進退無非道，徊翔必有名。", "好風初婉軟，離思苦縈盈。金馬舊遊貴，桐廬春水生。", "雨侵寒牖夢，梅引凍醪傾。共祝中興主，高歌唱太平。"]'),
('yuding-44','遣興','杜牧','唐','御定全唐诗','yuding','','[]','鏡弄白髭須，如何作老夫。浮生長勿勿，兒小且嗚嗚。',48,'御定全唐詩/json/523.json','["鏡弄白髭須，如何作老夫。浮生長勿勿，兒小且嗚嗚。", "忍過事堪喜，泰來憂勝無。治平心徑熟，不遣有窮途。"]'),
('yuding-45','早秋','杜牧','唐','御定全唐诗','yuding','','[]','疏雨洗空曠，秋標驚意新。大熱去酷吏，清風來故人。',48,'御定全唐詩/json/523.json','["疏雨洗空曠，秋標驚意新。大熱去酷吏，清風來故人。", "尊酒酌未酌，晚花嚬不嚬。銖秤與縷雪，誰覺老陳陳。"]'),
('yuding-46','秋思','杜牧','唐','御定全唐诗','yuding','','[]','熱去解鉗釱，飄蕭秋半時。微雨池塘見，好風襟袖知。',48,'御定全唐詩/json/523.json','["熱去解鉗釱，飄蕭秋半時。微雨池塘見，好風襟袖知。", "發短梳未足，枕涼閑且欹。平生分過此，何事不參差。"]'),
('yuding-47','途中一絕','杜牧','唐','御定全唐诗','yuding','','[]','鏡中絲發悲來慣，衣上塵痕拂漸難。',32,'御定全唐詩/json/523.json','["鏡中絲發悲來慣，衣上塵痕拂漸難。", "惆悵江湖釣竿手，卻遮西日向長安。"]'),
('yuding-48','春盡途中','杜牧','唐','御定全唐诗','yuding','','[]','田園不事來遊宦，故國誰教爾別離。',32,'御定全唐詩/json/523.json','["田園不事來遊宦，故國誰教爾別離。", "獨倚關亭還把酒，一年春盡送春詩。"]'),
('yuding-49','題村舍','杜牧','唐','御定全唐诗','yuding','','[]','三樹稚桑春未到，扶床乳女午啼饑。',32,'御定全唐詩/json/523.json','["三樹稚桑春未到，扶床乳女午啼饑。", "潛銷暗鑠歸何處，萬指侯家自不知。"]'),
('yuding-50','代人寄遠六言二首','杜牧','唐','御定全唐诗','yuding','','[]','河橋酒旆風軟，候館梅花雪嬌。',56,'御定全唐詩/json/523.json','["河橋酒旆風軟，候館梅花雪嬌。", "宛陵樓上瞪目，我郎何處情饒。", "繡領任垂蓬髻，丁香閑結春梢。", "剩肯新年歸否，江南綠草迢迢。"]'),
('yuding-51','閨情','杜牧','唐','御定全唐诗','yuding','','[]','娟娟卻月眉，新鬢學鴉飛。暗砌勻檀粉，晴窗畫夾衣。',48,'御定全唐詩/json/523.json','["娟娟卻月眉，新鬢學鴉飛。暗砌勻檀粉，晴窗畫夾衣。", "袖紅垂寂寞，眉黛斂衣稀。還向長陵去，今宵歸不歸。"]'),
('yuding-52','舊游','杜牧','唐','御定全唐诗','yuding','','[]','閑吟芍藥詩，惆望久嚬眉。盼眄回眸遠，纖衫整髻遲。',48,'御定全唐詩/json/523.json','["閑吟芍藥詩，惆望久嚬眉。盼眄回眸遠，纖衫整髻遲。", "重尋春晝夢，笑把淺花枝。小市長陵住，非郎誰得知。"]'),
('yuding-53','寄遠','杜牧','唐','御定全唐诗','yuding','','[]','只影隨驚雁，單棲鎖畫籠。向春羅袖薄，誰念舞臺風。',24,'御定全唐詩/json/523.json','["只影隨驚雁，單棲鎖畫籠。向春羅袖薄，誰念舞臺風。"]'),
('yuding-54','簾','杜牧','唐','御定全唐诗','yuding','','[]','徒雲逢剪削，豈謂見偏裝。鳳節輕雕日，鸞花薄飾香。',72,'御定全唐詩/json/523.json','["徒雲逢剪削，豈謂見偏裝。鳳節輕雕日，鸞花薄飾香。", "問屏何屈曲，憐帳解周防。下漬金階露，斜分碧瓦霜。", "沉沉伴春夢，寂寂侍華堂。誰見昭陽殿，真珠十二行。"]'),
('yuding-55','寄題甘露寺北軒','杜牧','唐','御定全唐诗','yuding','','[]','曾向蓬萊宮裏行，北軒闌檻最留情。孤高堪弄桓伊笛，',40,'御定全唐詩/json/523.json','["曾向蓬萊宮裏行，北軒闌檻最留情。孤高堪弄桓伊笛，", "他年會著荷衣去，不向山僧說姓名。"]'),
('yuding-56','題青雲館','杜牧','唐','御定全唐诗','yuding','','[]','虯蟠千仞劇羊腸，天府由來百二強。四皓有芝輕漢祖，',40,'御定全唐詩/json/523.json','["虯蟠千仞劇羊腸，天府由來百二強。四皓有芝輕漢祖，", "深處會容高尚者，水苗三頃百株桑。"]'),
('yuding-57','正初奉酬歙州刺史邢群','杜牧','唐','御定全唐诗','yuding','','[]','翠岩千尺倚溪斜，曾得嚴光作釣家。越嶂遠分丁字水，',40,'御定全唐詩/json/523.json','["翠岩千尺倚溪斜，曾得嚴光作釣家。越嶂遠分丁字水，", "一壑風煙陽羨裏，解龜休去路非賒。"]'),
('yuding-58','江上偶見絕句','杜牧','唐','御定全唐诗','yuding','','[]','楚江寒食橘花時，野渡臨風駐彩旗。',32,'御定全唐詩/json/523.json','["楚江寒食橘花時，野渡臨風駐彩旗。", "草色連雲人去住，水紋如縠燕差池。"]'),
('yuding-59','題木蘭廟','杜牧','唐','御定全唐诗','yuding','','[]','彎弓征戰作男兒，夢裏曾經與畫眉。',32,'御定全唐詩/json/523.json','["彎弓征戰作男兒，夢裏曾經與畫眉。", "幾度思歸還把酒，拂雲堆上祝明妃。"]'),
('yuding-60','入商山','杜牧','唐','御定全唐诗','yuding','','[]','早入商山百里雲，藍溪橋下水聲分。',32,'御定全唐詩/json/523.json','["早入商山百里雲，藍溪橋下水聲分。", "流水舊聲人舊耳，此回嗚咽不堪聞。"]'),
('yuding-61','偶題','杜牧','唐','御定全唐诗','yuding','','[]','甘羅昔作秦丞相，子政曾為漢輦郎。',32,'御定全唐詩/json/523.json','["甘羅昔作秦丞相，子政曾為漢輦郎。", "千載更逢王侍讀，當時還道有文章。"]'),
('yuding-62','送盧秀才一絕','杜牧','唐','御定全唐诗','yuding','','[]','春瀨與煙遠，送君孤棹開。潺湲如不改，愁更釣魚來。',24,'御定全唐詩/json/523.json','["春瀨與煙遠，送君孤棹開。潺湲如不改，愁更釣魚來。"]'),
('yuding-63','醉題','杜牧','唐','御定全唐诗','yuding','','[]','金鑷洗霜鬢，銀觥敵露桃。醉頭扶不起，三丈日還高。',24,'御定全唐詩/json/523.json','["金鑷洗霜鬢，銀觥敵露桃。醉頭扶不起，三丈日還高。"]'),
('yuding-64','題商山四皓廟一絕','杜牧','唐','御定全唐诗','yuding','','[]','呂氏強梁嗣子柔，我於天性豈恩讎。',32,'御定全唐詩/json/523.json','["呂氏強梁嗣子柔，我於天性豈恩讎。", "南軍不袒左邊袖，四老安劉是滅劉。"]'),
('yuding-65','送隱者一絕','杜牧','唐','御定全唐诗','yuding','','[]','無媒徑路草蕭蕭，自古雲林遠市朝。',32,'御定全唐詩/json/523.json','["無媒徑路草蕭蕭，自古雲林遠市朝。", "公道世間唯白髮，貴人頭上不曾饒。"]'),
('yuding-66','題張處士山莊一絕','杜牧','唐','御定全唐诗','yuding','','[]','好鳥疑敲磬，風蟬認軋箏。修篁與嘉樹，偏倚半岩生。',24,'御定全唐詩/json/523.json','["好鳥疑敲磬，風蟬認軋箏。修篁與嘉樹，偏倚半岩生。"]'),
('yuding-67','有懷重送斛斯判官','杜牧','唐','御定全唐诗','yuding','','[]','蒼蒼煙月滿川亭，我有勞歌一為聽。',32,'御定全唐詩/json/523.json','["蒼蒼煙月滿川亭，我有勞歌一為聽。", "將取離魂隨白騎，三台星裏拜文星。"]'),
('yuding-68','贈別二首','杜牧','唐','御定全唐诗','yuding','','[]','娉娉褭褭十三餘，豆蔻梢頭二月初。',64,'御定全唐詩/json/523.json','["娉娉褭褭十三餘，豆蔻梢頭二月初。", "春風十裏揚州路，卷上珠簾總不如。", "多情卻似總無情，唯覺尊前笑不成。", "蠟燭有心還惜別，替人垂淚到天明。"]'),
('yuding-69','寄遠','杜牧','唐','御定全唐诗','yuding','','[]','前山極遠碧雲合，清夜一聲白雪微。',32,'御定全唐詩/json/523.json','["前山極遠碧雲合，清夜一聲白雪微。", "欲寄相思千里月，溪邊殘照雨霏霏。"]'),
('yuding-70','少年行','杜牧','唐','御定全唐诗','yuding','','[]','官為駿馬監，職帥羽林兒。兩綬藏不見，落花何處期。',72,'御定全唐詩/json/523.json','["官為駿馬監，職帥羽林兒。兩綬藏不見，落花何處期。", "獵敲白玉鐙，怒袖紫金錘。田竇長留醉，蘇辛曲讓岐。", "豪持出塞節，笑別遠山眉。捷報雲台賀，公卿拜夀卮。"]'),
('yuding-71','盆池','杜牧','唐','御定全唐诗','yuding','','[]','鑿破蒼苔地，偷他一片天。白雲生鏡裏，明月落階前。',24,'御定全唐詩/json/523.json','["鑿破蒼苔地，偷他一片天。白雲生鏡裏，明月落階前。"]'),
('yuding-72','有寄','杜牧','唐','御定全唐诗','yuding','','[]','雲闊煙深樹，江澄水浴秋。美人何處在，明月萬山頭。',24,'御定全唐詩/json/523.json','["雲闊煙深樹，江澄水浴秋。美人何處在，明月萬山頭。"]'),
('yuding-0','斑竹筒簟','杜牧','唐','御定全唐诗','yuding','','[]','血染斑斑成錦紋，昔年遺恨至今存。',32,'御定全唐詩/json/524.json','["血染斑斑成錦紋，昔年遺恨至今存。", "分明知是湘妃泣，何忍將身臥淚痕。"]'),
('yuding-1','和嚴惲秀才落花','杜牧','唐','御定全唐诗','yuding','','[]','共惜流年留不得，且環流水醉流杯。',32,'御定全唐詩/json/524.json','["共惜流年留不得，且環流水醉流杯。", "無情紅豔年年盛，不恨凋零卻恨開。"]'),
('yuding-2','倡樓戲贈','杜牧','唐','御定全唐诗','yuding','','[]','細柳橋邊深半春，纈衣簾裏動香塵。',32,'御定全唐詩/json/524.json','["細柳橋邊深半春，纈衣簾裏動香塵。", "無端有寄閑消息，背插金釵笑向人。"]'),
('yuding-3','初上船留寄','杜牧','唐','御定全唐诗','yuding','','[]','煙水本好尚，親交何慘淒。況為珠履客，即泊錦帆堤。',48,'御定全唐詩/json/524.json','["煙水本好尚，親交何慘淒。況為珠履客，即泊錦帆堤。", "沙雁同船去，田鴉繞岸啼。此時還有味，必臥日從西。"]'),
('yuding-4','秋岸','杜牧','唐','御定全唐诗','yuding','','[]','河岸微退落，柳影微凋疏。船上聽呼稚，堤南趁漉魚。',48,'御定全唐詩/json/524.json','["河岸微退落，柳影微凋疏。船上聽呼稚，堤南趁漉魚。", "數帆旗去疾，一艇箭回初。曾入相思夢，因憑附遠書。"]'),
('yuding-5','過大樑聞河亭方宴贈孫子端','杜牧','唐','御定全唐诗','yuding','','[]','梁園縱玩歸應少，賦雪搜才去必頻。',32,'御定全唐詩/json/524.json','["梁園縱玩歸應少，賦雪搜才去必頻。", "板落豈緣無罰酒，不教客右更添人。"]'),
('yuding-6','題吳興消暑樓十二韻','杜牧','唐','御定全唐诗','yuding','','[]','晴日登攀好，危樓物象饒。一溪通四境，萬岫饒層霄。',144,'御定全唐詩/json/524.json','["晴日登攀好，危樓物象饒。一溪通四境，萬岫饒層霄。", "鳥翼舒華屋，魚鱗棹短橈。浪花機乍織，雲葉匠新雕。", "台榭羅嘉卉，城池敞麗譙。蟾蜍來作鑒，螮蝀引成橋。", "燕任隨秋葉，人空集早潮。楚鴻行盡直，沙鷺立偏翹。", "暮角淒遊旅，清歌慘泬寥。景牽遊目困，愁托酒腸銷。", "遠吹流松韻，殘陽渡柳橋。時陪庾公賞，還悟脫煩囂。"]'),
('yuding-7','奉送中丞姊夫儔自大理卿出鎮江西敘事書懷因成十二韻','杜牧','唐','御定全唐诗','yuding','','[]','惟帝憂南紀，搜賢與大藩。梅仙調步驟，庾亮拂櫜鞬。',144,'御定全唐詩/json/524.json','["惟帝憂南紀，搜賢與大藩。梅仙調步驟，庾亮拂櫜鞬。", "一室何勞掃，三章自不冤。精明如定國，孤峻似陳蕃。", "灞岸秋猶嫩，藍橋水始喧。紅旓掛石壁，黑槊斷雲根。", "滕閣丹霄倚，章江碧玉奔。一聲仙妓唱，千里暮江痕。", "私好初童稚，官榮見子孫。流年休掛念，萬事至無言。", "玉輦君頻過，馮唐將未論。庸書酬萬債，竹塢問樊村。"]'),
('yuding-8','中丞業深韜略，志在功名，再奉長句一篇兼有諮勸','杜牧','唐','御定全唐诗','yuding','','[]','檣似鄧林江拍天，越香巴錦萬千千。滕王閣上柘枝鼓，',40,'御定全唐詩/json/524.json','["檣似鄧林江拍天，越香巴錦萬千千。滕王閣上柘枝鼓，", "要君嚴重疏歡樂，猶有河湟可下鞭。"]'),
('yuding-9','和裴傑秀才新櫻桃','杜牧','唐','御定全唐诗','yuding','','[]','新果真瓊液，人應宴紫蘭。圓疑竊龍頷，色已奪雞冠。',72,'御定全唐詩/json/524.json','["新果真瓊液，人應宴紫蘭。圓疑竊龍頷，色已奪雞冠。", "遠火微微辨，繁星歷歷看。茂先知味好，曼倩恨偷難。", "忍用烹酥酪，從將玩玉盤。流年如可駐，何必九華丹。"]'),
('yuding-10','春思','杜牧','唐','御定全唐诗','yuding','','[]','豈君心的的，嗟我淚涓涓。綿羽啼來久，錦鱗書未傳。',48,'御定全唐詩/json/524.json','["豈君心的的，嗟我淚涓涓。綿羽啼來久，錦鱗書未傳。", "獸壚凝冷焰，羅幕蔽晴煙。自是求佳夢，何須訝晝眠。"]'),
('yuding-11','代人作','杜牧','唐','御定全唐诗','yuding','','[]','樓高春日早，屏束麝煙堆。盼眄凝魂別，依稀夢雨來。',96,'御定全唐詩/json/524.json','["樓高春日早，屏束麝煙堆。盼眄凝魂別，依稀夢雨來。", "綠鬟羞妥麼，紅頰思天偎。鬥草憐香蕙，簪花間雪梅。", "戍遼雖咽切，游蜀亦遲回。錦字梭懸壁，琴心月滿台。", "笑筵凝貝啟，眠箔曉珠開。臘破征車動，袍襟對淚裁。"]'),
('yuding-12','偶題二首','杜牧','唐','御定全唐诗','yuding','','[]','勞勞千里身，襟袂滿行塵。深夜懸雙淚，短亭思遠人。',96,'御定全唐詩/json/524.json','["勞勞千里身，襟袂滿行塵。深夜懸雙淚，短亭思遠人。", "蒼江程未息，黑水夢何頻。明月輕橈去，唯應釣赤鱗。", "有恨秋來極，無端別後知。夜闌終耿耿，明發竟遲遲。", "信已憑鴻去，歸唯與燕期。只因明月見，千里兩相思。"]'),
('yuding-13','冬至日遇京使發寄舍弟','杜牧','唐','御定全唐诗','yuding','','[]','遠信初憑雙鯉去，他鄉正遇一陽生。尊前豈解愁家國，',40,'御定全唐詩/json/524.json','["遠信初憑雙鯉去，他鄉正遇一陽生。尊前豈解愁家國，", "竹門風過還惆悵，疑是松窗雪打聲。"]'),
('yuding-14','洛下送張曼容赴上党召','杜牧','唐','御定全唐诗','yuding','','[]','歌闋樽殘恨卻偏，憑君不用設離筵。未趨雉尾隨元老，',40,'御定全唐詩/json/524.json','["歌闋樽殘恨卻偏，憑君不用設離筵。未趨雉尾隨元老，", "羽書正急徵兵地，須遣頭風處處痊。"]'),
('yuding-15','宣州留贈','杜牧','唐','御定全唐诗','yuding','','[]','紅鉛濕盡半羅裙，洞府人間手欲分。滿面風流雖似玉，',40,'御定全唐詩/json/524.json','["紅鉛濕盡半羅裙，洞府人間手欲分。滿面風流雖似玉，", "為報眼波須穩當，五陵游宕莫知聞。"]'),
('yuding-16','寄題宣州開元寺','杜牧','唐','御定全唐诗','yuding','','[]','松寺曾同一鶴棲，夜深台殿月高低。',32,'御定全唐詩/json/524.json','["松寺曾同一鶴棲，夜深台殿月高低。", "何人為倚東樓柱，正是千山雪漲溪。"]'),
('yuding-17','贈張祜','杜牧','唐','御定全唐诗','yuding','','[]','詩韻一逢君，平生稱所聞。粉毫唯畫月，瓊尺只裁雲。',48,'御定全唐詩/json/524.json','["詩韻一逢君，平生稱所聞。粉毫唯畫月，瓊尺只裁雲。", "黥陣人人懾，秋星歷歷分。數篇留別我，羞殺李將軍。"]'),
('yuding-18','殘春獨來南亭因寄張祜','杜牧','唐','御定全唐诗','yuding','','[]','暖雲如粉草如茵，獨步長堤不見人。一嶺桃花紅錦黦，',40,'御定全唐詩/json/524.json','["暖雲如粉草如茵，獨步長堤不見人。一嶺桃花紅錦黦，", "仲蔚欲知何處在，苦吟林下拂詩塵。"]'),
('yuding-19','宣州開元寺南樓','杜牧','唐','御定全唐诗','yuding','','[]','小樓才受一床橫，終日看山酒滿傾。',32,'御定全唐詩/json/524.json','["小樓才受一床橫，終日看山酒滿傾。", "可惜和風夜來雨，醉中虛度打窗聲。"]'),
('yuding-20','寄遠人','杜牧','唐','御定全唐诗','yuding','','[]','終日求人蔔，回回道好音。那時離別後，入夢到如今。',24,'御定全唐詩/json/524.json','["終日求人蔔，回回道好音。那時離別後，入夢到如今。"]'),
('yuding-21','別沈處士','杜牧','唐','御定全唐诗','yuding','','[]','舊事參差夢，新程邐迤秋。故人如見憶，時到寺東樓。',24,'御定全唐詩/json/524.json','["舊事參差夢，新程邐迤秋。故人如見憶，時到寺東樓。"]'),
('yuding-22','留贈','杜牧','唐','御定全唐诗','yuding','','[]','舞靴應任閒人看，笑臉還須待我開。',32,'御定全唐詩/json/524.json','["舞靴應任閒人看，笑臉還須待我開。", "不用鏡前空有淚，薔薇花謝即歸來。"]'),
('yuding-23','奉和僕射相公春澤稍愆聖君軫慮嘉雪忽降品彙昭蘇即事書成四韻','杜牧','唐','御定全唐诗','yuding','','[]','飄來雞樹鳳池邊，漸壓瓊枝凍碧漣。銀闕雙高銀漢裏，',40,'御定全唐詩/json/524.json','["飄來雞樹鳳池邊，漸壓瓊枝凍碧漣。銀闕雙高銀漢裏，", "上相抽毫歌帝德，一篇風雅美豐年。"]'),
('yuding-24','寄李播評事','杜牧','唐','御定全唐诗','yuding','','[]','子列光殊價，明時忍自高。寧無好舟楫，不泛惡風濤。',48,'御定全唐詩/json/524.json','["子列光殊價，明時忍自高。寧無好舟楫，不泛惡風濤。", "大翼終難戢，奇鋒且自韜。春來煙渚上，幾淨雪霜毫。"]'),
('yuding-25','送牛相出鎮襄州','杜牧','唐','御定全唐诗','yuding','','[]','盛時常注意，南雍暫分茅。紫殿辭明主，岩廊別舊交。',72,'御定全唐詩/json/524.json','["盛時常注意，南雍暫分茅。紫殿辭明主，岩廊別舊交。", "危幢侵碧霧，寒旆獵紅旓。德業懸秦鏡，威聲隱楚郊。", "拜塵先灑淚，成廈昔容巢。遙仰沈碑會，鴛鴦玉佩敲。"]'),
('yuding-26','送薛邽二首','杜牧','唐','御定全唐诗','yuding','','[]','可憐走馬騎驢漢，豈有風光肯占伊。',64,'御定全唐詩/json/524.json','["可憐走馬騎驢漢，豈有風光肯占伊。", "只有三張最惆悵，下山回馬尚遲遲。", "小捷風流已俊才，便將紅粉作金台。", "明年未去池陽郡，更乞春時卻重來。"]'),
('yuding-27','見穆三十宅中庭海榴花謝','杜牧','唐','御定全唐诗','yuding','','[]','矜紅掩素似多才，不待櫻桃不逐梅。春到未曾逢宴賞，',40,'御定全唐詩/json/524.json','["矜紅掩素似多才，不待櫻桃不逐梅。春到未曾逢宴賞，", "堪恨王孫浪遊去，落英狼藉始歸來。"]'),
('yuding-28','留誨曹師等詩','杜牧','唐','御定全唐诗','yuding','','[]','萬物有醜好，各一姿狀分。唯人即不爾，學與不學論。',72,'御定全唐詩/json/524.json','["萬物有醜好，各一姿狀分。唯人即不爾，學與不學論。", "學非探其花，要自撥其根。孝友與誠實，而不忘爾言。", "根本既深實，柯葉自滋繁。念爾無忽此，期以慶吾門。"]'),
('yuding-29','洛陽','杜牧','唐','御定全唐诗','yuding','','[]','文爭武戰就神功，時似開元天寶中。已建玄戈收相土，',40,'御定全唐詩/json/524.json','["文爭武戰就神功，時似開元天寶中。已建玄戈收相土，", "疑有女娥西望處，上陽煙樹正秋風。"]'),
('yuding-30','寄唐州李玭尚書','杜牧','唐','御定全唐诗','yuding','','[]','累代功勳照世光，奚胡聞道死心降。書功筆禿三千管，',40,'御定全唐詩/json/524.json','["累代功勳照世光，奚胡聞道死心降。書功筆禿三千管，", "時人欲識胸襟否，彭蠡秋連萬里江。"]'),
('yuding-31','南陵道中','杜牧','唐','御定全唐诗','yuding','','[]','南陵水面漫悠悠，風緊雲輕欲變秋。',32,'御定全唐詩/json/524.json','["南陵水面漫悠悠，風緊雲輕欲變秋。", "正是客心孤回處，誰家紅袖憑江樓。"]'),
('yuding-32','登九峰樓','杜牧','唐','御定全唐诗','yuding','','[]','晴江灩灩含淺沙，高低繞郭滯秋花。牛歌魚笛山月上，',40,'御定全唐詩/json/524.json','["晴江灩灩含淺沙，高低繞郭滯秋花。牛歌魚笛山月上，", "白頭搔殺倚柱遍，歸棹何時聞軋鴉。"]'),
('yuding-33','別家','杜牧','唐','御定全唐诗','yuding','','[]','初歲嬌兒未識爺，別爺不拜手吒叉。',32,'御定全唐詩/json/524.json','["初歲嬌兒未識爺，別爺不拜手吒叉。", "拊頭一別三千里，何日迎門卻到家。"]'),
('yuding-34','歸家','杜牧','唐','御定全唐诗','yuding','','[]','稚子牽衣問，歸來何太遲。共誰爭歲月，贏得鬢邊絲。',24,'御定全唐詩/json/524.json','["稚子牽衣問，歸來何太遲。共誰爭歲月，贏得鬢邊絲。"]'),
('yuding-35','雨','杜牧','唐','御定全唐诗','yuding','','[]','連雲接塞添迢遞，灑幕侵燈送寂寥。',32,'御定全唐詩/json/524.json','["連雲接塞添迢遞，灑幕侵燈送寂寥。", "一夜不眠孤客耳，主人窗外有芭蕉。"]'),
('yuding-36','送人','杜牧','唐','御定全唐诗','yuding','','[]','鴛鴦帳裏暖芙蓉，低泣關山幾萬重。',32,'御定全唐詩/json/524.json','["鴛鴦帳裏暖芙蓉，低泣關山幾萬重。", "明鏡半邊釵一股，此生何處不相逢。"]'),
('yuding-37','遣懷','杜牧','唐','御定全唐诗','yuding','','[]','道泰時還泰，時來命不來。何當離城市，高臥博山隈。',24,'御定全唐詩/json/524.json','["道泰時還泰，時來命不來。何當離城市，高臥博山隈。"]'),
('yuding-38','醉贈薛道封','杜牧','唐','御定全唐诗','yuding','','[]','飲酒論文四百刻，水分雲隔二三年。',32,'御定全唐詩/json/524.json','["飲酒論文四百刻，水分雲隔二三年。", "男兒事業知公有，賣與明君直幾錢。"]'),
('yuding-39','歙州盧中丞見惠名醞','杜牧','唐','御定全唐诗','yuding','','[]','誰憐賤子啟窮途，太守封來酒一壺。攻破是非渾似夢，',40,'御定全唐詩/json/524.json','["誰憐賤子啟窮途，太守封來酒一壺。攻破是非渾似夢，", "猶念悲秋更分賜，夾溪紅蓼映風蒲。"]'),
('yuding-40','詠襪','杜牧','唐','御定全唐诗','yuding','','[]','鈿尺裁量減四分，纖纖玉筍裹輕雲。',32,'御定全唐詩/json/524.json','["鈿尺裁量減四分，纖纖玉筍裹輕雲。", "五陵年少欺他醉，笑把花前出畫裙。"]'),
('yuding-41','宮祠二首','杜牧','唐','御定全唐诗','yuding','','[]','蟬翼輕綃傅體紅，玉膚如醉向春風。',64,'御定全唐詩/json/524.json','["蟬翼輕綃傅體紅，玉膚如醉向春風。", "深宮鎖閉猶疑惑，更取丹沙試辟宮。", "監宮引出暫開門，隨例須朝不是恩。", "銀鑰卻收金鎖合，月明花落又黃昏。"]'),
('yuding-42','月','杜牧','唐','御定全唐诗','yuding','','[]','三十六宮秋夜深，昭陽歌斷信沉沉。',32,'御定全唐詩/json/524.json','["三十六宮秋夜深，昭陽歌斷信沉沉。", "唯應獨伴陳皇后，照見長門望幸心。"]');
